window.SPECS = {"setup":{"module":"setup","display":"Configuração & Admin","functionalities":[{"group":"Gestão de Empresas","objetivo":"Criar, atualizar e consultar a entidade company e seus padrões contábeis/operacionais.","acoes":[{"nome":"setup-company","objetivo":"Cria uma nova empresa e auto-provisiona ano fiscal, centro de custo e armazém padrão.","entradas":"--name (obrigatório); --abbr (default: iniciais do nome, senão 3 primeiras letras); --currency (default USD); --country (default 'United States'); --fiscal-year-start-month (default 1); --industry (opcional, resolve perfil de onboarding).","saidas":"company_id, name, abbr, fiscal_year_id, cost_center_id, warehouse_id; e opcionalmente onboard_profile, profile_modules, region_module.","regras":"name é obrigatório; IntegrityError em duplicado/dados inválidos retorna erro. Calcula período do ano fiscal a partir do mês de início vs data atual. Criação de fiscal_year/cost_center/warehouse é não-fatal (falha apenas loga em stderr). --industry mapeia perfil/região via dados locais bundled (sem rede).","efeitos":"INSERT em company; INSERT em fiscal_year; INSERT em cost_center e UPDATE company.default_cost_center_id; INSERT em warehouse e UPDATE company.default_warehouse_id; audit_log (action 'create', entity 'company'). Nenhuma postagem em gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabelas company/fiscal_year/cost_center/warehouse existentes)."},{"nome":"update-company","objetivo":"Atualiza campos editáveis de uma empresa, incluindo contas/centros padrão.","entradas":"--company-id (default: primeira empresa); flags por campo: --name, --abbr, --currency, --country, --tax-id, contas padrão (--default-*-account-id), --default-cost-center-id, --default-warehouse-id, --round-off-account-id, --exchange-gain-loss-account-id, --perpetual-inventory, --enable-negative-stock, --accounts-frozen-till-date, --role-allowed-for-frozen-entries, --fiscal-year-start-month.","saidas":"company_id, updated_fields (lista).","regras":"Se nenhum company-id, usa a primeira empresa; erro se nenhuma existir ou id não encontrado. Erro 'No fields to update' se nada informado. Valida que contas padrão informadas não sejam contas de grupo (is_group=1), rejeitando com mensagem.","efeitos":"UPDATE company (campos informados + updated_at); audit_log (action 'update', com old/new values). Somente leitura em account para validação. Sem gl_entry/SLE/PLE.","precondicoes":"Pelo menos uma company existente; contas referenciadas devem existir e ser folha (leaf)."},{"nome":"get-company","objetivo":"Retorna o registro completo de uma empresa.","entradas":"--company-id (default: primeira empresa).","saidas":"company (objeto com todas as colunas).","regras":"Sem id, retorna a primeira empresa; erro 'No company found' com sugestão se nenhuma existir.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado; idealmente ao menos uma empresa."},{"nome":"list-companies","objetivo":"Lista empresas com paginação.","entradas":"--limit (default 20); --offset (default 0).","saidas":"companies (array), total_count, limit, offset, has_more.","regras":"Ordena por name; has_more calculado como offset+limit<total_count.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."}]},{"group":"Moedas e Câmbio","objetivo":"Cadastrar moedas e gerir taxas de câmbio manuais e via API externa.","acoes":[{"nome":"add-currency","objetivo":"Cadastra uma moeda no catálogo.","entradas":"--code (obrigatório, normalizado para maiúsculas); --name (default: code); --symbol (default ''); --decimal-places (default 2); --enabled (flag, default 0/desabilitada).","saidas":"code, name.","regras":"code obrigatório; IntegrityError retorna 'Currency already exists'.","efeitos":"INSERT em currency; audit_log (action 'create', entity 'currency'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela currency)."},{"nome":"list-currencies","objetivo":"Lista moedas, opcionalmente só as habilitadas.","entradas":"--enabled-only (flag); --limit (default 20); --offset (default 0).","saidas":"currencies (array), total_count, limit, offset, has_more.","regras":"Com --enabled-only filtra enabled=1; ordena por code.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."},{"nome":"add-exchange-rate","objetivo":"Registra uma taxa de câmbio manual para um par de moedas.","entradas":"--from-currency (obrigatório), --to-currency (obrigatório), --rate (obrigatório); --effective-date (default: hoje UTC); --source (default 'manual').","saidas":"exchange_rate_id, effective_date.","regras":"Os três campos são obrigatórios; moedas normalizadas para maiúsculas; IntegrityError retorna falha (duplicado/inválido).","efeitos":"INSERT em exchange_rate; audit_log (action 'create', entity 'exchange_rate'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela exchange_rate)."},{"nome":"get-exchange-rate","objetivo":"Retorna a taxa vigente de um par na data (ou a mais recente anterior).","entradas":"--from-currency (obrigatório), --to-currency (obrigatório); --effective-date (default: hoje UTC).","saidas":"rate, effective_date, source.","regras":"from/to obrigatórios; busca effective_date <= data, ordenado desc, limit 1; erro se nenhuma taxa encontrada.","efeitos":"nenhum (leitura).","precondicoes":"Existir taxa para o par na/antes da data."},{"nome":"list-exchange-rates","objetivo":"Lista taxas de câmbio com filtros opcionais.","entradas":"--from-currency, --to-currency, --from-date, --to-date (todos opcionais); --limit (default 20); --offset (default 0).","saidas":"rates (array), total_count, limit, offset, has_more.","regras":"Aplica filtros conforme flags; ordena por effective_date desc.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."},{"nome":"fetch-exchange-rates","objetivo":"Busca taxas USD-base em frankfurter.dev e faz upsert no exchange_rate.","entradas":"Nenhuma flag (base=USD fixo, effective_date=hoje, source='api').","saidas":"rates_updated, source ('frankfurter.dev'), base ('USD'), date.","regras":"Requer rede (timeout 15s); erro de conexão/HTTP retorna falha com sugestão; erro se API retornar zero taxas. Para cada par: UPDATE se já existe (USD/to/hoje), senão INSERT.","efeitos":"INSERT ou UPDATE em exchange_rate (rate, source='api', updated_at); audit_log (action 'fetch', entity 'exchange_rate'). Sem gl_entry/SLE/PLE. Faz chamada HTTP externa.","precondicoes":"Conexão de internet; tabela exchange_rate."}]},{"group":"Condições de Pagamento","objetivo":"Cadastrar e listar templates de prazos/descontos de pagamento.","acoes":[{"nome":"add-payment-terms","objetivo":"Cria um template de condição de pagamento.","entradas":"--name (obrigatório); --due-days (default 30); --discount-percentage (opcional); --discount-days (opcional); --description (opcional).","saidas":"payment_terms_id, name.","regras":"name obrigatório; IntegrityError retorna 'Payment terms already exists'.","efeitos":"INSERT em payment_terms; audit_log (action 'create', entity 'payment_terms'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela payment_terms)."},{"nome":"list-payment-terms","objetivo":"Lista todas as condições de pagamento.","entradas":"--limit (default 20); --offset (default 0).","saidas":"terms (array), total_count, limit, offset, has_more.","regras":"Ordena por due_days e name.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."}]},{"group":"Unidades de Medida","objetivo":"Gerir unidades de medida (UoM) e seus fatores de conversão.","acoes":[{"nome":"add-uom","objetivo":"Cadastra uma unidade de medida.","entradas":"--name (obrigatório); --must-be-whole-number (flag, default 0).","saidas":"uom_id, name.","regras":"name obrigatório; IntegrityError retorna 'UoM already exists'.","efeitos":"INSERT em uom; audit_log (action 'create', entity 'uom'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela uom)."},{"nome":"list-uoms","objetivo":"Lista todas as unidades de medida.","entradas":"--limit (default 20); --offset (default 0).","saidas":"uoms (array), total_count, limit, offset, has_more.","regras":"Ordena por name.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."},{"nome":"add-uom-conversion","objetivo":"Registra um fator de conversão entre duas UoMs (opcionalmente por item).","entradas":"--from-uom (obrigatório), --to-uom (obrigatório), --conversion-factor (obrigatório); --item-id (opcional).","saidas":"uom_conversion_id.","regras":"from-uom/to-uom/conversion-factor obrigatórios; IntegrityError retorna falha (duplicado/inválido).","efeitos":"INSERT em uom_conversion; audit_log (action 'create', entity 'uom_conversion'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela uom_conversion); UoMs referenciadas devem existir."}]},{"group":"Usuários e Acessos (RBAC)","objetivo":"Criar e administrar contas de usuário ERP, status, senhas web e vínculos de empresa.","acoes":[{"nome":"add-user","objetivo":"Cria um novo usuário ERP.","entradas":"--name (username, obrigatório); --email (opcional, validado); --full-name (opcional); --company-id (opcional, vira lista company_ids).","saidas":"user_id, username.","regras":"username obrigatório; email validado por regex se informado; erro se username já existe.","efeitos":"INSERT em erp_user; audit_log (action 'add-user', entity 'erp_user'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela erp_user)."},{"nome":"update-user","objetivo":"Atualiza campos de um usuário existente (username, email, nome, status, empresas).","entradas":"--user-id (obrigatório); --name (novo username); --email; --full-name; --user-status (active|disabled|locked); --company-id (anexa à lista).","saidas":"user_id, updated_fields.","regras":"user-id obrigatório; erro se usuário não encontrado; user-status validado contra active/disabled/locked; company-id é anexado (sem duplicar) a company_ids; erro 'No fields to update' se nada informado.","efeitos":"UPDATE em erp_user (+ updated_at); audit_log (action 'update-user', com old/new). Sem gl_entry/SLE/PLE.","precondicoes":"Usuário existente."},{"nome":"list-users","objetivo":"Lista usuários ERP com paginação.","entradas":"--limit (default 50); --offset (default 0).","saidas":"users (array: id, username, email, full_name, status, company_ids, created_at), count, has_more.","regras":"Busca limit+1 para detectar has_more; ordena por username.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."},{"nome":"get-user","objetivo":"Retorna um usuário e seus papéis atribuídos (com escopo de empresa).","entradas":"--user-id (obrigatório).","saidas":"todos os campos do usuário + roles (array: role_name, company_id, company_name).","regras":"user-id obrigatório; erro se usuário não encontrado; faz join user_role/role/company.","efeitos":"nenhum (leitura).","precondicoes":"Usuário existente."},{"nome":"set-password","objetivo":"Define a senha de login web (hash) de um usuário.","entradas":"--user-id (obrigatório); --password (obrigatório, mínimo 8 caracteres).","saidas":"user_id, username, message.","regras":"user-id e password obrigatórios; senha < 8 chars rejeitada; erro se usuário não encontrado; usa hash_password da lib.","efeitos":"UPDATE erp_user.password_hash (+ updated_at); audit_log (action 'set-password', sem valores). Sem gl_entry/SLE/PLE.","precondicoes":"Usuário existente."}]},{"group":"Papéis e Permissões","objetivo":"Gerir papéis (roles), suas atribuições a usuários e o seed de permissões padrão RBAC.","acoes":[{"nome":"add-role","objetivo":"Cria um papel customizado (não-sistema).","entradas":"--name (obrigatório); --description (opcional).","saidas":"role_id, name.","regras":"name obrigatório; erro se role já existe; gravado com is_system=0.","efeitos":"INSERT em role; audit_log (action 'add-role', entity 'role'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabela role)."},{"nome":"list-roles","objetivo":"Lista todos os papéis com contagem de usuários por papel.","entradas":"Nenhuma.","saidas":"roles (array: id, name, description, is_system, user_count), count.","regras":"Left join com user_role; ordena por is_system desc, depois name.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."},{"nome":"assign-role","objetivo":"Atribui um papel a um usuário, opcionalmente com escopo de empresa.","entradas":"--user-id (obrigatório); --role-name (obrigatório); --company-id (opcional; None = atribuição global).","saidas":"user_role_id, role_name, company_id.","regras":"user-id e role-name obrigatórios; erro se usuário ou role não encontrado; erro se já atribuído (comparação NULL-safe via SQL IS ?).","efeitos":"INSERT em user_role; audit_log (action 'assign-role', entity 'user_role'). Sem gl_entry/SLE/PLE.","precondicoes":"Usuário e role existentes."},{"nome":"revoke-role","objetivo":"Remove um papel de um usuário (no escopo de empresa informado).","entradas":"--user-id (obrigatório); --role-name (obrigatório); --company-id (opcional, NULL-safe).","saidas":"revoked (role_name), user_id.","regras":"user-id e role-name obrigatórios; erro se role não encontrado; DELETE com IS ?; erro se não havia atribuição (rowcount 0).","efeitos":"DELETE em user_role; audit_log (action 'revoke-role', entity 'user_role', com old values). Sem gl_entry/SLE/PLE.","precondicoes":"Role existente e atribuição presente."},{"nome":"seed-permissions","objetivo":"Popula as permissões padrão de papéis a partir da lib RBAC compartilhada.","entradas":"Nenhuma.","saidas":"permissions_seeded (contagem total de role_permission).","regras":"Chama seed_role_permissions da lib; idempotente conforme implementação da lib.","efeitos":"INSERT em role_permission (via lib seed_role_permissions). Sem audit_log direto. Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado (tabelas role/role_permission)."}]},{"group":"Integração Telegram","objetivo":"Vincular IDs de usuário do Telegram a contas ERP e checar permissões via Telegram.","acoes":[{"nome":"link-telegram-user","objetivo":"Vincula um Telegram user ID a uma conta de usuário ERP.","entradas":"--user-id (obrigatório); --telegram-user-id (obrigatório).","saidas":"user_id, username, telegram_user_id, linked (true).","regras":"Ambos obrigatórios; erro se usuário não encontrado; erro se o telegram-user-id já está vinculado a outra conta.","efeitos":"UPDATE erp_user.telegram_user_id (+ updated_at); audit_log (action 'link-telegram-user'). Sem gl_entry/SLE/PLE.","precondicoes":"Usuário ERP existente; telegram-user-id não vinculado a outro usuário."},{"nome":"unlink-telegram-user","objetivo":"Remove o vínculo de um Telegram user ID de uma conta ERP.","entradas":"--telegram-user-id (obrigatório).","saidas":"user_id, telegram_user_id, unlinked (true).","regras":"telegram-user-id obrigatório; erro se nenhum usuário estiver vinculado a esse ID.","efeitos":"UPDATE erp_user.telegram_user_id = NULL (+ updated_at); audit_log (action 'unlink-telegram-user', com old values). Sem gl_entry/SLE/PLE.","precondicoes":"Existir usuário vinculado ao telegram-user-id."},{"nome":"check-telegram-permission","objetivo":"Verifica se um usuário Telegram tem permissão para uma ação de skill.","entradas":"--telegram-user-id (obrigatório); --skill (obrigatório); --check-action (obrigatório).","saidas":"allowed (bool); se vinculado: user_id, skill, action, telegram_user_id; se não: reason='not_linked'.","regras":"Três campos obrigatórios; resolve user via resolve_telegram_user_id; se não vinculado retorna allowed=false reason not_linked; senão consulta check_permission da lib RBAC.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado; permissões seeded para resultado significativo."}]},{"group":"Credenciais de Integração","objetivo":"Armazenar, consultar e migrar credenciais de integrações no arquivo de credenciais criptografado.","acoes":[{"nome":"set-credential","objetivo":"Armazena uma credencial de integração no arquivo criptografado.","entradas":"--integration (obrigatório); valor via --value OU --from-stdin OU --from-env <VAR> (um obrigatório).","saidas":"message, integration, credentials_file (caminho).","regras":"integration obrigatório; exige fonte de valor (value/stdin/env); erro se valor vazio ou env var não setada; nunca aceita o valor via --api-key.","efeitos":"Escreve no arquivo de credenciais criptografado (glue_lib.credentials, NÃO em tabela do DB); sem audit_log; sem gl_entry/SLE/PLE.","precondicoes":"Lib de credenciais disponível; master key disponível para criptografia."},{"nome":"get-credential","objetivo":"Informa se uma credencial existe (sem expor o valor).","entradas":"--integration (obrigatório).","saidas":"integration, exists (bool), redacted_preview (4 primeiros/4 últimos chars se len>=12, senão null).","regras":"integration obrigatório; nunca retorna o valor completo, apenas preview redigido.","efeitos":"nenhum (leitura do arquivo de credenciais).","precondicoes":"Lib de credenciais disponível."},{"nome":"list-credentials","objetivo":"Lista os nomes de integrações com credenciais armazenadas.","entradas":"Nenhuma.","saidas":"integrations (array de nomes).","regras":"Nunca lista valores, apenas nomes.","efeitos":"nenhum (leitura do arquivo de credenciais).","precondicoes":"Lib de credenciais disponível."},{"nome":"delete-credential","objetivo":"Remove uma credencial armazenada.","entradas":"--integration (obrigatório).","saidas":"integration, deleted (bool), message.","regras":"integration obrigatório; deleted=false se não havia credencial.","efeitos":"Remove entrada do arquivo de credenciais criptografado; sem audit_log; sem gl_entry/SLE/PLE.","precondicoes":"Lib de credenciais disponível."},{"nome":"migrate-credentials","objetivo":"Migra credenciais em texto plano de tabelas de addons para o arquivo criptografado.","entradas":"--dry-run (flag; pré-visualiza sem gravar).","saidas":"dry_run, moved (array), skipped (array), next (orientação).","regras":"Detecta tabela stripe_account.api_key; pula se já no store criptografado; com --dry-run não grava. Falhas por tabela ausente são ignoradas (addon não instalado).","efeitos":"Sem dry-run: escreve no arquivo de credenciais e faz UPDATE stripe_account.api_key=NULL (commit). Com dry-run: nenhum. Sem gl_entry/SLE/PLE; sem audit_log.","precondicoes":"Tabela de addon (ex.: stripe_account) presente para haver o que migrar."}]},{"group":"Campos Personalizados (UDF)","objetivo":"Definir, listar, remover e atribuir valores de campos customizados (UDF) em tabelas core.","acoes":[{"nome":"add-custom-field","objetivo":"Registra a definição de um campo customizado em uma tabela core (M1).","entradas":"--table (obrigatório); --field-name (obrigatório, snake_case); --field-type (obrigatório: text|int|float|date|select|link|json); --label, --required (flag), --default, --options, --skill-name (default 'glue-setup').","saidas":"result='registered', custom_field_id, table, field_name, field_type.","regras":"table/field-name obrigatórios; field-type validado contra lista; --options para select vira {values:[...]}, para link vira {table:...}, demais tipos é JSON cru; IntegrityError retorna 'já existe'.","efeitos":"INSERT em custom_field (via cf.add_custom_field); audit_log (action 'create', entity 'custom_field'). Sem gl_entry/SLE/PLE.","precondicoes":"Banco inicializado com tabela custom_field (lib custom_fields)."},{"nome":"list-custom-fields","objetivo":"Lista definições de campos customizados (opcionalmente por tabela).","entradas":"--table (opcional, filtro).","saidas":"custom_fields (array), count.","regras":"Filtra por table_name se informado; ordena por table_name, field_name.","efeitos":"nenhum (leitura).","precondicoes":"Tabela custom_field existente."},{"nome":"remove-custom-field","objetivo":"Remove a definição de um campo customizado e seus valores armazenados.","entradas":"--table (obrigatório); --field-name (obrigatório); --confirm (flag, exigido se houver valores).","saidas":"result='removed', table, field_name, deleted_values (contagem).","regras":"table/field-name obrigatórios; erro se campo não existe; se há valores armazenados, exige --confirm; remoção respeita owner_skill (erro 'owner mismatch'). Hard delete.","efeitos":"DELETE em custom_field e custom_field_value (via cf.remove_custom_field); audit_log (action 'delete', entity 'custom_field'). Sem gl_entry/SLE/PLE.","precondicoes":"Definição de campo existente; --confirm se houver valores."},{"nome":"set-custom-field-value","objetivo":"Define o valor de um campo customizado em uma linha (validado).","entradas":"--table (obrigatório); --row-id (obrigatório); --field-name (obrigatório); --value (obrigatório).","saidas":"result='stored', table, row_id, field_name, value.","regras":"table/row-id/field-name obrigatórios; value obrigatório (não pode ser None); valida via cf.validate_custom_field_values e aborta com erros se inválido.","efeitos":"INSERT/UPDATE em custom_field_value (via cf.store_custom_field_values, commit). Sem audit_log. Sem gl_entry/SLE/PLE.","precondicoes":"Definição do campo registrada para a tabela."},{"nome":"get-custom-field-values","objetivo":"Lê valores de campos customizados de uma linha (todos ou um específico).","entradas":"--table (obrigatório); --row-id (obrigatório); --field-name (opcional, filtra um campo).","saidas":"table, row_id, custom_fields (dict de valores).","regras":"table/row-id obrigatórios; se --field-name informado retorna apenas esse campo.","efeitos":"nenhum (leitura).","precondicoes":"Tabela custom_field_value existente."}]},{"group":"Registros de Tipos e Status","objetivo":"Administrar em runtime os registries de account_type e voucher_type (extensão, listagem, desativação) e diagnosticar cobertura.","acoes":[{"nome":"add-account-type","objetivo":"Registra um novo account_type para que contas possam usá-lo (M0).","entradas":"--account-type (obrigatório); --label (default: derivado do valor); --skill-name (default 'custom').","saidas":"result='registered', account_type, label.","regras":"account-type obrigatório; IntegrityError retorna 'já registrado'.","efeitos":"INSERT em account_type_registry (is_active=1); audit_log (action 'create', entity 'account_type_registry'). Sem gl_entry/SLE/PLE.","precondicoes":"Tabela account_type_registry existente."},{"nome":"list-account-types","objetivo":"Lista account types registrados (só ativos, salvo --include-inactive).","entradas":"--include-inactive (flag).","saidas":"account_types (array), count.","regras":"Sem a flag, filtra is_active=1; ordena por account_type.","efeitos":"nenhum (leitura).","precondicoes":"Tabela account_type_registry existente."},{"nome":"deactivate-account-type","objetivo":"Soft-disable de um account_type (is_active=0), bloqueado se em uso.","entradas":"--account-type (obrigatório).","saidas":"result='deactivated', account_type.","regras":"account-type obrigatório; bloqueia se alguma account usa o tipo (conta COUNT em account); erro se o tipo não estava registrado (nenhuma linha alterada).","efeitos":"UPDATE account_type_registry SET is_active=0; audit_log (action 'update'). Leitura em account para checar uso. Sem gl_entry/SLE/PLE.","precondicoes":"account_type registrado e não usado por nenhuma conta."},{"nome":"add-voucher-type","objetivo":"Registra um novo voucher_type para uma tabela-alvo (M0).","entradas":"--voucher-type (obrigatório); --target-table (obrigatório: gl_entry|stock_ledger_entry|payment_allocation); --label (default derivado); --skill-name (default 'custom').","saidas":"result='registered', voucher_type, target_table, label.","regras":"voucher-type obrigatório; target-table deve ser um dos três alvos válidos; IntegrityError retorna 'já registrado para o alvo'.","efeitos":"INSERT em voucher_type_registry (is_active=1); audit_log (action 'create'). Sem postagens em gl_entry/SLE/PLE.","precondicoes":"Tabela voucher_type_registry existente."},{"nome":"list-voucher-types","objetivo":"Lista voucher types registrados (opcionalmente por target-table).","entradas":"--include-inactive (flag); --target-table (filtro opcional).","saidas":"voucher_types (array), count.","regras":"Sem a flag filtra is_active=1; filtra por target_table se informado; ordena por target_table, voucher_type.","efeitos":"nenhum (leitura).","precondicoes":"Tabela voucher_type_registry existente."},{"nome":"deactivate-voucher-type","objetivo":"Soft-disable de um voucher_type em uma tabela-alvo, bloqueado se há linhas vivas usando-o.","entradas":"--voucher-type (obrigatório); --target-table (obrigatório, um dos três alvos).","saidas":"result='deactivated', voucher_type, target_table.","regras":"voucher-type obrigatório; target-table validado; bloqueia se houver linhas na tabela-alvo usando o voucher_type; erro se não registrado para o alvo.","efeitos":"UPDATE voucher_type_registry SET is_active=0 (por voucher_type+target_table); audit_log (action 'update'). Leitura na tabela-alvo para checar uso. Sem novas postagens em gl_entry/SLE/PLE.","precondicoes":"voucher_type registrado para o alvo e sem linhas vivas usando-o."},{"nome":"validate-registry-completeness","objetivo":"Diagnóstico read-only: reporta valores de tipo/status em uso nos dados que não estão registrados+ativos.","entradas":"Nenhuma.","saidas":"complete (bool), unregistered_in_use (dict por categoria), detail (explicação).","regras":"Cobre account_type, party_type (gl_entry/payment_entry/payment_ledger_entry), voucher_type por alvo e asset_status; tolera tabelas ausentes em instalação mínima.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado; os registries existentes."}]},{"group":"Backup e Restauração","objetivo":"Criar, listar, verificar, restaurar e fazer retenção de backups do banco (com cripto opcional).","acoes":[{"nome":"backup-database","objetivo":"Cria um backup do banco SQLite, opcionalmente criptografado AES-256.","entradas":"--backup-path (default: BACKUP_DIR/glue_backup_<ts>.sqlite|.enc); --encrypt (flag); --passphrase (obrigatório se --encrypt).","saidas":"backup_path, size_bytes, encrypted, timestamp; se criptografado: carries_master_key, original_size.","regras":"Erro se --encrypt sem --passphrase. Criptografado: faz backup temp, depois encrypt_file com HMAC; se existe master key local, ela é wrapped com a passphrase e embutida no header (permite restore cross-machine). Define mode 600 no arquivo.","efeitos":"Cria arquivo de backup no filesystem (usa src.backup); não escreve em tabelas do DB; sem audit_log; sem gl_entry/SLE/PLE.","precondicoes":"Banco existente; lib crypto/master_key para modo criptografado."},{"nome":"list-backups","objetivo":"Lista arquivos de backup com tamanho, data e flag de criptografia.","entradas":"Nenhuma.","saidas":"backups (array: path, filename, size_bytes, timestamp, encrypted), count, total_size_bytes.","regras":"Casa glue_*.sqlite e glue_*.enc; parseia timestamp do nome; ordena reverso (recentes primeiro); retorna vazio se diretório não existe.","efeitos":"nenhum (leitura do filesystem).","precondicoes":"Nenhuma (diretório de backups pode não existir)."},{"nome":"verify-backup","objetivo":"Valida um arquivo de backup sem restaurar (SQLite válido, schema Glue, integridade).","entradas":"--backup-path (obrigatório); --passphrase (obrigatório se backup criptografado).","saidas":"valid, integrity, tables, schema_module, schema_version, size_bytes, encrypted (ou para .enc sem passphrase: valid=null com mensagem).","regras":"Erro se backup-path ausente ou arquivo inexistente; auto-detecta cripto; sem passphrase para .enc retorna valid=null; valida presença de schema_version, roda PRAGMA integrity_check; remove temp descriptografado ao final.","efeitos":"nenhum (leitura/validação; usa arquivo temp efêmero que é apagado).","precondicoes":"Arquivo de backup existente; passphrase para criptografados."},{"nome":"restore-database","objetivo":"Restaura o banco a partir de um backup, com backup de segurança e rollback automático.","entradas":"--backup-path (obrigatório); --passphrase (obrigatório se criptografado); --db-path (alvo, default padrão).","saidas":"restored_from, safety_backup, size_bytes, schema_versions, integrity, was_encrypted.","regras":"Erro se backup-path ausente/inexistente; cripto exige passphrase; valida schema_version no backup; fecha a conexão atual, cria safety backup, copia backup sobre o DB, roda integrity_check; em qualquer falha faz rollback restaurando o safety backup.","efeitos":"Substitui o arquivo do DB no filesystem; cria safety backup (glue_pre_restore_<ts>.sqlite); ajusta permissões; em falha restaura estado anterior. Não escreve em tabelas via SQL; sem audit_log.","precondicoes":"Backup válido Glue; passphrase se criptografado."},{"nome":"cleanup-backups","objetivo":"Aplica política de retenção (7 diários, 4 semanais, 12 mensais) removendo o excesso.","entradas":"Nenhuma (opera sobre glue_backup_*.sqlite no BACKUP_DIR).","saidas":"kept, deleted, freed_bytes.","regras":"Parseia timestamps do nome; mantém 7 datas diárias mais recentes, depois 4 semanais (mais antigo por semana) e 12 mensais; deleta o restante; tolera erros de remoção individual.","efeitos":"Remove arquivos de backup do filesystem; audit_log (action 'cleanup', entity 'backup'). Sem gl_entry/SLE/PLE.","precondicoes":"Diretório de backups com arquivos no padrão esperado."}]},{"group":"Schema e Migrações","objetivo":"Inicializar o schema do banco, aplicar migrações de fundação e consultar a versão de schema.","acoes":[{"nome":"initialize-database","objetivo":"Inicializa (ou re-inicializa com --force) todo o schema do banco Glue.","entradas":"--db-path (default padrão); --force (flag: dropa e recria do zero).","saidas":"message, db_path, tables, indexes, skills_registered, journal_mode (WAL), foreign_keys (ON), reinitialized.","regras":"Usa CREATE TABLE IF NOT EXISTS (idempotente); com --force remove o arquivo e recria; symlinka a lib compartilhada; ajusta permissões 600; verifica recontando tabelas/índices. Gerencia sua própria conexão (não usa a conexão padrão do dispatch).","efeitos":"Cria/recria todas as tabelas e índices via init_schema.init_db; com --force remove o arquivo do DB; symlinka ~/.glue/lib; chmod nos arquivos do DB. Sem audit_log; sem gl_entry/SLE/PLE.","precondicoes":"Módulo init_schema disponível; permissão de escrita no caminho do DB."},{"nome":"migrate","objetivo":"Executa migrações pendentes da fundação (migrations/NNN_*.py), registrando-as no ledger.","entradas":"--db-path (default padrão); --dry-run (flag: lista pendentes sem aplicar).","saidas":"Resultado do runner (ex.: migrações aplicadas/pendentes); em falha, erro com nome da migração e detalhe.","regras":"Idempotente e dialect-aware; --dry-run apenas lista; falha de migração retorna erro com suggestion. Gerencia suas próprias conexões via db_path (não usa a conexão do dispatch).","efeitos":"Aplica DDL/DML das migrações e grava em glue_schema_migration (ledger). Com --dry-run: nenhum. Sem audit_log; efeitos dependem das migrações.","precondicoes":"migration_runner.py e arquivos de migração presentes; DB existente."},{"nome":"get-schema-version","objetivo":"Lê a versão de schema registrada para um módulo.","entradas":"--module (default 'glue-setup').","saidas":"module, version, updated_at.","regras":"Erro se não houver versão registrada para o módulo.","efeitos":"nenhum (leitura).","precondicoes":"Tabela schema_version populada (via initialize-database)."}]},{"group":"Dados Padrão e Onboarding","objetivo":"Semear dados padrão, criar empresa-demo de tutorial e conduzir o assistente de onboarding passo-a-passo.","acoes":[{"nome":"seed-defaults","objetivo":"Carrega dados padrão (moedas, UoMs, condições de pagamento) de forma idempotente.","entradas":"--company-id (default: primeira empresa).","saidas":"currencies_seeded, uoms_seeded, payment_terms_seeded (contagens).","regras":"Sem company-id usa a primeira; erro se nenhuma empresa existir; lê JSONs de ASSETS_DIR; usa INSERT OR IGNORE (idempotente).","efeitos":"INSERT OR IGNORE em currency, uom e payment_terms; audit_log (action 'seed', entity 'system'). Sem gl_entry/SLE/PLE.","precondicoes":"Pelo menos uma empresa; arquivos de assets presentes."},{"nome":"tutorial","objetivo":"Cria a empresa-demo 'Acme Corp' com plano de contas mínimo, centro de custo e ano fiscal.","entradas":"Nenhuma flag relevante (idempotente).","saidas":"message, company_id, accounts_created (ou accounts), fiscal_year, cost_center, next_steps; se já existe: message + accounts + next_steps.","regras":"Idempotente: se 'Acme Corp' já existe, retorna dados existentes; senão cria empresa, ~21 contas (plano fixo), define contas padrão da empresa, cost center 'Main' e fiscal year do ano corrente.","efeitos":"INSERT em company, account (várias), cost_center, fiscal_year; UPDATE company (contas e cost center padrão); audit_log (action 'create', entity 'company'). Sem postagens em gl_entry/SLE/PLE.","precondicoes":"Banco inicializado."},{"nome":"onboarding-step","objetivo":"Assistente de onboarding por estado (state-machine) que avança um passo por chamada.","entradas":"--answer (resposta do passo atual); --reset (flag: reinicia no passo 1).","saidas":"step, completed, prompt, options, field; ao final: company_id, currency, fiscal_month, load_demo, results (steps_completed/steps_failed).","regras":"Estado persistido em ~/.glue/onboarding_state.json. Passos: 1 nome; 2 moeda (validada contra VALID_CURRENCIES); 3 mês fiscal (1-12); 4 demo (yes/no). Passo 4 executa subprocessos: setup-company, seed-defaults, setup-chart-of-accounts (glue-gl, us_gaap) e, se demo, seed-demo-data (glue meta). Falhas de subpasso vão para steps_failed sem abortar.","efeitos":"Escreve/limpa o arquivo de estado de onboarding (filesystem). Dispara subprocessos que, por sua vez, gravam em company, account, currency/uom/payment_terms e demo data, e seus próprios audit_log. Esta ação em si não escreve diretamente em tabelas.","precondicoes":"Banco inicializado; scripts glue-gl/glue para os passos C/D (opcionais)."}]},{"group":"Config. Regionais/Avançadas","objetivo":"Definir configurações regionais por empresa e configurar a conta de adiantamento (advance) de cliente/fornecedor.","acoes":[{"nome":"update-regional-settings","objetivo":"Define configurações regionais da empresa (formato de data/número, template fiscal padrão).","entradas":"--company-id (default: primeira empresa); --date-format; --number-format; --default-tax-template-id (ao menos um obrigatório).","saidas":"updated (lista de chaves atualizadas).","regras":"Sem company-id usa a primeira; erro se nenhuma empresa; erro 'No settings to update' se nada informado; faz upsert por (company_id, key).","efeitos":"INSERT/UPDATE (ON CONFLICT) em regional_settings; audit_log (action 'update', entity 'regional_settings'). Sem gl_entry/SLE/PLE.","precondicoes":"Pelo menos uma empresa; tabela regional_settings."},{"nome":"set-advance-account","objetivo":"Configura a sub-conta de adiantamento (advance) de cliente ou fornecedor na empresa (S2).","entradas":"--company-id (obrigatório); --account-id (obrigatório); --type (obrigatório: customer|supplier).","saidas":"result='set', company_id, type, column (advance_from_customer_account_id ou advance_to_supplier_account_id), account_id.","regras":"Todos obrigatórios; type validado; empresa e conta devem existir; conta não pode ser de grupo; para customer exige root_type 'liability', para supplier exige 'asset'. Quando setada, submit-payment roteia a perna de adiantamento não-alocado para esta conta.","efeitos":"UPDATE company (coluna advance_*_account_id allowlistada + updated_at, via dynamic_update); audit_log (action 'update', entity 'company'). Sem gl_entry/SLE/PLE.","precondicoes":"Empresa e conta (folha, root_type correto) existentes."}]},{"group":"Auditoria/Status/Chave-Mestra","objetivo":"Consultar trilha de auditoria e status do sistema e importar a chave-mestra de criptografia de um backup.","acoes":[{"nome":"get-audit-log","objetivo":"Consulta a trilha de auditoria com filtros opcionais.","entradas":"--entity-type, --entity-id, --audit-action, --from-date, --to-date (filtros opcionais); --limit (default 50).","saidas":"entries (array de registros de auditoria, com old_values/new_values já parseados de JSON).","regras":"Aplica filtros conforme flags; ordena por timestamp desc; faz parse dos campos JSON old_values/new_values.","efeitos":"nenhum (leitura).","precondicoes":"Tabela audit_log existente."},{"nome":"status","objetivo":"Retorna o status geral do sistema (contagens e versões de schema).","entradas":"Nenhuma.","saidas":"companies, currencies (habilitadas), uoms, payment_terms, schema_versions (dict módulo->versão).","regras":"Conta company, currency (enabled=1), uom, payment_terms; lê todas as linhas de schema_version.","efeitos":"nenhum (leitura).","precondicoes":"Banco inicializado."},{"nome":"import-master-key-from-backup","objetivo":"Extrai a chave-mestra de criptografia embutida em um backup e a instala localmente (restore cross-machine).","entradas":"--backup-path (obrigatório); passphrase via --passphrase OU --passphrase-from-stdin OU --passphrase-from-env <VAR> (uma obrigatória); --force (flag: sobrescreve chave existente).","saidas":"message, master_key_path, next (orientação para restore).","regras":"backup-path obrigatório e arquivo deve existir; exige passphrase não-vazia; backup deve ser formato ECRYPT02 e carregar wrapped master key (senão erro); passphrase errada falha o unwrap; recusa sobrescrever chave existente sem --force (com aviso de perda de dados).","efeitos":"Escreve o arquivo master.key em ~/.config/glue (MASTER_KEY_PATH); com --force remove a chave existente antes. Não escreve em tabelas do DB; sem audit_log; sem gl_entry/SLE/PLE.","precondicoes":"Backup ECRYPT02 com chave embutida; passphrase de wrapping correta; ausência de master key (ou --force)."}]}]},"gl":{"module":"gl","display":"Contabilidade (GL)","functionalities":[{"group":"Plano de Contas","objetivo":"Criar, importar, consultar e atualizar contas contábeis e a hierarquia do plano de contas por empresa.","acoes":[{"nome":"setup-chart-of-accounts","objetivo":"Cria o plano de contas de uma empresa a partir de um template JSON de assets/charts.","entradas":"--template (default 'us_gaap'); --company-id (obrigatório se houver mais de uma empresa; auto-detecta se houver só uma).","saidas":"accounts_created, template, company_id.","regras":"Falha se empresa não encontrada, se nenhuma empresa existe, se há múltiplas e --company-id ausente, ou se o template não existe em assets/charts/{template}.json. Resolve parent_id e depth via número da conta; pula contas cujo account_number já existe (idempotente).","efeitos":"INSERT em account (uma linha por conta nova: id, name, account_number, parent_id, root_type, account_type, is_group, balance_direction, company_id, depth); audit_log (import/account); commit.","precondicoes":"A empresa (company) deve existir e o arquivo de template do plano deve estar presente."},{"nome":"add-account","objetivo":"Cria uma única conta contábil (grupo ou postável) para uma empresa.","entradas":"--name (obrigatório); --company-id (obrigatório); --root-type (obrigatório: asset|liability|equity|income|expense); --account-type; --account-number; --parent-id; --currency (default 'USD'); --is-group (default false).","saidas":"status='created', account_id, name, account_number.","regras":"account_type em LEAF_ONLY_TYPES (receivable, payable, bank, cash, tax, cost_of_goods_sold, stock, depreciation, accumulated_depreciation, round_off) não pode ser grupo. account_type informado deve estar registrado e ativo em account_type_registry. balance_direction='credit_normal' para liability/equity/income, senão 'debit_normal'. depth = depth do pai +1 (erro se pai não existe). IntegrityError vira erro de duplicidade.","efeitos":"INSERT em account; audit_log (create/account); commit.","precondicoes":"Empresa existente; pai existente se --parent-id; account_type registrado/ativo se informado."},{"nome":"update-account","objetivo":"Atualiza campos editáveis de uma conta (nome, número, pai, congelamento).","entradas":"--account-id (obrigatório); campos opcionais: --name, --account-number, --parent-id, --is-frozen.","saidas":"status='updated', account_id, updated_fields.","regras":"Erro se conta não existe ou se nenhum campo for fornecido. Faz lookup de existência de gl_entry não-cancelado (has_entries) mas o código não bloqueia mudanças com base nisso. --is-frozen é normalizado para 1/0. Seta updated_at.","efeitos":"UPDATE em account (campos enviados + updated_at) via dynamic_update; audit_log (update/account com old/new); commit.","precondicoes":"A conta deve existir."},{"nome":"list-accounts","objetivo":"Lista contas de uma empresa com filtros e paginação.","entradas":"--company-id ou --company (nome, resolvido); --root-type; --account-type; --is-group; --parent-id; --search (name/account_number); --include-frozen (default false); --limit (default 20); --offset (default 0).","saidas":"accounts[], total_count, limit, offset, has_more.","regras":"Sem --include-frozen, filtra is_frozen=0 e disabled=0. Ordena por account_number depois name. total_count calculado antes do limit.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."},{"nome":"get-account","objetivo":"Retorna uma conta com seu saldo calculado até uma data.","entradas":"--account-id (obrigatório); --as-of-date (default: hoje UTC).","saidas":"account (todos os campos + balance, debit_total, credit_total).","regras":"Erro se conta não existe. Saldo = debit_total - credit_total se balance_direction='debit_normal', senão credit_total - debit_total, somando gl_entry não-cancelados com posting_date <= as_of.","efeitos":"nenhum (leitura).","precondicoes":"A conta deve existir."},{"nome":"import-chart-of-accounts","objetivo":"Importa contas de um arquivo CSV para uma empresa, complementando o setup por template.","entradas":"--csv-path (obrigatório, .csv válido e arquivo regular); --company-id (obrigatório). Colunas CSV: name, root_type, account_number, account_type, parent_name, currency, is_group.","saidas":"imported, skipped, total_rows.","regras":"Valida extensão .csv, existência e schema via validate_csv('account'); erro se CSV inválido ou vazio. Pula contas cujo name já existe na empresa (skipped). Resolve parent por parent_name; balance_direction derivado do root_type; depth fixado em 0; currency default 'USD'.","efeitos":"INSERT em account (uma por linha importada); commit. NÃO grava audit_log.","precondicoes":"Empresa existente e arquivo CSV válido acessível."}]},{"group":"Congelamento de Contas","objetivo":"Bloquear e desbloquear contas para postagem via flag is_frozen.","acoes":[{"nome":"freeze-account","objetivo":"Marca uma conta como congelada (is_frozen=1).","entradas":"--account-id (obrigatório).","saidas":"status='updated', account_id, is_frozen=true.","regras":"Erro se a conta não existe.","efeitos":"UPDATE account.is_frozen=1 e updated_at; audit_log (freeze/account); commit.","precondicoes":"A conta deve existir."},{"nome":"unfreeze-account","objetivo":"Remove o congelamento de uma conta (is_frozen=0).","entradas":"--account-id (obrigatório).","saidas":"status='updated', account_id, is_frozen=false.","regras":"Erro se a conta não existe.","efeitos":"UPDATE account.is_frozen=0 e updated_at; audit_log (unfreeze/account); commit.","precondicoes":"A conta deve existir."}]},{"group":"Lançamentos no Razão","objetivo":"Postar, estornar e listar lançamentos no razão (gl_entry) por voucher.","acoes":[{"nome":"post-gl-entries","objetivo":"Posta um conjunto de linhas débito/crédito balanceadas no razão para um voucher.","entradas":"--voucher-type (obrigatório, canonicalizado), --voucher-id (obrigatório), --posting-date (obrigatório), --company-id (obrigatório), --entries (obrigatório, array JSON).","saidas":"status='created', gl_entry_ids, entries_created, warnings.","regras":"voucher_type é normalizado para snake_case via canonical_voucher_type. --entries deve ser array JSON não-vazio. Validação por validate_gl_entries (lança ValueError, ex.: desbalanceado/conta inválida); inserção por insert_gl_entries.","efeitos":"INSERT em gl_entry (via lib, com débito/crédito base, checksum de cadeia); audit_log (post/gl_entry); commit.","precondicoes":"Empresa e contas referenciadas existentes; entries balanceadas e válidas."},{"nome":"reverse-gl-entries","objetivo":"Cria lançamentos de estorno para todas as linhas de um voucher.","entradas":"--voucher-type (obrigatório, canonicalizado), --voucher-id (obrigatório), --posting-date (default: hoje UTC).","saidas":"reversed_count, reversal_entry_ids.","regras":"Normaliza voucher_type. Delega a reverse_gl_entries da lib (lança ValueError se voucher não encontrado/já estornado).","efeitos":"INSERT de lançamentos de estorno em gl_entry (débito/crédito invertidos); audit_log (reverse/gl_entry); commit.","precondicoes":"Existirem gl_entry para o voucher informado."},{"nome":"list-gl-entries","objetivo":"Lista lançamentos do razão com join na conta, filtros e paginação.","entradas":"--company-id/--company; --account-id; --voucher-type (canonicalizado); --voucher-id; --party-type; --party-id; --from-date; --to-date; --is-cancelled; --limit (default 100); --offset (default 0).","saidas":"entries[] (campos de gl_entry + account_name), total_count, limit, offset, has_more.","regras":"Junta gl_entry com account; filtra company via account.company_id. voucher_type filtrado é canonicalizado. Ordena por posting_date desc, created_at desc. total_count calculado antes do limit.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma obrigatória além de DB acessível."}]},{"group":"Saldos de Conta","objetivo":"Calcular o saldo de uma conta em uma data, opcionalmente por parte.","acoes":[{"nome":"get-account-balance","objetivo":"Calcula o saldo de uma conta até uma data, com filtro opcional por parte.","entradas":"--account-id (obrigatório); --as-of-date (obrigatório); --party-type; --party-id.","saidas":"balance, debit_total, credit_total, currency.","regras":"Erro se a conta não existe ou se faltar --as-of-date. Soma gl_entry não-cancelados com posting_date <= as_of; saldo conforme balance_direction (débito-crédito ou crédito-débito).","efeitos":"nenhum (leitura).","precondicoes":"A conta deve existir."}]},{"group":"Anos Fiscais","objetivo":"Criar e listar anos fiscais de uma empresa, garantindo não-sobreposição de datas.","acoes":[{"nome":"add-fiscal-year","objetivo":"Cria um ano fiscal para a empresa validando sobreposição de datas.","entradas":"--name (obrigatório); --start-date (obrigatório); --end-date (obrigatório); --company-id (obrigatório).","saidas":"status='created', fiscal_year_id, name.","regras":"Erro se as datas se sobrepõem a um fiscal_year existente da empresa. IntegrityError vira erro de duplicidade.","efeitos":"INSERT em fiscal_year (id, name, start_date, end_date, company_id); audit_log (create/fiscal_year); commit.","precondicoes":"A empresa deve existir."},{"nome":"list-fiscal-years","objetivo":"Lista os anos fiscais de uma empresa com paginação.","entradas":"--company-id/--company; --limit (default 20); --offset (default 0).","saidas":"fiscal_years[], total_count, limit, offset, has_more.","regras":"Filtra por company_id; ordena por start_date desc.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."}]},{"group":"Fechamento de Período","objetivo":"Validar, fechar e reabrir um ano fiscal, transferindo o resultado para lucros acumulados.","acoes":[{"nome":"validate-period-close","objetivo":"Calcula receita, despesa, resultado líquido e checa o balanceamento do balancete antes do fechamento.","entradas":"--fiscal-year-id (obrigatório).","saidas":"fiscal_year, income_total, expense_total, net_income, trial_balance_balanced.","regras":"Erro se FY não existe ou já está fechado. income = credit-debit de contas income; expense = debit-credit de contas expense (no intervalo do FY, não-cancelados). trial_balance_balanced = |total_debit-total_credit| < 0.01 sobre toda a empresa.","efeitos":"nenhum (leitura).","precondicoes":"Ano fiscal existente e ainda aberto."},{"nome":"close-fiscal-year","objetivo":"Fecha o ano fiscal criando o voucher de fechamento e zerando contas de resultado contra lucros acumulados.","entradas":"--fiscal-year-id (obrigatório); --closing-account-id (obrigatório, conta equity); --posting-date (obrigatório).","saidas":"status='submitted', pcv_id, net_pl_transferred, gl_entries_created, fiscal_year_closed=true.","regras":"Erro se FY não existe/já fechado; conta de fechamento deve existir, ser root_type='equity' e pertencer à MESMA empresa do FY (ADR-0016, hard-fail). net_pl = income - expense. Helper _close_pl_accounts zera cada conta income/expense leaf (is_group=0) com saldo, postando pares contra lucros acumulados.","efeitos":"INSERT em period_closing_voucher (status='submitted'); INSERT de pares em gl_entry (voucher_type='period_closing', voucher_id=pcv_id, moeda 'USD'/rate '1'); UPDATE fiscal_year.is_closed=1; audit_log (close/fiscal_year); commit.","precondicoes":"Ano fiscal aberto e conta de lucros acumulados (equity) da mesma empresa existente."},{"nome":"reopen-fiscal-year","objetivo":"Reabre um ano fiscal fechado, cancelando o voucher de fechamento e seus lançamentos.","entradas":"--fiscal-year-id (obrigatório).","saidas":"fiscal_year_id, is_closed=false, pcv_reversed.","regras":"Erro se FY não existe ou não está fechado. Localiza o period_closing_voucher submitted; se houver, cancela seus gl_entry e marca PCV como 'cancelled'.","efeitos":"UPDATE gl_entry.is_cancelled=1 (voucher_type='period_closing' do PCV); UPDATE period_closing_voucher.status='cancelled'; UPDATE fiscal_year.is_closed=0; audit_log (reopen/fiscal_year); commit.","precondicoes":"Ano fiscal existente e fechado."}]},{"group":"Centros de Custo","objetivo":"Criar e listar centros de custo da empresa.","acoes":[{"nome":"add-cost-center","objetivo":"Cria um centro de custo (grupo ou folha) para uma empresa.","entradas":"--name (obrigatório); --company-id (obrigatório); --parent-id; --is-group (default false).","saidas":"status='created', cost_center_id, name.","regras":"Erro se faltar name ou company-id. IntegrityError vira erro de duplicidade.","efeitos":"INSERT em cost_center (id, name, parent_id, company_id, is_group); audit_log (create/cost_center); commit.","precondicoes":"A empresa deve existir."},{"nome":"list-cost-centers","objetivo":"Lista os centros de custo de uma empresa com paginação.","entradas":"--company-id/--company; --parent-id; --limit (default 20); --offset (default 0).","saidas":"cost_centers[], total_count, limit, offset, has_more.","regras":"Filtra por company_id e opcionalmente parent_id; ordena por name.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."}]},{"group":"Dimensões Contábeis","objetivo":"Gerenciar o registro de dimensões contábeis (dimension_registry) que alimentam gl_entry.dimensions_json.","acoes":[{"nome":"add-dimension","objetivo":"Registra uma nova dimensão contábil com chave, rótulo e tipo de dado.","entradas":"--key (obrigatório); --label (obrigatório); --type (text|uuid_fk|enum, default 'text'); --refers-to (obrigatório se type=uuid_fk); --allowed-values (obrigatório se type=enum, CSV); --required-on-account-types (CSV).","saidas":"status='created', dimension_id, key, data_type.","regras":"key não pode colidir com chaves reservadas (account_id, cost_center_id, project_id). uuid_fk exige --refers-to; enum exige --allowed-values. CSVs viram listas JSON. IntegrityError vira 'dimension already exists'.","efeitos":"INSERT em dimension_registry; audit_log (create/dimension_registry); commit.","precondicoes":"Tabela dimension_registry disponível; key única e não reservada."},{"nome":"list-dimensions","objetivo":"Lista as dimensões contábeis registradas, ativas por padrão.","entradas":"--include-inactive (default false).","saidas":"dimensions[], count.","regras":"Sem --include-inactive, filtra is_active=1. Ordena por key.","efeitos":"nenhum (leitura).","precondicoes":"Tabela dimension_registry disponível."},{"nome":"update-dimension","objetivo":"Atualiza metadados de uma dimensão por chave (sem renomear a chave).","entradas":"--key (obrigatório); campos opcionais: --label, --type (validado), --refers-to, --allowed-values, --required-on-account-types, --is-active.","saidas":"status='updated', key.","regras":"Erro se dimensão não existe, se --type inválido, ou se nenhum campo for fornecido. Não permite renomear a key. Seta updated_at.","efeitos":"UPDATE em dimension_registry (campos enviados + updated_at); audit_log (update/dimension_registry); commit.","precondicoes":"A dimensão deve existir."},{"nome":"deactivate-dimension","objetivo":"Desativa uma dimensão, bloqueando se ainda referenciada por GL recente.","entradas":"--key (obrigatório); --within-days (default 90).","saidas":"status='deactivated', key.","regras":"Erro se dimensão não existe. Conta gl_entry não-cancelados com a chave em dimensions_json e posting_date >= hoje-within_days; se houver, recusa a desativação (dimensão em uso).","efeitos":"UPDATE dimension_registry.is_active=0 e updated_at; audit_log (update/dimension_registry); commit.","precondicoes":"A dimensão deve existir e não ter uso recente dentro da janela."}]},{"group":"Orçamentos","objetivo":"Criar e listar orçamentos por conta/centro de custo dentro de um ano fiscal, com realizado e variação.","acoes":[{"nome":"add-budget","objetivo":"Cria um orçamento para um ano fiscal, vinculado a conta e/ou centro de custo.","entradas":"--fiscal-year-id (obrigatório); --budget-amount (obrigatório); --account-id e/ou --cost-center-id (ao menos um obrigatório); --action-if-exceeded (default 'warn').","saidas":"status='created', budget_id.","regras":"Erro se faltar FY ou amount, ou se não houver nem account nem cost-center. company_id é herdado do fiscal_year. IntegrityError vira erro de duplicidade.","efeitos":"INSERT em budget (id, fiscal_year_id, account_id, cost_center_id, budget_amount, action_if_exceeded, company_id); audit_log (create/budget); commit.","precondicoes":"O ano fiscal deve existir."},{"nome":"list-budgets","objetivo":"Lista orçamentos de um ano fiscal com valor realizado e variação calculados do razão.","entradas":"--fiscal-year-id (obrigatório); --company-id/--company; --limit (default 20); --offset (default 0).","saidas":"budgets[] (campos + actual_amount, variance), total_count, limit, offset, has_more.","regras":"Erro se FY não existe. Para cada orçamento, soma debit de gl_entry não-cancelados no intervalo do FY filtrando por account_id e/ou cost_center_id; variance = budget_amount - actual.","efeitos":"nenhum (leitura).","precondicoes":"Ano fiscal existente; empresa resolvível."}]},{"group":"Séries de Numeração","objetivo":"Inicializar e avançar séries de numeração de documentos por tipo de entidade e empresa.","acoes":[{"nome":"seed-naming-series","objetivo":"Cria séries de numeração padrão (uma por tipo de entidade) para uma empresa no ano corrente.","entradas":"--company-id (obrigatório).","saidas":"series_created, total_types.","regras":"Itera ENTITY_PREFIXES gerando prefixo '{prefix}{ano}-'; cria a série apenas se ainda não existir (idempotente). current_value inicia em 0.","efeitos":"INSERT em naming_series (id, entity_type, prefix, current_value, company_id) por série nova; commit. NÃO grava audit_log.","precondicoes":"A empresa deve existir."},{"nome":"next-series","objetivo":"Retorna o próximo nome/número da série para um tipo de entidade.","entradas":"--entity-type (obrigatório); --company-id (obrigatório).","saidas":"series (nome gerado), entity_type.","regras":"Delega a get_next_name da lib (lança ValueError se entity_type/série inválida), que incrementa o contador.","efeitos":"UPDATE em naming_series (current_value incrementado, dentro de get_next_name); commit.","precondicoes":"Série existir para o entity_type/empresa (ou ser criável pela lib)."}]},{"group":"Importação","objetivo":"Importar saldos de abertura via CSV postando-os como lançamento de abertura no razão.","acoes":[{"nome":"import-opening-balances","objetivo":"Importa saldos de abertura de um CSV e os posta como um lançamento de abertura único.","entradas":"--csv-path (obrigatório, .csv válido); --company-id (obrigatório); --posting-date (obrigatório). Colunas: account_number, debit, credit, party_type, party_name.","saidas":"gl_entries_created, voucher_id, rows_processed.","regras":"Valida .csv e schema via validate_csv('opening_balance'); erro se inválido/vazio. Resolve conta por account_number (erro se não achar); resolve party_id por party_name em customer/supplier. Posta como voucher_type='journal_entry' com is_opening=True (insert_gl_entries lança ValueError se desbalanceado).","efeitos":"INSERT em gl_entry (via lib, marcados como abertura, mesmo voucher_id); commit. NÃO grava audit_log.","precondicoes":"Empresa e contas (por account_number) existentes; CSV válido acessível."}]},{"group":"Integridade e Câmbio","objetivo":"Verificar a integridade do razão e revalorizar saldos em moeda estrangeira no fim de período.","acoes":[{"nome":"check-gl-integrity","objetivo":"Verifica o balanceamento global e a integridade da cadeia de hash SHA-256 do razão de uma empresa.","entradas":"--company-id/--company.","saidas":"balanced, total_debit, total_credit, difference, chain_intact, broken_links, total_entries.","regras":"balanced = |total_debit-total_credit| < 0.01 (não-cancelados). Recalcula o hash encadeado (campos posting_date|account_id|debit|credit|voucher_type|voucher_id|prev_hash, prev inicial 'GENESIS') e compara com gl_checksum; entries sem checksum são puladas; conta broken_links.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."},{"nome":"revalue-foreign-balances","objetivo":"Revaloriza contas monetárias em moeda estrangeira na taxa de fim de período, postando ganho/perda não realizado.","entradas":"--company-id (obrigatório); --as-of-date (obrigatório).","saidas":"revaluations[] (por conta, com txn_balance, old/new_base_balance, gain_loss, exchange_rate, gl_entries ou skipped/reason), total_gain_loss, accounts_processed.","regras":"Erro se empresa não existe ou sem exchange_gain_loss_account_id. Processa contas leaf não-desabilitadas com currency != base e account_type em receivable/payable/bank/cash. Para cada uma com saldo: ganho/perda = saldo*nova_taxa - saldo_base atual; pula se taxa ausente ou variação zero; ganho → DR conta / CR FX, perda → DR FX / CR conta; aplica default_cost_center_id à perna FX.","efeitos":"INSERT em gl_entry (via insert_gl_entries, voucher_type='exchange_rate_revaluation', um voucher por conta); commit. NÃO grava audit_log.","precondicoes":"Empresa com default_currency e exchange_gain_loss_account_id configurados; taxas de câmbio cadastradas."}]},{"group":"Status","objetivo":"Fornecer estatísticas agregadas do estado do módulo GL.","acoes":[{"nome":"status","objetivo":"Retorna contagens agregadas de empresas, contas, anos fiscais e lançamentos do GL.","entradas":"--company-id (opcional; auto-detecta se houver só uma empresa, senão estatísticas globais).","saidas":"companies, accounts, fiscal_years, gl_entries, latest_posting_date.","regras":"Com company_id, conta accounts/fiscal_years/gl_entries não-cancelados e a maior posting_date dessa empresa; sem ele, agrega globalmente. companies é sempre a contagem total de empresas.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além de DB acessível."}]}]},"journals":{"module":"journals","display":"Lançamentos","functionalities":[{"group":"Criação/edição","objetivo":"Criar e alterar lançamentos contábeis em rascunho, validando partidas balanceadas e contas existentes.","acoes":[{"nome":"add-journal-entry","objetivo":"Cria um novo lançamento contábil (journal entry) em rascunho com suas linhas.","entradas":"--company-id (obrigatório); --posting-date (obrigatório); --lines JSON array (obrigatório); --entry-type (default 'journal'); --remark (opcional); --cwip-asset-id (opcional, hook CWIP).","saidas":"status='created', journal_entry_id, naming_series.","regras":"entry_type deve estar em VALID_ENTRY_TYPES; lines validadas por _validate_lines (>=2 linhas, debit/credit >=0, não ambos >0, ao menos um >0, total débito==crédito após round_currency); cada account_id deve existir; se --cwip-asset-id, o ativo deve estar 'under_construction' (validado no add, accumulation só no submit). Status inicial 'draft'.","efeitos":"INSERT em journal_entry (status='draft') e journal_entry_line; grava audit_log via audit(); commit. Sem postagem em gl_entry.","precondicoes":"Empresa (company) existente; contas (account) das linhas existentes; se CWIP, asset under_construction."},{"nome":"update-journal-entry","objetivo":"Atualiza um lançamento em rascunho (data, tipo, remark e/ou substitui linhas).","entradas":"--journal-entry-id (obrigatório); opcionais --posting-date, --entry-type, --remark, --lines (substitui todas as linhas).","saidas":"status='updated', journal_entry_id, updated_fields (lista de campos alterados).","regras":"JE deve existir e status=='draft' (senão erro com sugestão de cancelar). entry_type novo validado contra VALID_ENTRY_TYPES; se --lines, revalida por _validate_lines e existência das contas; erro 'No fields to update' se nada informado.","efeitos":"UPDATE em journal_entry (campos + total_debit/total_credit e updated_at); se linhas: DELETE+INSERT em journal_entry_line; grava audit_log; commit. Sem gl_entry.","precondicoes":"JE existente em status 'draft'; contas das novas linhas existentes."}]},{"group":"Consulta/listagem","objetivo":"Recuperar um lançamento individual ou listar lançamentos com filtros e paginação (somente leitura).","acoes":[{"nome":"get-journal-entry","objetivo":"Retorna um lançamento contábil com todas as suas linhas.","entradas":"--journal-entry-id (obrigatório).","saidas":"id, naming_series, posting_date, entry_type, status, total_debit, total_credit, remark, amended_from, company_id, lines[] (id, account_id, account_name, debit, credit, party_type, party_id, cost_center_id, project_id, remark).","regras":"JE deve existir (senão erro 'not found'). Linhas ordenadas por line_order com join em account para nome.","efeitos":"nenhum (leitura).","precondicoes":"JE existente."},{"nome":"list-journal-entries","objetivo":"Lista lançamentos de uma empresa com filtros e paginação.","entradas":"company resolvido por --company-id ou --company (obrigatório resolver um); opcionais --status, --entry-type, --from-date, --to-date, --account-id; --limit (default 20), --offset (default 0).","saidas":"entries[] (id, naming_series, posting_date, entry_type, status, total_debit, total_credit, remark), total_count, limit, offset, has_more.","regras":"Filtro obrigatório por company_id (resolve_company_id); --account-id filtra via subquery em journal_entry_line; ordenação por posting_date desc, created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Empresa identificável por id ou nome."}]},{"group":"Ciclo de vida","objetivo":"Transicionar o lançamento entre rascunho, submetido e cancelado, postando ou revertendo entradas no razão (gl_entry).","acoes":[{"nome":"submit-journal-entry","objetivo":"Submete um rascunho: revalida, posta entradas balanceadas no razão e muda status para 'submitted'.","entradas":"--journal-entry-id (obrigatório).","saidas":"status='submitted', journal_entry_id, gl_entries_created; se CWIP: cwip_asset_id, cwip_accumulation_id.","regras":"JE deve existir e status=='draft'. Revalida linhas; chama validate_gl_entries (is_opening se entry_type=='opening') e insert_gl_entries (allow_cwip se cwip_asset_id). Erros de GL/CWIP abortam (err). Para CWIP: exatamente uma conta capital_work_in_progress debitada, senão erro.","efeitos":"INSERT em gl_entry (via insert_gl_entries); se CWIP, registra accumulation (record_cwip_accumulation); UPDATE journal_entry.status='submitted'; grava audit_log; commit (transação única).","precondicoes":"JE existente em 'draft'; contas/cost centers válidos para postagem; se CWIP, asset under_construction e leg de CWIP presente."},{"nome":"cancel-journal-entry","objetivo":"Cancela um lançamento submetido, revertendo suas entradas no razão e marcando status 'cancelled'.","entradas":"--journal-entry-id (obrigatório).","saidas":"status='cancelled', journal_entry_id, reversed=true.","regras":"JE deve existir e status=='submitted'. Reverte via reverse_gl_entries; se cwip_asset_id, desfaz accumulations (reverse_cwip_accumulations). Falha de reversão aborta.","efeitos":"INSERT de entradas reversas em gl_entry (reverse_gl_entries); se CWIP, desfaz cwip accumulation/carrying value; UPDATE journal_entry.status='cancelled'; grava audit_log; commit.","precondicoes":"JE existente em status 'submitted' com gl_entries postadas."}]},{"group":"Retificação","objetivo":"Corrigir um lançamento submetido cancelando o original e gerando um novo rascunho vinculado.","acoes":[{"nome":"amend-journal-entry","objetivo":"Retifica um lançamento submetido: cancela o original e cria um novo rascunho ligado (amended_from).","entradas":"--journal-entry-id (obrigatório); opcionais --lines (novas linhas; se ausente copia as originais), --posting-date (default data do original), --remark (default remark do original).","saidas":"status='created', original_id, new_journal_entry_id, new_naming_series.","regras":"JE deve existir e status=='submitted'. Reverte GL do original e marca-o status='amended'; valida as linhas do novo JE por _validate_lines. Novo JE herda entry_type e company do original, status 'draft', amended_from=original.","efeitos":"reverse_gl_entries (entradas reversas em gl_entry); UPDATE original.status='amended'; INSERT novo journal_entry (draft, amended_from) + journal_entry_line; grava audit_log; commit.","precondicoes":"JE existente em status 'submitted'."}]},{"group":"Exclusão/duplicação","objetivo":"Excluir rascunhos definitivamente ou duplicar um lançamento existente como novo rascunho.","acoes":[{"nome":"delete-journal-entry","objetivo":"Exclui definitivamente um lançamento em rascunho (cabeçalho e linhas).","entradas":"--journal-entry-id (obrigatório).","saidas":"status='deleted', deleted=true.","regras":"JE deve existir e status=='draft' (senão erro com sugestão de cancelar). Apaga linhas antes do cabeçalho (FK).","efeitos":"DELETE em journal_entry_line e journal_entry; grava audit_log (old_values naming_series); commit.","precondicoes":"JE existente em status 'draft'."},{"nome":"duplicate-journal-entry","objetivo":"Duplica um lançamento (qualquer status) como um novo rascunho, copiando todas as linhas.","entradas":"--journal-entry-id (obrigatório); --posting-date (opcional, default data atual UTC).","saidas":"status='created', new_journal_entry_id, naming_series.","regras":"JE de origem deve existir; copia account_id/debit/credit/party/cost_center/project/remark das linhas e revalida por _validate_lines. Novo JE herda entry_type e company, status 'draft', remark do original.","efeitos":"INSERT novo journal_entry (draft) + journal_entry_line; grava audit_log; commit. Sem gl_entry.","precondicoes":"JE de origem existente."}]},{"group":"Intercompany","objetivo":"Gerar lançamentos pareados entre duas empresas com contas intercompany de receber/pagar.","acoes":[{"nome":"create-intercompany-je","objetivo":"Cria dois lançamentos pareados entre empresa origem e destino (DR Intercompany Receivable/CR Revenue e DR Expense/CR Intercompany Payable).","entradas":"--source-company-id (obrigatório); --target-company-id (obrigatório); --amount (obrigatório, >0); --posting-date (obrigatório); --description (opcional, default 'Intercompany transaction').","saidas":"source_je_id, source_naming, target_je_id, target_naming, amount, description.","regras":"Origem != destino; amount>0; ambas empresas existem e mesma default_currency (senão erro v2). Cria/reaproveita contas Intercompany Receivable (asset) e Payable (liability); exige conta revenue na origem e expense/cogs no destino; usa cost center não-grupo se houver. Ambos JEs entry_type='inter_company', status 'draft', com cross-reference no remark.","efeitos":"Pode INSERT em account (contas intercompany ausentes); INSERT 2x journal_entry (draft) e respectivas journal_entry_line; UPDATE remark com referência cruzada; grava audit_log; commit. Sem gl_entry (ficam em rascunho).","precondicoes":"Duas empresas distintas, existentes, mesma moeda; origem com conta de receita e destino com conta de despesa/CMV não-grupo."}]},{"group":"Modelos recorrentes","objetivo":"Criar e alterar modelos de lançamentos recorrentes que servem de base para geração automática.","acoes":[{"nome":"add-recurring-template","objetivo":"Cria um modelo de lançamento recorrente com frequência, vigência e linhas.","entradas":"--company-id (obrigatório); --template-name (obrigatório); --start-date (obrigatório); --lines JSON (obrigatório); --frequency (default 'monthly'); --entry-type (default 'journal'); --end-date (opcional); --auto-submit (flag, default off); --remark (opcional).","saidas":"status='created', template_id, naming_series, next_run_date (=start_date).","regras":"frequency em VALID_FREQUENCIES; entry_type em VALID_ENTRY_TYPES; lines validadas por _validate_lines e contas existentes; status inicial 'active', next_run_date=start_date, lines armazenadas como JSON.","efeitos":"INSERT em recurring_journal_template (status='active'); grava audit_log; commit. Não gera journal_entry nem gl_entry.","precondicoes":"Empresa existente; contas das linhas existentes."},{"nome":"update-recurring-template","objetivo":"Atualiza um modelo recorrente (nome, frequência, vigência, tipo, remark, auto_submit, linhas e/ou status).","entradas":"--template-id (obrigatório); opcionais --template-name, --frequency, --end-date, --entry-type, --remark, --auto-submit, --lines, --template-status (apenas 'active'/'paused').","saidas":"status='updated', template_id, updated_fields.","regras":"Template deve existir e status != 'completed'. frequency/entry_type validados; lines revalidadas e contas verificadas; template_status só pode ser 'active' ou 'paused'; erro 'No fields to update' se nada informado.","efeitos":"UPDATE em recurring_journal_template (campos informados + updated_at); grava audit_log; commit.","precondicoes":"Template existente não 'completed'."}]},{"group":"Consulta de modelos","objetivo":"Listar e detalhar modelos de lançamentos recorrentes (somente leitura).","acoes":[{"nome":"list-recurring-templates","objetivo":"Lista os modelos recorrentes de uma empresa com paginação.","entradas":"company resolvido por --company-id ou --company (obrigatório); --status (filtro opcional); --limit (default 20), --offset (default 0).","saidas":"templates[] (id, naming_series, name, frequency, start_date, end_date, next_run_date, last_generated_date, entry_type, auto_submit, remark, status), total_count, limit, offset, has_more.","regras":"Filtro obrigatório por company_id; filtro opcional por status; ordenado por next_run_date asc.","efeitos":"nenhum (leitura).","precondicoes":"Empresa identificável por id ou nome."},{"nome":"get-recurring-template","objetivo":"Retorna um modelo recorrente com todos os campos, incluindo as linhas parseadas.","entradas":"--template-id (obrigatório).","saidas":"Todos os campos do template (row_to_dict), com 'lines' convertido de JSON para array quando possível.","regras":"Template deve existir (senão erro 'not found'); tenta json.loads em lines (ignora se falhar).","efeitos":"nenhum (leitura).","precondicoes":"Template existente."}]},{"group":"Processamento de recorrências","objetivo":"Gerar lançamentos a partir dos modelos recorrentes vencidos e avançar o calendário de execução.","acoes":[{"nome":"process-recurring","objetivo":"Gera lançamentos de todos os modelos ativos vencidos (next_run_date <= data) e avança suas datas de execução.","entradas":"--company-id (obrigatório); --as-of-date (opcional, default data atual UTC).","saidas":"generated (contagem), results[] (template_id, template_name, journal_entry_id, naming_series, posting_date, je_status, next_run_date, template_status).","regras":"Idempotente: só modelos status='active' com next_run_date<=as_of_date. Cria JE 'draft' com posting_date=next_run_date; se auto_submit, valida e posta GL e marca 'submitted' (falha mantém 'draft'). Avança next_run_date por _advance_date; se passar de end_date marca template 'completed'.","efeitos":"INSERT journal_entry (draft) + journal_entry_line por modelo; se auto_submit, INSERT em gl_entry e UPDATE je.status='submitted'; UPDATE recurring_journal_template (next_run_date, last_generated_date, status); grava audit_log; commit.","precondicoes":"--company-id informado; modelos recorrentes ativos com next_run_date vencido."}]},{"group":"Exclusão de modelos","objetivo":"Remover modelos de lançamentos recorrentes.","acoes":[{"nome":"delete-recurring-template","objetivo":"Exclui um modelo de lançamento recorrente.","entradas":"--template-id (obrigatório).","saidas":"status='deleted', deleted=true.","regras":"Template deve existir (senão erro 'not found'). Apesar do docstring mencionar soft delete, o código executa DELETE físico da linha.","efeitos":"DELETE em recurring_journal_template; grava audit_log; commit.","precondicoes":"Template existente."}]},{"group":"Status","objetivo":"Resumir contagens de lançamentos e de modelos recorrentes por status para uma empresa.","acoes":[{"nome":"status","objetivo":"Mostra a contagem de lançamentos por status e de modelos recorrentes por status para a empresa.","entradas":"company resolvido por --company-id ou --company (obrigatório).","saidas":"total, draft, submitted, cancelled, amended e recurring_templates (active, paused, completed).","regras":"Filtro obrigatório por company_id (resolve_company_id); agrega journal_entry e recurring_journal_template por status via GROUP BY.","efeitos":"nenhum (leitura).","precondicoes":"Empresa identificável por id ou nome."}]}]},"selling":{"module":"selling","display":"Vendas (Order-to-Cash)","functionalities":[{"group":"Clientes","objetivo":"Cadastrar, consultar, listar e importar clientes da empresa, incluindo limite de crédito.","acoes":[{"nome":"add-customer","objetivo":"Cria um registro de cliente no status 'active'.","entradas":"--name (obrigatório); --company-id (obrigatório); --customer-type (default 'company', um de company|individual); --customer-group; --payment-terms-id; --credit-limit (default 0); --tax-id; --exempt-from-sales-tax; --primary-address; --primary-contact; --email; --phone; --custom-fields (JSON).","saidas":"customer_id, name, customer_type (mais quaisquer custom fields mesclados).","regras":"Valida existência de company_id; valida customer_type contra company|individual; valida payment_terms_id se informado; credit_limit normalizado para currency; falha de IntegrityError -> erro de duplicidade; rollback se erro de custom field.","efeitos":"INSERT em customer (status='active'); persiste custom fields; audit_log via audit(); commit.","precondicoes":"Empresa existente; payment_terms existente se informado."},{"nome":"update-customer","objetivo":"Atualiza campos de um cliente existente (resolvido por id ou name).","entradas":"--customer-id (obrigatório, aceita id ou name); campos opcionais: --name, --credit-limit, --payment-terms-id, --customer-group, --customer-type, --email, --phone.","saidas":"customer_id, updated_fields (lista).","regras":"Cliente deve existir; valida customer_type se informado; erro 'No fields to update' se nada fornecido; seta updated_at.","efeitos":"UPDATE dynamic em customer; audit_log; commit.","precondicoes":"Cliente existente."},{"nome":"get-customer","objetivo":"Retorna um cliente com resumo de faturas em aberto (outstanding).","entradas":"--customer-id (obrigatório, aceita id ou name).","saidas":"Todos os campos do cliente + total_outstanding + outstanding_invoice_count (mais custom fields mesclados).","regras":"Cliente deve existir; total_outstanding soma outstanding_amount de sales_invoice em status submitted/overdue/partially_paid com saldo>0.","efeitos":"nenhum (leitura).","precondicoes":"Cliente existente."},{"nome":"list-customers","objetivo":"Lista clientes com filtros e paginação.","entradas":"--company-id; --customer-group; --search (em name/tax_id); --limit (default 20); --offset (default 0).","saidas":"customers (lista), total_count, limit, offset, has_more.","regras":"Filtros opcionais combinados via AND; ordena por name; conta total separadamente.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"import-customers","objetivo":"Importa clientes em lote a partir de um arquivo CSV.","entradas":"--csv-path (obrigatório, deve terminar em .csv); --company-id (obrigatório). Colunas CSV: name, customer_type, territory, default_currency, email, phone, tax_id.","saidas":"imported, skipped, total_rows.","regras":"Valida que path é arquivo .csv real; valida CSV via validate_csv; pula linhas com name duplicado na empresa; gera naming_series para cada novo cliente.","efeitos":"INSERT em customer por linha nova (com naming_series); commit. Não grava audit_log.","precondicoes":"Arquivo CSV válido existente; empresa existente."}]},{"group":"Cotações","objetivo":"Criar, editar, consultar, listar, submeter e converter cotações em pedidos de venda.","acoes":[{"nome":"add-quotation","objetivo":"Cria uma cotação no status 'draft' com itens e impostos calculados.","entradas":"--customer-id (obrigatório); --posting-date (obrigatório); --items (obrigatório, JSON array); --company-id (obrigatório); --valid-till; --tax-template-id.","saidas":"quotation_id, total_amount, tax_amount, grand_total.","regras":"Cliente deve estar 'active'; empresa deve existir; cada item exige item_id, qty>0; aplica discount_percentage por linha; calcula imposto via tax template; status inicial 'draft' (sem naming_series).","efeitos":"INSERT em quotation (status='draft') e quotation_item; audit_log; commit.","precondicoes":"Cliente ativo e empresa existentes; itens válidos."},{"nome":"update-quotation","objetivo":"Atualiza valid_until e/ou itens de uma cotação em rascunho.","entradas":"--quotation-id (obrigatório); --valid-till; --items (JSON).","saidas":"quotation_id, updated_fields.","regras":"Cotação deve existir e estar 'draft'; se --items, deleta itens antigos e reinsere recalculando total/tax/grand_total; erro se nada a atualizar.","efeitos":"UPDATE quotation; DELETE+INSERT quotation_item quando itens informados; audit_log; commit.","precondicoes":"Cotação em status 'draft'."},{"nome":"get-quotation","objetivo":"Retorna uma cotação com suas linhas de item.","entradas":"--quotation-id (obrigatório).","saidas":"Campos da quotation + items (lista com item_name).","regras":"Cotação deve existir.","efeitos":"nenhum (leitura).","precondicoes":"Cotação existente."},{"nome":"list-quotations","objetivo":"Lista cotações com filtros e paginação.","entradas":"--company-id; --customer-id; --status; --from-date; --to-date; --limit (default 20); --offset (default 0).","saidas":"quotations (lista, com customer_name), total_count, limit, offset, has_more.","regras":"Filtros combinados por AND sobre quotation_date; ordena por quotation_date e created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"submit-quotation","objetivo":"Submete uma cotação: draft -> open, gerando naming_series.","entradas":"--quotation-id (obrigatório).","saidas":"quotation_id, naming_series, status ('open').","regras":"Cotação deve estar 'draft'; gera naming_series via get_next_name; sem postagens contábeis.","efeitos":"UPDATE quotation (status='open', naming_series); audit_log; commit.","precondicoes":"Cotação em status 'draft'."},{"nome":"convert-quotation-to-so","objetivo":"Cria um pedido de venda (draft) a partir de uma cotação e marca-a como 'ordered'.","entradas":"--quotation-id (obrigatório); --delivery-date.","saidas":"quotation_id, sales_order_id, status ('ordered').","regras":"Cotação deve estar 'open' ou 'draft' e ter itens; copia itens para sales_order_item; SO criado em 'draft'; atualiza quotation.status='ordered' e converted_to.","efeitos":"INSERT sales_order (status='draft') e sales_order_item; UPDATE quotation (status='ordered', converted_to); audit_log; commit.","precondicoes":"Cotação em 'open'/'draft' com itens."}]},{"group":"Pedidos de Venda","objetivo":"Criar, editar, consultar, listar, confirmar, cancelar e fechar pedidos de venda com checagem de limite de crédito.","acoes":[{"nome":"add-sales-order","objetivo":"Cria um pedido de venda no status 'draft' (com aplicação de pricing rules).","entradas":"--customer-id (obrigatório); --posting-date (obrigatório, vira order_date); --items (obrigatório, JSON); --company-id (obrigatório); --delivery-date; --tax-template-id.","saidas":"sales_order_id, total_amount, tax_amount, grand_total.","regras":"Cliente deve estar 'active'; empresa deve existir; aplica pricing rules (apply_pricing=True) por item; qty>0; calcula imposto; status inicial 'draft'.","efeitos":"INSERT sales_order (status='draft') e sales_order_item; audit_log; commit.","precondicoes":"Cliente ativo e empresa existentes."},{"nome":"update-sales-order","objetivo":"Atualiza delivery_date e/ou itens de um pedido em rascunho.","entradas":"--sales-order-id (obrigatório); --delivery-date; --items (JSON).","saidas":"sales_order_id, updated_fields.","regras":"SO deve existir e estar 'draft'; se --items, deleta e reinsere itens (com pricing) recalculando totais; erro se nada a atualizar.","efeitos":"UPDATE sales_order; DELETE+INSERT sales_order_item quando itens informados; audit_log; commit.","precondicoes":"Pedido em status 'draft'."},{"nome":"get-sales-order","objetivo":"Retorna um pedido com itens e resumo de entregas/faturas vinculadas.","entradas":"--sales-order-id (obrigatório).","saidas":"Campos do SO + items + delivery_notes (não-cancelados) + sales_invoices (não-cancelados).","regras":"SO deve existir.","efeitos":"nenhum (leitura).","precondicoes":"Pedido existente."},{"nome":"list-sales-orders","objetivo":"Lista pedidos de venda com filtros e paginação.","entradas":"--company-id; --customer-id; --status; --from-date; --to-date; --limit (default 20); --offset (default 0).","saidas":"sales_orders (lista, com customer_name, per_delivered, per_invoiced), total_count, limit, offset, has_more.","regras":"Filtros por AND sobre order_date; ordena por order_date/created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"submit-sales-order","objetivo":"Confirma um pedido (draft -> confirmed) com checagem de limite de crédito.","entradas":"--sales-order-id (obrigatório).","saidas":"sales_order_id, naming_series, status ('confirmed').","regras":"SO deve estar 'draft'; cliente deve estar 'active'; itens com qty>0 e rate>0; se credit_limit>0, exposição (outstanding AR + pedidos confirmed não-faturados + este grand_total) não pode exceder o limite, senão erro; gera naming_series.","efeitos":"UPDATE sales_order (status='confirmed', naming_series); audit_log; commit. Sem GL/SLE/PLE.","precondicoes":"Pedido em 'draft' com itens válidos; cliente ativo."},{"nome":"cancel-sales-order","objetivo":"Cancela um pedido somente se não houver entregas/faturas ativas vinculadas.","entradas":"--sales-order-id (obrigatório).","saidas":"sales_order_id, status ('cancelled').","regras":"Erro se já cancelado; erro se houver delivery_note ou sales_invoice não-cancelados vinculados.","efeitos":"UPDATE sales_order (status='cancelled'); audit_log; commit.","precondicoes":"Pedido sem documentos-filhos ativos."},{"nome":"close-sales-order","objetivo":"Fecha um pedido parcialmente atendido, impedindo novas DNs/faturas mas preservando filhos existentes.","entradas":"--sales-order-id (obrigatório); --reason; --closed-by.","saidas":"sales_order_id, doc_status ('closed'), close_reason, closed_by.","regras":"Erro se status for draft/cancelled/closed; grava motivo e responsável.","efeitos":"UPDATE sales_order (status='closed', close_reason, closed_by); audit_log; commit.","precondicoes":"Pedido em status que não seja draft/cancelled/closed."}]},{"group":"Emendas","objetivo":"Emendar pedidos de venda criando uma nova versão vinculada e rastrear a cadeia de emendas.","acoes":[{"nome":"amend-sales-order","objetivo":"Cancela o pedido original (sem filhos ativos) e cria um novo SO 'draft' vinculado via amended_from.","entradas":"--sales-order-id (obrigatório); --items (JSON opcional; se omitido, copia itens do original).","saidas":"new_sales_order_id, amended_from, original_status ('cancelled'), total_amount, tax_amount, grand_total.","regras":"SO não pode ser draft/cancelled/closed; bloqueia se houver delivery_note ou sales_invoice ativos; recalcula totais (com pricing) e impostos; novo SO em 'draft'.","efeitos":"UPDATE sales_order original (status='cancelled'); INSERT novo sales_order (amended_from) e sales_order_item; dois audit_log (cancelamento e criação); commit.","precondicoes":"Pedido amendável sem documentos-filhos ativos."},{"nome":"get-amendment-history","objetivo":"Rastreia a cadeia completa de emendas de um pedido (ancestrais e descendentes).","entradas":"--sales-order-id (obrigatório).","saidas":"sales_order_id, amendment_chain (lista de {sales_order_id, status, amended_from, grand_total}), chain_length.","regras":"SO deve existir; caminha para trás via amended_from até a raiz e para frente via descendentes.","efeitos":"nenhum (leitura).","precondicoes":"Pedido existente."}]},{"group":"Notas de Entrega","objetivo":"Criar, consultar, listar, submeter (com postagens de estoque/COGS) e cancelar notas de entrega.","acoes":[{"nome":"create-delivery-note","objetivo":"Cria uma nota de entrega (draft) a partir de um pedido de venda, total ou parcial.","entradas":"--sales-order-id (obrigatório); --posting-date (default hoje); --items (JSON para entrega parcial; omitido = entrega tudo pendente); --warehouse-id (override para todos os itens).","saidas":"delivery_note_id, sales_order_id, total_qty, item_count.","regras":"SO deve estar 'confirmed' ou 'partially_delivered' (erro se 'closed'); em parcial, qty>0 e <= remaining por item; erro se nada a entregar; DN criada em 'draft'.","efeitos":"INSERT delivery_note (status='draft') e delivery_note_item; audit_log; commit. Sem postagens contábeis ainda.","precondicoes":"Pedido confirmado/parcialmente entregue com saldo a entregar."},{"nome":"get-delivery-note","objetivo":"Retorna uma nota de entrega com seus itens.","entradas":"--delivery-note-id (obrigatório).","saidas":"Campos da DN + items (com item_name, item_code).","regras":"DN deve existir.","efeitos":"nenhum (leitura).","precondicoes":"Nota de entrega existente."},{"nome":"list-delivery-notes","objetivo":"Lista notas de entrega com filtros e paginação.","entradas":"--company-id; --customer-id; --status; --from-date; --to-date; --limit (default 20); --offset (default 0).","saidas":"delivery_notes (lista, com customer_name, total_qty), total_count, limit, offset, has_more.","regras":"Filtros por AND sobre posting_date; ordena por posting_date/created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"submit-delivery-note","objetivo":"Submete uma DN: cria SLE (saída de estoque) e GL de COGS, atualizando o SO.","entradas":"--delivery-note-id (obrigatório).","saidas":"delivery_note_id, naming_series, status ('submitted'), sle_entries_created, gl_entries_created.","regras":"DN deve estar 'draft'; SO vinculado não pode estar cancelado; itens de serviço são pulados; resolve warehouse (item/default da empresa); só permite despachar de warehouse tipo 'stores'; gera SLE negativos e GL de COGS via lib; atualiza delivered_qty e status do SO.","efeitos":"INSERT stock_ledger_entry (negativos) e gl_entry (COGS); UPDATE serial_number p/ 'delivered'; UPDATE delivery_note (status='submitted', naming_series); UPDATE sales_order_item.delivered_qty e recálculo de per_delivered/status do SO; audit_log; commit.","precondicoes":"DN em 'draft' com itens; warehouse 'stores' válido; SO não cancelado."},{"nome":"cancel-delivery-note","objetivo":"Cancela uma DN submetida: reverte SLE + GL e reverte delivered_qty do SO.","entradas":"--delivery-note-id (obrigatório).","saidas":"delivery_note_id, status ('cancelled'), sle_reversals, gl_reversals.","regras":"DN deve estar 'submitted'; erro se houver faturas ativas referenciando a DN; reverte SLE e GL via lib; recalcula status do SO (pode voltar a 'confirmed').","efeitos":"INSERT entradas reversoras em stock_ledger_entry e gl_entry; UPDATE delivery_note (status='cancelled'); decrementa sales_order_item.delivered_qty (mínimo 0) e recalcula status do SO; audit_log; commit.","precondicoes":"DN 'submitted' sem faturas ativas vinculadas."}]},{"group":"Faturas de Venda","objetivo":"Criar (de SO/DN/avulsa), editar, consultar, listar, submeter (com GL/PLE/SLE), cancelar e atualizar saldo de faturas de venda.","acoes":[{"nome":"create-sales-invoice","objetivo":"Cria uma fatura de venda (draft) a partir de SO, DN ou avulsa.","entradas":"--sales-order-id OU --delivery-note-id OU (avulsa: --customer-id + --items + --company-id); --posting-date (default hoje); --tax-template-id; --due-date; --payment-terms-id.","saidas":"sales_invoice_id, total_amount, tax_amount, grand_total, update_stock.","regras":"De SO: status valido (confirmed/partially_delivered/fully_delivered/partially_invoiced), só itens não-faturados; se SO tem DN submetida, update_stock=0. De DN: DN deve estar 'submitted', update_stock=0. Avulsa: cliente ativo, itens válidos, update_stock=1 (default). Calcula due_date por payment terms ou +30 dias.","efeitos":"INSERT sales_invoice (status='draft', outstanding=grand_total) e sales_invoice_item; audit_log; commit. Sem GL/PLE ainda.","precondicoes":"SO/DN em status válido, ou cliente ativo para avulsa."},{"nome":"update-sales-invoice","objetivo":"Atualiza due_date e/ou itens de uma fatura em rascunho.","entradas":"--sales-invoice-id (obrigatório); --due-date; --items (JSON).","saidas":"sales_invoice_id, updated_fields.","regras":"Fatura deve existir e estar 'draft'; se --items, deleta e reinsere itens recalculando total/tax/grand_total/outstanding; erro se nada a atualizar.","efeitos":"UPDATE sales_invoice; DELETE+INSERT sales_invoice_item quando itens informados; audit_log; commit.","precondicoes":"Fatura em status 'draft'."},{"nome":"get-sales-invoice","objetivo":"Retorna uma fatura com itens e lançamentos de pagamento (PLE).","entradas":"--sales-invoice-id (obrigatório).","saidas":"Campos da fatura + items + payments (PLE de tipo sales_invoice/credit_note).","regras":"Fatura deve existir.","efeitos":"nenhum (leitura).","precondicoes":"Fatura existente."},{"nome":"list-sales-invoices","objetivo":"Lista faturas de venda com filtros e paginação.","entradas":"--company-id; --customer-id; --status; --from-date; --to-date; --limit (default 20); --offset (default 0).","saidas":"sales_invoices (lista, com customer_name, outstanding_amount, is_return), total_count, limit, offset, has_more.","regras":"Filtros por AND sobre posting_date; ordena por posting_date/created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"submit-sales-invoice","objetivo":"Submete uma fatura: posta GL de receita + PLE (e opcionalmente SLE/COGS se update_stock).","entradas":"--sales-invoice-id (obrigatório).","saidas":"sales_invoice_id, naming_series, status ('submitted'), gl_entries_created, sle_entries_created, update_stock.","regras":"Fatura deve estar 'draft'; cliente deve estar 'active'; aplica política de crédito (_enforce_credit_policy: bloqueia suspended/on_hold e excesso de credit_limit); DR Receivable / CR Receita / CR Imposto (invertido para credit_note); se update_stock cria SLE e GL de COGS; gera naming_series; atualiza invoiced_qty/status do SO.","efeitos":"INSERT gl_entry (receita + COGS), payment_ledger_entry, e stock_ledger_entry se update_stock; UPDATE sales_invoice (status='submitted', naming_series); UPDATE sales_order_item.invoiced_qty e status do SO; audit_log; commit.","precondicoes":"Fatura em 'draft' com itens; cliente ativo dentro da política de crédito; contas receivable/income configuradas."},{"nome":"cancel-sales-invoice","objetivo":"Cancela uma fatura: reverte GL + PLE (e SLE se update_stock).","entradas":"--sales-invoice-id (obrigatório).","saidas":"sales_invoice_id, status ('cancelled'), gl_reversals, sle_reversals.","regras":"Fatura deve estar 'submitted', 'overdue' ou 'partially_paid'; reverte GL (incl. COGS) e SLE via lib; marca PLE como delinked; zera outstanding; reverte invoiced_qty do SO.","efeitos":"INSERT entradas reversoras em gl_entry e stock_ledger_entry; UPDATE payment_ledger_entry (delinked=1); UPDATE sales_invoice (status='cancelled', outstanding=0); decrementa sales_order_item.invoiced_qty e recalcula status do SO; audit_log; commit.","precondicoes":"Fatura em status submitted/overdue/partially_paid."},{"nome":"update-invoice-outstanding","objetivo":"Atualiza o saldo em aberto de uma fatura quando um pagamento é alocado (chamado por glue-payments).","entradas":"--sales-invoice-id (obrigatório); --amount (obrigatório, >0).","saidas":"sales_invoice_id, outstanding_amount, status.","regras":"Fatura deve estar submitted/overdue/partially_paid; amount>0; delega cálculo/escrita à lib payment_clearing.apply_payment_to_document (rejeita over-payment).","efeitos":"UPDATE sales_invoice (outstanding_amount e status via lib compartilhada); audit_log; commit.","precondicoes":"Fatura clearable (submitted/overdue/partially_paid)."}]},{"group":"Notas de Crédito/Estorno","objetivo":"Criar e listar notas de crédito (faturas de devolução com valores negativos) contra faturas originais.","acoes":[{"nome":"create-credit-note","objetivo":"Cria uma nota de crédito (fatura is_return=1, valores negativos) contra uma fatura original.","entradas":"--against-invoice-id (obrigatório); --items (obrigatório, JSON); --posting-date (default hoje); --reason.","saidas":"credit_note_id, against_invoice_id, grand_total, is_return (True).","regras":"Fatura original deve estar submitted/overdue/partially_paid/paid; cada item deve existir na fatura original e qty de retorno <= qty original; quantidades/valores armazenados negativos; nota de crédito criada em 'draft' com return_against.","efeitos":"INSERT sales_invoice (is_return=1, status='draft', return_against) e sales_invoice_item (negativos); audit_log; commit. Postagens contábeis só no submit-sales-invoice.","precondicoes":"Fatura original em status válido com itens correspondentes."},{"nome":"list-credit-notes","objetivo":"Lista notas de crédito (faturas com is_return=1) com filtros e paginação.","entradas":"--company-id; --customer-id; --status; --from-date; --to-date; --limit (default 20); --offset (default 0).","saidas":"credit_notes (lista, com customer_name e return_against_name), total_count, limit, offset, has_more.","regras":"Sempre filtra is_return=1; demais filtros por AND sobre posting_date.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Crédito e Cobrança (Dunning)","objetivo":"Gerir limite/status de crédito do cliente e executar ciclos de cobrança escalonada (dunning).","acoes":[{"nome":"check-credit-limit","objetivo":"Calcula o crédito disponível de um cliente (somente leitura).","entradas":"--customer-id (obrigatório).","saidas":"customer_id, name, credit_limit, credit_status, outstanding_ar, available_credit, limit_enforced.","regras":"Cliente deve existir; outstanding_ar soma outstanding_amount de faturas submitted is_return=0; available_credit = limit - outstanding se limit>0, senão None.","efeitos":"nenhum (leitura).","precondicoes":"Cliente existente."},{"nome":"place-customer-on-hold","objetivo":"Define o credit_status do cliente para on_hold/suspended (ou active para liberar).","entradas":"--customer-id (obrigatório); --credit-status (default 'on_hold', um de active|on_hold|suspended); --reason.","saidas":"customer_id, credit_status (novo), previous.","regras":"Cliente deve existir; valida credit_status; preserva valor anterior para auditoria.","efeitos":"UPDATE customer (credit_status, updated_at); commit; audit_log com old/new values e descrição (reason).","precondicoes":"Cliente existente."},{"nome":"add-dunning-level","objetivo":"Configura um nível de escalonamento de cobrança (ação a tomar em N dias de atraso).","entradas":"--company-id (obrigatório); --level (obrigatório, inteiro 1-10); --days-overdue (obrigatório, >=0); --dunning-action (obrigatório, um de email|hold|call|suspend); --template-id; --description.","saidas":"id, company_id, level, days_overdue, action.","regras":"Valida faixa de level e days_overdue; valida dunning-action; IntegrityError -> nível duplicado para a empresa.","efeitos":"INSERT dunning_level; commit; audit_log.","precondicoes":"Empresa existente."},{"nome":"run-dunning-cycle","objetivo":"Encontra faturas vencidas, casa cada cliente ao maior nível aplicável e executa a ação configurada (incl. enfileirar e-mail).","entradas":"--company-id (obrigatório); --run-date (default hoje); --db-path (para subprocess de e-mail).","saidas":"run_date, company_id, customers_processed, runs_created, actions (contagem por tipo), emails (sent/skipped), run_ids.","regras":"Sem níveis configurados retorna mensagem; busca faturas submitted is_return=0 com outstanding>0 e due_date<hoje; maior nível por cliente vence; idempotente por (cliente, nível, dia) - pula duplicatas; 'hold'/'suspend' alteram credit_status; 'call' apenas registra; 'email' enfileira após o commit via ACTION send-email do glue-alerts; e-mail/template ausente é skip-with-note.","efeitos":"INSERT dunning_run (status='completed'); UPDATE customer.credit_status para hold/suspend; subprocess para glue-alerts send-email (escreve outbox no módulo de alertas); UPDATE dunning_run.generated_email_id/notes; audit não emitido aqui; dois commits (run e pós-e-mail).","precondicoes":"Empresa com níveis de dunning configurados; glue-alerts disponível para envios de e-mail."},{"nome":"list-dunning-runs","objetivo":"Lista o histórico de execuções de dunning, opcionalmente filtrado por cliente/empresa.","entradas":"--customer-id; --company-id; --limit.","saidas":"runs (lista de dunning_run).","regras":"Filtros opcionais combinados; ordena por run_date e created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Parceiros de Venda","objetivo":"Cadastrar e listar parceiros de venda com taxa de comissão.","acoes":[{"nome":"add-sales-partner","objetivo":"Cria um parceiro de venda com taxa de comissão.","entradas":"--name (obrigatório); --commission-rate (obrigatório).","saidas":"sales_partner_id, name, commission_rate.","regras":"Nome e commission-rate obrigatórios; rate normalizado para currency; IntegrityError -> erro de duplicidade.","efeitos":"INSERT sales_partner; audit_log; commit.","precondicoes":"Nenhuma."},{"nome":"list-sales-partners","objetivo":"Lista parceiros de venda com paginação.","entradas":"--limit (default 20); --offset (default 0).","saidas":"sales_partners (lista), total_count, limit, offset, has_more.","regras":"Ordena por name; conta total separadamente.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Faturas Recorrentes","objetivo":"Criar, editar, listar templates de fatura recorrente e gerar automaticamente faturas das templates vencidas.","acoes":[{"nome":"add-recurring-template","objetivo":"Cria uma template de fatura recorrente no status 'draft'.","entradas":"--customer-id (obrigatório); --items (obrigatório, JSON); --frequency (obrigatório, um de weekly|monthly|quarterly|semi_annually|annually); --start-date (obrigatório); --company-id (obrigatório); --end-date; --tax-template-id; --payment-terms-id.","saidas":"template_id, frequency, start_date, next_invoice_date (=start_date).","regras":"Valida frequency; cliente deve estar 'active'; empresa deve existir; itens não-vazios com item_id; next_invoice_date inicial = start_date.","efeitos":"INSERT recurring_invoice_template (status='draft') e recurring_invoice_template_item; audit_log; commit.","precondicoes":"Cliente ativo e empresa existentes."},{"nome":"update-recurring-template","objetivo":"Atualiza frequency, status e/ou itens de uma template recorrente.","entradas":"--template-id (obrigatório); --frequency; --template-status (active|paused|cancelled via --status? na verdade dest template_status); --items (JSON).","saidas":"template_id, updated_fields.","regras":"Template deve existir; valida frequency e template_status; se --items deleta e reinsere; erro se nada a atualizar.","efeitos":"UPDATE recurring_invoice_template; DELETE+INSERT recurring_invoice_template_item quando itens informados; audit_log; commit.","precondicoes":"Template existente."},{"nome":"list-recurring-templates","objetivo":"Lista templates de fatura recorrente com filtros e paginação.","entradas":"--company-id; --customer-id; --template-status; --limit (default 20); --offset (default 0).","saidas":"recurring_templates (lista), total_count, limit, offset, has_more.","regras":"Filtros por AND; ordena por next_invoice_date.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"generate-recurring-invoices","objetivo":"Cron: gera e auto-submete faturas das templates ativas vencidas até a data de referência.","entradas":"--company-id (obrigatório); --as-of-date (default hoje).","saidas":"invoices_generated (contagem), templates_processed, templates_completed, invoices (lista), errors (lista).","regras":"Seleciona templates status='active', next_invoice_date<=as_of_date e não expiradas; por template cria fatura draft, posta GL+PLE, gera naming, marca submitted; avança next_invoice_date conforme frequency; marca 'completed' se passar end_date; erros por template não abortam o lote (rollback isolado).","efeitos":"INSERT sales_invoice (status='submitted', update_stock=0) e sales_invoice_item; INSERT gl_entry (receita+imposto) e payment_ledger_entry; UPDATE recurring_invoice_template (last/next_invoice_date, possivelmente status='completed'); commit. Não grava audit_log.","precondicoes":"Empresa existente com templates ativos vencidos."}]},{"group":"Blanket Orders","objetivo":"Criar, ativar, consultar, listar acordos-quadro (blanket orders) de venda e gerar pedidos com drawdown contra eles.","acoes":[{"nome":"add-blanket-order","objetivo":"Cria um blanket order de venda (acordo-quadro) no status 'draft'.","entradas":"--customer-id (obrigatório); --items (obrigatório, JSON); --company-id (obrigatório); --valid-from (obrigatório); --valid-to (obrigatório).","saidas":"blanket_order_id, customer_id, total_qty, valid_from, valid_to.","regras":"Cliente deve estar 'active'; empresa deve existir; valid_to deve ser posterior a valid_from; cada item exige qty>0 e rate>0; blanket_order_type='selling'.","efeitos":"INSERT blanket_order (type='selling', status='draft') e blanket_order_item; UPDATE blanket_order.total_qty; audit_log; commit.","precondicoes":"Cliente ativo e empresa existentes."},{"nome":"submit-blanket-order","objetivo":"Ativa um blanket order de venda (draft -> active).","entradas":"--blanket-order-id (obrigatório).","saidas":"blanket_order_id, doc_status ('active').","regras":"Blanket order deve estar 'draft' e ser do tipo 'selling'.","efeitos":"UPDATE blanket_order (status='active'); audit_log; commit.","precondicoes":"Blanket order 'draft' do tipo selling."},{"nome":"get-blanket-order","objetivo":"Retorna um blanket order de venda com seus itens.","entradas":"--blanket-order-id (obrigatório).","saidas":"Campos do blanket_order + items.","regras":"Blanket order deve existir.","efeitos":"nenhum (leitura).","precondicoes":"Blanket order existente."},{"nome":"list-blanket-orders","objetivo":"Lista blanket orders de venda com filtros e paginação.","entradas":"--company-id; --customer-id; --status; --limit (default 20); --offset (default 0).","saidas":"blanket_orders (lista), total_count, limit, offset, has_more.","regras":"Sempre filtra blanket_order_type='selling'; demais filtros por AND; ordena por created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"create-so-from-blanket","objetivo":"Cria um pedido de venda (draft) fazendo drawdown de um blanket order ativo.","entradas":"--blanket-order-id (obrigatório); --items (obrigatório, JSON); --posting-date (default hoje); --delivery-date; --tax-template-id.","saidas":"sales_order_id, blanket_order_id, total_amount, grand_total.","regras":"Blanket deve estar 'active', tipo 'selling' e não expirado; cada item deve estar no blanket e qty<=quantidade remanescente (quantity - ordered_qty); rate do item ou do blanket; SO criado em 'draft'.","efeitos":"INSERT sales_order (status='draft') e sales_order_item; UPDATE blanket_order_item.ordered_qty e blanket_order.ordered_qty; audit_log; commit.","precondicoes":"Blanket order ativo, não expirado, com saldo remanescente."}]},{"group":"Faturamento Intercompany","objetivo":"Mapear contas entre empresas e espelhar/cancelar faturas intercompany (SI no vendedor -> PI no comprador).","acoes":[{"nome":"add-intercompany-account-map","objetivo":"Adiciona um mapeamento de conta da empresa origem para a conta da empresa destino.","entradas":"--company-id (origem, obrigatório); --target-company-id (obrigatório); --source-account-id (obrigatório); --target-account-id (obrigatório).","saidas":"map_id.","regras":"Origem e destino devem ser empresas diferentes e existentes; cada conta deve pertencer à sua empresa; rejeita mapeamento duplicado para o par e conta de origem.","efeitos":"INSERT intercompany_account_map; commit. Não grava audit_log.","precondicoes":"Duas empresas distintas e suas contas existentes."},{"nome":"list-intercompany-account-maps","objetivo":"Lista mapeamentos de contas intercompany para um par de empresas.","entradas":"--company-id (origem, obrigatório); --target-company-id.","saidas":"mappings (lista com nomes das contas origem/destino), total.","regras":"Origem obrigatória; filtra por destino se informado; junta com account para trazer nomes.","efeitos":"nenhum (leitura).","precondicoes":"Empresa de origem existente."},{"nome":"create-intercompany-invoice","objetivo":"Cria uma fatura de compra espelho (draft) na empresa destino a partir de uma fatura de venda.","entradas":"--sales-invoice-id (obrigatório); --target-company-id (obrigatório); --supplier-id (obrigatório, fornecedor na empresa destino).","saidas":"purchase_invoice_id, sales_invoice_id, source_company_id, target_company_id, total_amount, grand_total, items_mirrored.","regras":"SI deve estar submitted/partially_paid/paid/overdue; origem != destino; SI não pode já ser intercompany; supplier deve pertencer à empresa destino; resolve conta de despesa via mapeamento (income origem -> expense destino) ou conta de despesa default.","efeitos":"INSERT purchase_invoice (is_intercompany=1, status='draft', intercompany_reference_id=SI) e purchase_invoice_item; UPDATE sales_invoice (is_intercompany=1, intercompany_reference_id=PI); commit. Não grava audit_log.","precondicoes":"SI submetida não-intercompany; empresa destino e supplier compatíveis existentes."},{"nome":"list-intercompany-invoices","objetivo":"Lista todas as faturas intercompany de uma empresa (como vendedora e compradora).","entradas":"--company-id (obrigatório); --limit (default 20); --offset (default 0).","saidas":"invoices (SI com direction='sales' + PI com direction='purchase'), total.","regras":"Une sales_invoice is_intercompany=1 (como vendedor) e purchase_invoice is_intercompany=1 (como comprador); ordena por posting_date desc.","efeitos":"nenhum (leitura).","precondicoes":"Empresa existente."},{"nome":"cancel-intercompany-invoice","objetivo":"Cancela uma fatura de venda intercompany e cascateia o cancelamento para a fatura de compra espelho.","entradas":"--sales-invoice-id (obrigatório).","saidas":"sales_invoice_id, purchase_invoice_id, si_status, si_gl_reversals, si_sle_reversals, pi_gl_reversals, pi_sle_reversals.","regras":"SI deve ser intercompany (is_intercompany=1); se SI submitted/overdue/partially_paid reverte GL/SLE e delinka PLE; PI espelho submetida é revertida de forma análoga, PI em draft é deletada; status já cancelado é no-op.","efeitos":"INSERT reversões em gl_entry e stock_ledger_entry (SI e PI); UPDATE payment_ledger_entry (delinked=1); UPDATE sales_invoice e purchase_invoice (status='cancelled', outstanding=0) OU DELETE purchase_invoice/itens se draft; commit. Não grava audit_log.","precondicoes":"SI intercompany existente com PI espelho referenciada."}]},{"group":"Drop Ship/Romaneio","objetivo":"Gerar pedidos de compra por drop-ship a partir de itens do SO e gerir romaneios (packing slips) ligados a notas de entrega.","acoes":[{"nome":"create-drop-ship-order","objetivo":"Cria um pedido de compra (draft) a partir dos itens drop-ship de um pedido de venda.","entradas":"--sales-order-id (obrigatório); --supplier-id (obrigatório); --posting-date (default hoje).","saidas":"purchase_order_id, sales_order_id, supplier_id, delivery_address, total_amount, item_count, message.","regras":"SO deve estar 'confirmed' ou 'partially_delivered'; supplier deve existir; usa só itens com is_drop_ship=1 e quantidade remanescente>0; PO usa delivery_address = endereço primário do cliente; PO criado em 'draft'.","efeitos":"INSERT purchase_order (status='draft', delivery_address) e purchase_order_item (vinculados aos itens do SO); audit_log; commit.","precondicoes":"SO confirmado/parcialmente entregue com itens drop-ship pendentes; supplier existente."},{"nome":"add-packing-slip","objetivo":"Cria um romaneio (packing slip) vinculado a uma nota de entrega.","entradas":"--delivery-note-id (obrigatório); --items (obrigatório, JSON: [{delivery_note_item_id, qty_packed}]); --posting-date (default hoje); --notes/--reason.","saidas":"packing_slip_id, delivery_note_id, item_count, message.","regras":"DN deve existir; cada item deve referenciar um delivery_note_item da DN; qty_packed>0; soma de qty_packed (incluindo packings anteriores) não pode exceder a qty da linha da DN.","efeitos":"INSERT packing_slip e packing_slip_item; audit_log; commit.","precondicoes":"Nota de entrega existente com itens correspondentes."},{"nome":"get-packing-slip","objetivo":"Retorna um romaneio com seus itens.","entradas":"--packing-slip-id (obrigatório).","saidas":"Campos do packing_slip + items (com item_code, item_name).","regras":"Packing slip deve existir.","efeitos":"nenhum (leitura).","precondicoes":"Romaneio existente."},{"nome":"list-packing-slips","objetivo":"Lista romaneios com filtros opcionais.","entradas":"--delivery-note-id; --company-id; --limit (default 20); --offset (default 0).","saidas":"packing_slips (lista), count.","regras":"Filtros opcionais; ordena por created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Status","objetivo":"Fornecer um resumo do domínio de vendas para uma empresa.","acoes":[{"nome":"status","objetivo":"Retorna um resumo de vendas (contagens por status e total em aberto) para uma empresa.","entradas":"--company-id (opcional; se omitido usa a primeira empresa encontrada).","saidas":"customers (contagem), quotations (por status), sales_orders (por status), sales_invoices (por status), total_outstanding.","regras":"Se nenhuma empresa informada nem existente, erro; agrega contagens via group by status; total_outstanding soma faturas submitted/overdue/partially_paid com saldo>0.","efeitos":"nenhum (leitura).","precondicoes":"Pelo menos uma empresa existente."}]}]},"buying":{"module":"buying","display":"Compras","functionalities":[{"group":"Fornecedores","objetivo":"Cadastro, atualizacao, consulta, listagem e importacao em massa de fornecedores, incluindo resumo de saldo devedor.","acoes":[{"nome":"add-supplier","objetivo":"Cria um registro de fornecedor com status 'active'.","entradas":"--name (obrigatorio); --company-id (obrigatorio); --supplier-type (default 'company', deve ser 'company'|'individual'); --supplier-group; --payment-terms-id; --tax-id; --is-1099-vendor (int, default 0); --primary-address (JSON); --email; --phone; --custom-fields (JSON).","saidas":"supplier_id, name e quaisquer custom fields mesclados na resposta.","regras":"Valida existencia de company_id; supplier_type restrito a company/individual; valida payment_terms_id se informado; primary_address e parseado como JSON; erro de IntegrityError vira 'Supplier creation failed'; erro em custom field faz rollback.","efeitos":"INSERT em supplier (status='active'); grava custom fields; audit_log via audit('add-supplier'); commit.","precondicoes":"Company existente; payment_terms existente se informado."},{"nome":"update-supplier","objetivo":"Atualiza campos de um fornecedor existente.","entradas":"--supplier-id (obrigatorio, aceita id ou name); --name; --payment-terms-id; --supplier-group; --supplier-type (company|individual); --email; --phone.","saidas":"supplier_id, updated_fields (lista de campos alterados).","regras":"Resolve supplier por id OU name e normaliza para id; erro se nao encontrado; erro 'No fields to update' se nenhum campo passado; supplier_type restrito a company/individual.","efeitos":"UPDATE em supplier (campos + updated_at via dynamic_update); audit_log via audit('update-supplier'); commit.","precondicoes":"Fornecedor existente."},{"nome":"get-supplier","objetivo":"Retorna o fornecedor com resumo de saldo devedor agregado das faturas de compra.","entradas":"--supplier-id (obrigatorio, aceita id ou name).","saidas":"Todos os campos do supplier, total_outstanding, outstanding_invoice_count, custom fields mesclados.","regras":"Resolve por id OU name; erro se nao encontrado; soma outstanding_amount de purchase_invoice em status submitted/overdue/partially_paid.","efeitos":"nenhum (leitura).","precondicoes":"Fornecedor existente."},{"nome":"list-suppliers","objetivo":"Lista fornecedores paginados com filtros opcionais.","entradas":"--company-id; --supplier-group; --search (filtra name/tax_id por LIKE); --limit (default 20); --offset (default 0).","saidas":"suppliers (lista), total_count, limit, offset, has_more.","regras":"Ordena por name; paginacao via limit/offset; has_more = offset+limit < total_count.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"import-suppliers","objetivo":"Importa fornecedores em massa de um arquivo CSV, pulando duplicados por nome+empresa.","entradas":"--csv-path (obrigatorio, deve ser .csv regular file); --company-id (obrigatorio). CSV: name, supplier_type, country, default_currency, email, phone, tax_id.","saidas":"imported, skipped, total_rows.","regras":"Resolve symlinks e exige extensao .csv e arquivo regular; valida CSV via validate_csv; erro se CSV vazio; pula linhas cujo (name, company_id) ja existe; gera naming_series por linha importada.","efeitos":"INSERT em supplier para cada linha nova (com naming_series); commit. Nao gera audit_log.","precondicoes":"Arquivo CSV valido; company informada."}]},{"group":"Requisicoes de Material","objetivo":"Criacao em rascunho, submissao e listagem de requisicoes de material (compra/transferencia/manufatura).","acoes":[{"nome":"add-material-request","objetivo":"Cria uma requisicao de material em rascunho com seus itens.","entradas":"--request-type (obrigatorio: purchase|transfer|manufacture; 'transfer' mapeia para 'material_transfer'); --items (obrigatorio, JSON array com item_id e qty); --company-id (obrigatorio). Cada item: item_id, qty, warehouse_id.","saidas":"material_request_id, request_type, item_count.","regras":"Valida tipo de requisicao e company; itens devem ter item_id e qty>0; aceita tambem material_transfer/material_issue internamente.","efeitos":"INSERT em material_request (status='draft') e material_request_item; audit_log via audit('add-material-request'); commit.","precondicoes":"Company existente."},{"nome":"submit-material-request","objetivo":"Submete uma requisicao de material atribuindo naming_series.","entradas":"--material-request-id (obrigatorio).","saidas":"material_request_id, naming_series, status='submitted'.","regras":"Erro se nao encontrada; so submete se status='draft'; gera naming_series via get_next_name por company.","efeitos":"UPDATE material_request (status='submitted', naming_series, updated_at); audit_log via audit('submit-material-request'); commit.","precondicoes":"Requisicao em rascunho."},{"nome":"list-material-requests","objetivo":"Lista requisicoes de material paginadas com filtros.","entradas":"--company-id; --request-type ('transfer' mapeia para 'material_transfer'); --mr-status; --limit (default 20); --offset (default 0).","saidas":"material_requests (lista), total_count, limit, offset, has_more.","regras":"Ordena por created_at desc; paginacao limit/offset.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."}]},{"group":"Cotacoes e RFQ","objetivo":"Criacao/submissao de RFQs, registro de cotacoes de fornecedores e comparacao de propostas por item.","acoes":[{"nome":"add-rfq","objetivo":"Cria uma Solicitacao de Cotacao (RFQ) em rascunho com itens e fornecedores convidados.","entradas":"--items (obrigatorio, JSON array: item_id, qty, uom, required_date); --suppliers (obrigatorio, JSON array de supplier IDs); --company-id (obrigatorio).","saidas":"rfq_id, item_count, supplier_count.","regras":"Valida company; valida que cada supplier informado existe; itens precisam item_id e qty>0; rfq_date = hoje.","efeitos":"INSERT em request_for_quotation (status='draft'), rfq_item e rfq_supplier; audit_log via audit('add-rfq'); commit.","precondicoes":"Company e fornecedores existentes."},{"nome":"submit-rfq","objetivo":"Submete a RFQ, marcando data de envio aos fornecedores.","entradas":"--rfq-id (obrigatorio).","saidas":"rfq_id, naming_series, status='submitted'.","regras":"Erro se nao encontrada; so submete de 'draft'; gera naming_series; preenche sent_date em todos rfq_supplier.","efeitos":"UPDATE request_for_quotation (status, naming_series, updated_at) e rfq_supplier (sent_date); audit_log via audit('submit-rfq'); commit.","precondicoes":"RFQ em rascunho."},{"nome":"list-rfqs","objetivo":"Lista RFQs paginadas com filtros.","entradas":"--company-id; --rfq-status; --limit (default 20); --offset (default 0).","saidas":"rfqs (lista), total_count, limit, offset, has_more.","regras":"Ordena por created_at desc; paginacao limit/offset.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"add-supplier-quotation","objetivo":"Registra a cotacao de um fornecedor respondendo a uma RFQ.","entradas":"--rfq-id (obrigatorio); --supplier-id (obrigatorio, id ou name); --items (obrigatorio, JSON: rfq_item_id, rate, lead_time_days).","saidas":"supplier_quotation_id, total_amount.","regras":"Valida RFQ e fornecedor; cada item precisa rfq_item_id e rate>0; qty vem do rfq_item; amount=qty*rate; soma total_amount; marca response_date/supplier_quotation_id no rfq_supplier; se todos fornecedores responderam, RFQ vira 'quotation_received'.","efeitos":"INSERT em supplier_quotation (status='draft') e supplier_quotation_item; UPDATE supplier_quotation (totais), rfq_supplier (response), e possivelmente request_for_quotation (status); audit_log via audit('add-supplier-quotation'); commit.","precondicoes":"RFQ existente; fornecedor existente; rfq_items existentes."},{"nome":"list-supplier-quotations","objetivo":"Lista cotacoes de fornecedores paginadas com filtros.","entradas":"--rfq-id; --supplier-id; --limit (default 20); --offset (default 0).","saidas":"supplier_quotations (lista com supplier_name), total_count, limit, offset, has_more.","regras":"Join com supplier; ordena por created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"compare-supplier-quotations","objetivo":"Compara lado a lado as cotacoes dos fornecedores para os mesmos itens da RFQ, destacando o menor preco.","entradas":"--rfq-id (obrigatorio).","saidas":"rfq_id, comparison (por item: quotes, lowest_rate, lowest_supplier, flag is_lowest), supplier_count.","regras":"Valida RFQ; para cada rfq_item compara rate de cada cotacao; calcula menor rate e marca is_lowest.","efeitos":"nenhum (leitura).","precondicoes":"RFQ existente com cotacoes registradas."}]},{"group":"Pedidos de Compra","objetivo":"Ciclo completo do pedido de compra: criar, atualizar, consultar, listar, submeter, cancelar e fechar.","acoes":[{"nome":"add-purchase-order","objetivo":"Cria um pedido de compra em rascunho com itens, descontos e impostos calculados.","entradas":"--supplier-id (obrigatorio, id ou name); --items (obrigatorio, JSON: item_id, qty, rate, uom, discount_percentage, warehouse_id, required_date); --company-id (obrigatorio); --tax-template-id; --posting-date (default hoje).","saidas":"purchase_order_id, total_amount, tax_amount, grand_total.","regras":"Fornecedor deve estar 'active'; valida company; cada item exige item_id, qty>0 e rate>0; net_amount aplica discount_percentage; tax via _calculate_tax; grand_total=total+tax.","efeitos":"INSERT em purchase_order (status='draft') e purchase_order_item; audit_log via audit('add-purchase-order'); commit.","precondicoes":"Fornecedor ativo; company existente."},{"nome":"update-purchase-order","objetivo":"Substitui os itens de um PO em rascunho e recalcula totais.","entradas":"--purchase-order-id (obrigatorio); --items (obrigatorio, JSON array).","saidas":"purchase_order_id, total_amount, grand_total.","regras":"So atualiza se status='draft' (sugere cancelar antes); apaga e reinsere todos os itens; recalcula tax pelo tax_template do PO; valida item_id/qty/rate por item.","efeitos":"DELETE/INSERT purchase_order_item; UPDATE purchase_order (totais, updated_at); audit_log via audit('update-purchase-order'); commit.","precondicoes":"PO em rascunho."},{"nome":"get-purchase-order","objetivo":"Retorna o PO com itens e status de recebimentos e faturas vinculados.","entradas":"--purchase-order-id (obrigatorio).","saidas":"Campos do PO + items, purchase_receipts (id, naming, status, posting_date), purchase_invoices (com grand_total e outstanding).","regras":"Erro se PO nao encontrado; itens ordenados por linha.","efeitos":"nenhum (leitura).","precondicoes":"PO existente."},{"nome":"list-purchase-orders","objetivo":"Lista pedidos de compra paginados com filtros.","entradas":"--company-id; --supplier-id; --po-status; --from-date / --to-date (filtra order_date); --limit (default 20); --offset (default 0).","saidas":"purchase_orders (com supplier_name), total_count, limit, offset, has_more.","regras":"Join com supplier; ordena por order_date desc, created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"submit-purchase-order","objetivo":"Confirma um PO em rascunho, atribuindo naming_series e avisando sobre quantidade minima.","entradas":"--purchase-order-id (obrigatorio).","saidas":"purchase_order_id, naming_series, status='confirmed', warnings (opcional: itens abaixo do min_order_qty).","regras":"So submete de 'draft'; verifica item_supplier.min_order_qty e gera avisos (nao bloqueia); gera naming_series.","efeitos":"UPDATE purchase_order (status='confirmed', naming_series, updated_at); audit_log via audit('submit-purchase-order'); commit.","precondicoes":"PO em rascunho."},{"nome":"cancel-purchase-order","objetivo":"Cancela um PO desde que nao tenha recebimentos ou faturas vinculados.","entradas":"--purchase-order-id (obrigatorio).","saidas":"purchase_order_id, status='cancelled'.","regras":"Erro se ja cancelado; bloqueia se existirem purchase_receipt nao-cancelados ou purchase_invoice nao-cancelados vinculados.","efeitos":"UPDATE purchase_order (status='cancelled', updated_at); audit_log via audit('cancel-purchase-order'); commit.","precondicoes":"PO sem documentos filhos ativos."},{"nome":"close-purchase-order","objetivo":"Fecha um PO parcialmente recebido, impedindo novos recebimentos/faturas mas preservando documentos filhos.","entradas":"--purchase-order-id (obrigatorio); --reason; --closed-by.","saidas":"purchase_order_id, doc_status='closed', close_reason, closed_by.","regras":"Erro se status estiver em draft/cancelled/closed.","efeitos":"UPDATE purchase_order (status='closed', close_reason, closed_by, updated_at); audit_log via audit('close-purchase-order'); commit.","precondicoes":"PO confirmado/parcialmente recebido ou faturado."}]},{"group":"Recebimentos (GRN)","objetivo":"Geracao de recebimentos a partir de PO, consulta/listagem e submissao/cancelamento com postagens de estoque e GL.","acoes":[{"nome":"create-purchase-receipt","objetivo":"Cria um recebimento de compra (GRN) em rascunho a partir de um PO (total ou parcial).","entradas":"--purchase-order-id (obrigatorio); --posting-date (default hoje); --items (JSON opcional para recebimento parcial: purchase_order_item_id, qty, warehouse_id, batch_id, serial_numbers).","saidas":"purchase_receipt_id, total_qty, item_count.","regras":"PO deve estar 'confirmed' ou 'partially_received' (erro se 'closed'); parcial valida qty contra remaining (ordered-received) aplicando receipt_tolerance_pct da empresa; total copia todos itens nao-recebidos; erro se nada a receber.","efeitos":"INSERT em purchase_receipt (status='draft') e purchase_receipt_item; audit_log via audit('create-purchase-receipt'); commit. Nao posta estoque/GL ainda.","precondicoes":"PO confirmado/parcialmente recebido."},{"nome":"get-purchase-receipt","objetivo":"Retorna um recebimento de compra com seus itens.","entradas":"--purchase-receipt-id (obrigatorio).","saidas":"Campos do purchase_receipt + items (com item_code/item_name).","regras":"Erro se nao encontrado; itens ordenados por linha.","efeitos":"nenhum (leitura).","precondicoes":"Recebimento existente."},{"nome":"list-purchase-receipts","objetivo":"Lista recebimentos de compra paginados com filtros.","entradas":"--company-id; --supplier-id; --pr-status; --limit (default 20); --offset (default 0).","saidas":"purchase_receipts (com supplier_name), total_count, limit, offset, has_more.","regras":"Join com supplier; ordena por posting_date desc, created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"submit-purchase-receipt","objetivo":"Submete o GRN gerando lancamentos de estoque (SLE) e GL de inventario perpetuo, e atualiza o PO.","entradas":"--purchase-receipt-id (obrigatorio).","saidas":"purchase_receipt_id, naming_series, status='submitted', sle_entries_created, gl_entries_created.","regras":"So submete de 'draft'; verifica que PO vinculado esteja confirmed/partially_received/partially_invoiced; warehouse cai para default da empresa se ausente (erro se nenhum); SLE com require_rate=True (rate da linha do PO); atualiza received_qty dos itens do PO e recalcula status (partially/fully_received).","efeitos":"INSERT stock_ledger_entry (insert_sle_entries) e gl_entry (DR Stock In Hand / CR Stock Received Not Billed via create_perpetual_inventory_gl); UPDATE purchase_order_item.received_qty e purchase_order.status/per_received; UPDATE purchase_receipt (status, naming); audit_log via audit('submit-purchase-receipt'); commit.","precondicoes":"GRN em rascunho com itens; warehouse ou default da empresa; fiscal_year e cost_center disponiveis."},{"nome":"cancel-purchase-receipt","objetivo":"Cancela um GRN submetido, revertendo SLE/GL e reduzindo received_qty no PO.","entradas":"--purchase-receipt-id (obrigatorio).","saidas":"purchase_receipt_id, status='cancelled', sle_reversals, gl_reversals.","regras":"So cancela se status='submitted'; reverte SLE e GL (GL com tolerancia a falha); reverte received_qty (com floor 0); recalcula status do PO; se tudo zerado volta PO para 'confirmed'.","efeitos":"Reversao em stock_ledger_entry (reverse_sle_entries) e gl_entry (reverse_gl_entries); UPDATE purchase_order_item.received_qty e purchase_order.status; UPDATE purchase_receipt (status='cancelled'); audit_log via audit('cancel-purchase-receipt'); commit.","precondicoes":"GRN submetido."}]},{"group":"Faturas de Compra","objetivo":"Ciclo da fatura de compra: criar (de PO/GRN/avulsa ou CWIP), atualizar, consultar, listar, submeter (GL/AP/imposto/PLE e SLE opcional), cancelar e baixar outstanding.","acoes":[{"nome":"create-purchase-invoice","objetivo":"Cria uma fatura de compra em rascunho a partir de PO, GRN, avulsa ou capitalizada em CWIP.","entradas":"--purchase-order-id e/ou --purchase-receipt-id; OU avulsa (--supplier-id, --company-id, --items obrigatorios); --posting-date (default hoje); --due-date; --tax-template-id; --cwip-asset-id (apenas avulsa). Itens avulsos: item_id, qty, rate, uom, expense_account_id, cost_center_id, project_id.","saidas":"purchase_invoice_id, total_amount, tax_amount, grand_total, update_stock.","regras":"De PO: copia itens nao-totalmente-faturados (qty-invoiced_qty), erro se PO 'closed', update_stock=0 se ja ha GRN submetido; de GRN: copia itens, update_stock=0; avulsa: update_stock=1 (default); --cwip-asset-id exige asset under_construction e proibe combinar com PO/GRN (update_stock=0); tax via _calculate_tax.","efeitos":"INSERT em purchase_invoice (status='draft', com update_stock/cwip_asset_id/outstanding=grand_total) e purchase_invoice_item; audit_log via audit('create-purchase-invoice'); commit. Sem GL/SLE nesta etapa.","precondicoes":"PO/GRN existentes conforme o caso; fornecedor existente; asset under_construction se CWIP."},{"nome":"update-purchase-invoice","objetivo":"Atualiza a data de vencimento e/ou os itens de uma fatura em rascunho.","entradas":"--purchase-invoice-id (obrigatorio); --due-date; --items (JSON array).","saidas":"purchase_invoice_id, updated_fields.","regras":"So atualiza se status='draft' (sugere cancelar antes); ao trocar itens, apaga/reinsere e recalcula tax/grand_total/outstanding; valida item_id/qty/rate; erro se nenhum campo informado.","efeitos":"UPDATE purchase_invoice (due_date e/ou totais, updated_at); DELETE/INSERT purchase_invoice_item; audit_log via audit('update-purchase-invoice'); commit.","precondicoes":"Fatura em rascunho."},{"nome":"get-purchase-invoice","objetivo":"Retorna a fatura de compra com itens e lancamentos de pagamento (PLE).","entradas":"--purchase-invoice-id (obrigatorio).","saidas":"Campos da purchase_invoice + items + payments (payment_ledger_entry contra esta fatura).","regras":"Erro se nao encontrada; itens ordenados por linha.","efeitos":"nenhum (leitura).","precondicoes":"Fatura existente."},{"nome":"list-purchase-invoices","objetivo":"Lista faturas de compra paginadas com filtros.","entradas":"--company-id; --supplier-id; --pi-status; --from-date / --to-date (filtra posting_date); --limit (default 20); --offset (default 0).","saidas":"purchase_invoices (com supplier_name), total_count, limit, offset, has_more.","regras":"Join com supplier; ordena por posting_date desc, created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"submit-purchase-invoice","objetivo":"Submete a fatura postando GL (despesa/SRNB + imposto + AP), PLE e, se update_stock, SLE + GL de inventario; trata returns e CWIP.","entradas":"--purchase-invoice-id (obrigatorio).","saidas":"purchase_invoice_id, naming_series, status='submitted', is_return, voucher_type, gl_entries_created, sle_entries_created, update_stock, (cwip_asset_id/cwip_accumulation_id se CWIP).","regras":"So submete de 'draft'; valida 3-way match (PO-GRN-Invoice) conforme three_way_match_policy da empresa (disabled/strict/tolerant) se vinculada a PO e nao for return; DR despesa OU SRNB/inventario (se ha GRN) OU CWIP account (se cwip_asset); DR input tax por linha de imposto; CR Trade Payables; returns invertem os lados e PLE negativo; CWIP nao pode ser return; atualiza invoiced_qty/status do PO.","efeitos":"INSERT gl_entry (insert_gl_entries, com entry_set='cogs' para estoque) e payment_ledger_entry; se update_stock: INSERT stock_ledger_entry + GL de inventario; se CWIP: record_cwip_accumulation; UPDATE purchase_order_item.invoiced_qty e purchase_order.status; UPDATE purchase_invoice (status, naming); audit_log via audit('submit-purchase-invoice' ou 'submit-debit-note'); commit.","precondicoes":"Fatura em rascunho com itens; payable account; fiscal_year/cost_center; asset under_construction se CWIP."},{"nome":"cancel-purchase-invoice","objetivo":"Cancela uma fatura submetida revertendo GL, PLE, SLE (se update_stock) e acumulacao CWIP.","entradas":"--purchase-invoice-id (obrigatorio).","saidas":"purchase_invoice_id, status='cancelled', gl_reversals, sle_reversals.","regras":"So cancela se status em submitted/overdue/partially_paid; reverte GL (inclui legs de estoque/COGS); se cwip_asset reverte acumulacoes; reverte SLE se update_stock; marca PLE como delinked; reverte invoiced_qty no PO e recalcula status.","efeitos":"Reversao em gl_entry (reverse_gl_entries) e stock_ledger_entry; UPDATE payment_ledger_entry (delinked=1); reverse_cwip_accumulations se aplicavel; UPDATE purchase_order_item.invoiced_qty e purchase_order.status; UPDATE purchase_invoice (status='cancelled'); audit_log via audit('cancel-purchase-invoice'); commit.","precondicoes":"Fatura submetida/overdue/parcialmente paga."},{"nome":"update-invoice-outstanding","objetivo":"Cross-skill (chamado por glue-payments) para reduzir o outstanding de uma fatura ao aplicar um pagamento.","entradas":"--purchase-invoice-id (obrigatorio); --amount (obrigatorio, >0).","saidas":"purchase_invoice_id, outstanding_amount (novo), status (novo).","regras":"Erro se fatura nao encontrada ou amount<=0; delega a apply_payment_to_document da lib payment_clearing (regra canonica unica); over-payment e REJEITADO (ValueError vira erro).","efeitos":"UPDATE purchase_invoice (outstanding_amount/status via lib payment_clearing); audit_log via audit('update-invoice-outstanding'); commit.","precondicoes":"Fatura existente."}]},{"group":"Notas de Debito","objetivo":"Criacao de notas de debito (devolucoes) em rascunho contra faturas de compra existentes.","acoes":[{"nome":"create-debit-note","objetivo":"Cria uma nota de debito (devolucao) em rascunho contra uma fatura de compra, com quantidades/valores negativos.","entradas":"--against-invoice-id (obrigatorio); --items (obrigatorio, JSON: item_id, qty, rate opcional); --posting-date (default hoje); --reason.","saidas":"debit_note_id, against_invoice_id, total_amount (negativo).","regras":"Fatura original deve estar em submitted/partially_paid/paid/overdue; rate ausente e buscado na fatura original; qty/amount sao negativados; herda supplier/company/update_stock da original; documento criado como purchase_invoice com is_return=1 e return_against; status='draft' (submissao posterior via submit-purchase-invoice).","efeitos":"INSERT em purchase_invoice (is_return=1, status='draft', valores negativos) e purchase_invoice_item; audit_log via audit('create-debit-note'); commit. Nao posta GL/PLE/SLE.","precondicoes":"Fatura de compra original submetida/paga existente."}]},{"group":"Custos de Importacao","objetivo":"Alocacao de custos de importacao (frete, seguro etc.) sobre itens de recebimentos, ajustando rate e postando GL.","acoes":[{"nome":"add-landed-cost-voucher","objetivo":"Aloca encargos de importacao entre os itens de recebimentos e capitaliza no estoque via GL.","entradas":"--purchase-receipt-ids (obrigatorio, JSON array); --charges (obrigatorio, JSON: description, amount, allocation_method 'qty'|'value', expense_account_id); --company-id (obrigatorio).","saidas":"landed_cost_voucher_id, total_landed_cost, gl_entries_created.","regras":"Recebimentos devem existir e estar 'submitted'; cada charge amount>0; aloca por quantidade ou por valor (ultimo item absorve diferenca de arredondamento); calcula final_rate=original_rate+encargo por unidade; GL so se expense_account_id e conta de stock existirem.","efeitos":"INSERT em landed_cost_voucher (status='submitted'), landed_cost_charge e landed_cost_item; INSERT gl_entry (DR Stock In Hand / CR conta de despesa via insert_gl_entries); audit_log via audit('add-landed-cost-voucher'); commit.","precondicoes":"Recebimentos submetidos; conta de estoque da empresa para GL."}]},{"group":"Blanket PO","objetivo":"Acordos-quadro (blanket orders) de compra: criar, ativar, consultar e listar.","acoes":[{"nome":"add-blanket-po","objetivo":"Cria um pedido de compra blanket (acordo-quadro) em rascunho com itens e periodo de validade.","entradas":"--supplier-id (obrigatorio, id ou name); --items (obrigatorio, JSON: item_id, qty, rate, uom); --company-id (obrigatorio); --valid-from (obrigatorio); --valid-to (obrigatorio).","saidas":"blanket_order_id, supplier_id, total_qty, valid_from, valid_to.","regras":"Fornecedor deve estar 'active'; valida company; valid_to deve ser > valid_from; cada item exige item_id, qty>0, rate>0; blanket_order_type='buying'.","efeitos":"INSERT em blanket_order (status='draft', type='buying') e blanket_order_item; UPDATE blanket_order (total_qty); audit_log via audit('add-blanket-po'); commit.","precondicoes":"Fornecedor ativo; company existente."},{"nome":"submit-blanket-po","objetivo":"Ativa um blanket PO em rascunho.","entradas":"--blanket-order-id (obrigatorio).","saidas":"blanket_order_id, doc_status='active'.","regras":"Erro se nao encontrado; so ativa de 'draft'; tipo deve ser 'buying'.","efeitos":"UPDATE blanket_order (status='active', updated_at); audit_log via audit('submit-blanket-po'); commit.","precondicoes":"Blanket PO de compra em rascunho."},{"nome":"get-blanket-po","objetivo":"Retorna um blanket PO com seus itens.","entradas":"--blanket-order-id (obrigatorio).","saidas":"Campos do blanket_order + items.","regras":"Erro se nao encontrado.","efeitos":"nenhum (leitura).","precondicoes":"Blanket PO existente."},{"nome":"list-blanket-pos","objetivo":"Lista blanket POs do tipo 'buying' paginados com filtros.","entradas":"--company-id; --supplier-id; --blanket-status; --limit (default 20); --offset (default 0).","saidas":"blanket_orders (lista), total_count, limit, offset, has_more.","regras":"Sempre filtra blanket_order_type='buying'; ordena por created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."}]},{"group":"Conversao p/ PO","objetivo":"Geracao de pedidos de compra a partir de blanket orders (drawdown) ou de pedidos de venda (back-to-back).","acoes":[{"nome":"create-po-from-blanket","objetivo":"Cria um PO em rascunho consumindo (drawdown) quantidades de um blanket PO ativo.","entradas":"--blanket-order-id (obrigatorio); --items (obrigatorio, JSON: item_id, qty, rate opcional, uom, warehouse_id, required_date); --posting-date (default hoje); --tax-template-id.","saidas":"purchase_order_id, blanket_order_id, total_amount, grand_total.","regras":"Blanket deve estar 'active', tipo 'buying' e nao expirado (valid_to>=hoje); cada item deve pertencer ao blanket e qty<=remaining (quantity-ordered_qty); rate padrao vem do blanket; atualiza ordered_qty dos itens e total do blanket.","efeitos":"INSERT em purchase_order (status='draft') e purchase_order_item; UPDATE blanket_order_item.ordered_qty e blanket_order.ordered_qty; audit_log via audit('create-po-from-blanket'); commit.","precondicoes":"Blanket PO ativo e vigente."},{"nome":"create-po-from-so","objetivo":"Cria pedidos de compra (um por fornecedor) a partir de um pedido de venda, usando o fornecedor padrao de cada item.","entradas":"--sales-order-id (obrigatorio); --posting-date (default hoje); --tax-template-id.","saidas":"sales_order_id, purchase_orders_created, purchase_orders (lista com supplier/grand_total/items_count), items_without_supplier.","regras":"SO deve estar em draft/confirmed; para cada item busca fornecedor padrao via item_supplier (menor priority); itens sem fornecedor vao para items_without_supplier; agrupa por fornecedor; pula fornecedores nao-ativos; erro se nenhum item tem fornecedor configurado.","efeitos":"INSERT em purchase_order (status='draft') e purchase_order_item (um PO por fornecedor); audit_log via audit('create-po-from-so'); commit.","precondicoes":"Sales order existente com itens; mapeamentos item_supplier configurados."}]},{"group":"Contas Recorrentes","objetivo":"Templates de contas/faturas recorrentes de fornecedores e geracao automatica das faturas conforme frequencia.","acoes":[{"nome":"add-recurring-bill-template","objetivo":"Cria um template de fatura de compra recorrente em rascunho.","entradas":"--supplier-id (obrigatorio, id ou name, ativo); --items (obrigatorio, JSON: item_id, qty, rate, uom); --frequency (obrigatorio: weekly|monthly|quarterly|semi_annually|annually); --start-date (obrigatorio); --company-id (obrigatorio); --end-date; --tax-template-id; --auto-submit (flag, default False).","saidas":"template_id, frequency, start_date, next_bill_date.","regras":"Frequencia deve estar em VALID_FREQUENCIES; fornecedor deve estar 'active'; valida company; cada item exige item_id; next_bill_date inicial = start_date; auto_submit gravado como 0/1.","efeitos":"INSERT em recurring_bill_template (status='draft') e recurring_bill_template_item; audit_log via audit('add-recurring-bill-template'); commit.","precondicoes":"Fornecedor ativo; company existente."},{"nome":"list-recurring-bill-templates","objetivo":"Lista templates de contas recorrentes paginados com filtros.","entradas":"--company-id; --supplier-id; --template-status; --limit (default 20); --offset (default 0).","saidas":"recurring_bill_templates (lista), total_count, limit, offset, has_more.","regras":"Ordena por next_bill_date.","efeitos":"nenhum (leitura).","precondicoes":"nenhuma."},{"nome":"generate-recurring-bills","objetivo":"Cron: gera automaticamente faturas de compra a partir de templates ativos com vencimento ate a data de referencia.","entradas":"--company-id (obrigatorio); --as-of-date (default hoje).","saidas":"bills_generated, templates_processed, templates_completed, bills (lista), errors (lista).","regras":"Seleciona templates 'active' com next_bill_date<=as_of_date e (end_date nulo ou >=as_of_date); due_date = next_date+30 dias; se auto_submit posta GL (DR despesa / CR payable) e status='submitted' com naming; avanca next_bill_date pela frequencia; marca template 'completed' se passar do end_date; erros por template sao coletados (com rollback do template em falha de GL).","efeitos":"INSERT em purchase_invoice (status draft ou submitted) e purchase_invoice_item; se auto_submit: INSERT gl_entry; UPDATE recurring_bill_template (last/next_bill_date, status); commit. Nao gera audit_log por fatura.","precondicoes":"Templates ativos com itens; contas payable/expense da empresa para auto_submit."}]},{"group":"Politicas de Compra","objetivo":"Configuracao de politicas da empresa para tolerancia de recebimento (GRN) e 3-way match.","acoes":[{"nome":"update-receipt-tolerance","objetivo":"Atualiza o percentual de tolerancia de recebimento (GRN) de uma empresa.","entradas":"--company-id (obrigatorio); --tolerance-pct (default '0'; 0=estrito).","saidas":"company_id, receipt_tolerance_pct.","regras":"Percentual nao pode ser negativo nem exceder 100; valida existencia da empresa.","efeitos":"UPDATE company (receipt_tolerance_pct, updated_at); audit_log via audit('update-receipt-tolerance'); commit.","precondicoes":"Company existente."},{"nome":"update-three-way-match-policy","objetivo":"Atualiza a politica de 3-way match (PO-GRN-Invoice) de uma empresa.","entradas":"--company-id (obrigatorio); --policy (obrigatorio: strict|tolerant|disabled).","saidas":"company_id, three_way_match_policy.","regras":"Politica restrita a strict/tolerant/disabled; valida existencia da empresa.","efeitos":"UPDATE company (three_way_match_policy, updated_at); audit_log via audit('update-three-way-match-policy'); commit.","precondicoes":"Company existente."}]},{"group":"Configuracoes de Item e Resumo","objetivo":"Acoes auxiliares de configuracao de UOM de compra por item e resumo geral do dominio de compras (acoes que nao se encaixam nos grupos do ciclo P2P).","acoes":[{"nome":"set-item-purchase-uom","objetivo":"Define a UOM de compra padrao e o fator de conversao para a UOM de estoque de um item.","entradas":"--item-id (obrigatorio); --purchase-uom (obrigatorio); --conversion-factor (obrigatorio, >0).","saidas":"uom_conversion_id, item_id, purchase_uom, stock_uom, conversion_factor, action ('created'|'updated'), message.","regras":"Valida item; conversion_factor>0; resolve IDs de UOM na tabela uom (cai para a string do nome se nao existir); cria ou atualiza a conversao from_uom(purchase)->to_uom(stock).","efeitos":"INSERT ou UPDATE em uom_conversion; audit_log via audit('set-item-purchase-uom'); commit.","precondicoes":"Item existente."},{"nome":"status","objetivo":"Retorna um resumo de compras da empresa (contagens e saldo devedor).","entradas":"--company-id (opcional; usa a primeira empresa se omitido).","saidas":"suppliers (contagem), purchase_orders (contagem por status + total), purchase_invoices (contagem por status + total), total_outstanding.","regras":"Erro se nenhuma empresa existir; agrupa POs e PIs por status; total_outstanding soma faturas submitted/overdue/partially_paid.","efeitos":"nenhum (leitura).","precondicoes":"Pelo menos uma empresa cadastrada."}]}]},"inventory":{"module":"inventory","display":"Estoque","functionalities":[{"group":"Itens","objetivo":"CRUD e resolução de itens (catálogo de produtos) e seus saldos consolidados.","acoes":[{"nome":"add-item","objetivo":"Cria um novo item no catálogo.","entradas":"--item-code (obrigatório); --item-name (obrigatório); --item-type (default 'stock', valores stock|non_stock|service); --valuation-method (default 'moving_average', valores moving_average|fifo); --item-group (id ou nome); --stock-uom (default 'Nos'); --has-batch (default 0); --has-serial (default 0); --standard-rate (default 0); --custom-fields (JSON).","saidas":"item_id, item_code, item_name e campos custom mesclados via merge_into_response.","regras":"Valida item_type e valuation_method contra listas; se --item-group informado resolve id por id/nome ou erra; is_stock_item=1 só para type 'stock'; arredonda standard_rate; IntegrityError vira erro de duplicidade. Erro de custom field faz rollback.","efeitos":"INSERT em item (status='active'); grava custom fields (store_from_arg); audit_log via audit('add-item'); commit.","precondicoes":"Tabela company existe (REQUIRED_TABLES); item_group referenciado deve existir se informado."},{"nome":"update-item","objetivo":"Atualiza campos editáveis de um item existente.","entradas":"--item-id (obrigatório); campos opcionais: --item-name, --reorder-level, --reorder-qty, --standard-rate, --status (active|disabled).","saidas":"item_id, updated_fields (lista dos campos alterados).","regras":"Erra se item não existe; bloqueia update de item 'disabled' a menos que --status=active; valida status em (active,disabled); erra se nenhum campo a atualizar; arredonda standard_rate; seta updated_at.","efeitos":"UPDATE dinâmico em item; audit_log via audit('update-item'); commit.","precondicoes":"Item deve existir."},{"nome":"get-item","objetivo":"Retorna o item com resumo de estoque por depósito e totais.","entradas":"--item-id (obrigatório).","saidas":"Campos do item + stock_balances (por warehouse: id, name, qty, valuation_rate, stock_value) + total_qty + total_stock_value + custom fields.","regras":"Erra se item não existe; agrega saldos dos warehouses distintos com SLE não cancelado via get_stock_balance, incluindo só linhas com qty ou valor != 0.","efeitos":"nenhum (leitura).","precondicoes":"Item deve existir."},{"nome":"list-items","objetivo":"Lista itens com filtros e paginação.","entradas":"Filtros opcionais: --warehouse-id (itens com estoque no depósito), --company-id (via item_group.company_id), --item-group, --item-type, --search (item_name/item_code LIKE); --limit (default 20); --offset (default 0).","saidas":"items[], total_count, limit, offset, has_more.","regras":"Conta total e retorna página ordenada por item_name; filtro de warehouse usa subquery de SLE não cancelado.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além de tabelas base."},{"nome":"resolve-item","objetivo":"Resolve uma frase livre/plural do usuário em candidatos de item ranqueados.","entradas":"--name (obrigatório, dest=name).","saidas":"query, matched, single_match, multiple_matches, match_type (exact|singular|substring|tokens|null), candidates[].","regras":"Cascata determinística de 4 tiers (exato, singularizado, substring LIKE, token-AND), para no primeiro tier com >=1 resultado; comparação case-insensitive via fn.Lower; limite 10 candidatos.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"import-items","objetivo":"Importa itens em massa a partir de um arquivo CSV.","entradas":"--csv-path (obrigatório).","saidas":"imported, skipped, total_rows.","regras":"Path precisa ser .csv e arquivo regular; valida CSV via validate_csv e parseia via parse_csv_rows; pula item_code duplicado (globalmente único); resolve group por nome se existir; uom default 'Nos', valuation_method default 'moving_average'.","efeitos":"INSERT em item (status='active') por linha nova; commit. NÃO grava audit_log.","precondicoes":"Arquivo CSV válido existente no caminho informado."}]},{"group":"Grupos de Itens","objetivo":"Criação e listagem de grupos de itens (hierarquia de categorização).","acoes":[{"nome":"add-item-group","objetivo":"Cria um grupo de itens, opcionalmente sob um grupo pai.","entradas":"--name (obrigatório); --parent-id (opcional); --company-id (opcional).","saidas":"item_group_id, name.","regras":"Erra se --parent-id informado e pai não existe; IntegrityError vira erro 'já existe' (por nome/empresa).","efeitos":"INSERT em item_group; audit_log via audit('add-item-group'); commit.","precondicoes":"Grupo pai deve existir se informado."},{"nome":"list-item-groups","objetivo":"Lista grupos de itens com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --parent-id; --limit (default 20); --offset (default 0).","saidas":"item_groups[], total_count, limit, offset, has_more.","regras":"Conta e pagina ordenando por name.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Depósitos","objetivo":"Cadastro, atualização e listagem de depósitos (warehouses) por empresa.","acoes":[{"nome":"add-warehouse","objetivo":"Cria um depósito vinculado a uma empresa.","entradas":"--name (obrigatório); --company-id (obrigatório); --warehouse-type (default 'stores', valores stores|production|transit|rejected); --parent-id (opcional); --account-id (opcional); --is-group (default 0).","saidas":"warehouse_id, name.","regras":"Erra se company, parent_id ou account_id informados não existem; valida warehouse_type contra lista.","efeitos":"INSERT em warehouse; audit_log via audit('add-warehouse'); commit.","precondicoes":"Empresa existe; conta/depósito pai existem se informados."},{"nome":"update-warehouse","objetivo":"Atualiza nome e/ou conta contábil de um depósito.","entradas":"--warehouse-id (obrigatório, aceita id ou nome); --name e/ou --account-id (opcionais).","saidas":"warehouse_id, updated_fields.","regras":"Resolve depósito por id ou nome ou erra; valida account_id existente; erra se nenhum campo a atualizar; seta updated_at.","efeitos":"UPDATE dinâmico em warehouse; audit_log via audit('update-warehouse'); commit.","precondicoes":"Depósito existe; conta existe se account_id informado."},{"nome":"list-warehouses","objetivo":"Lista depósitos de uma empresa com filtros e paginação.","entradas":"--company-id ou --company (nome) (um requerido via resolve_company_id); filtros opcionais --parent-id, --warehouse-type; --limit (default 20); --offset (default 0).","saidas":"warehouses[], total_count, limit, offset, has_more.","regras":"Resolve company_id por id ou nome; conta e pagina ordenando por name.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."}]},{"group":"Movimentações","objetivo":"Ciclo de vida de stock entries (recebimento, baixa, transferência, manufatura) em rascunho/submit/cancel.","acoes":[{"nome":"add-stock-entry","objetivo":"Cria uma movimentação de estoque em rascunho com seus itens.","entradas":"--entry-type (obrigatório, receive|issue|transfer|manufacture); --company-id (obrigatório); --posting-date (obrigatório); --items (obrigatório, JSON array com item_id, qty, rate, from_warehouse_id, to_warehouse_id, batch_id, serial_numbers).","saidas":"stock_entry_id, naming_series, total_incoming_value, total_outgoing_value, value_difference.","regras":"Valida entry_type e company; cada item exige item_id válido e qty>0; rate<=0 cai para standard_rate; usa default_warehouse da empresa se faltar from/to; valida warehouse exigido por tipo (receipt exige to, issue exige from, transfer exige ambos, manufacture exige um); calcula totais incoming/outgoing e value_difference.","efeitos":"INSERT em stock_entry (status='draft', naming_series via get_next_name) e em stock_entry_item; audit_log via audit('add-stock-entry'); commit. NÃO posta SLE/GL.","precondicoes":"Empresa existe; itens referenciados existem."},{"nome":"get-stock-entry","objetivo":"Retorna uma stock entry com seus itens.","entradas":"--stock-entry-id (obrigatório).","saidas":"Campos da stock_entry + items[] (com item_code/item_name).","regras":"Erra se não existe; itens ordenados por line_order.","efeitos":"nenhum (leitura).","precondicoes":"Stock entry existe."},{"nome":"list-stock-entries","objetivo":"Lista movimentações com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --entry-type (mapeado), --status-filter (dest se_status), --from-date, --to-date; --limit (default 20); --offset (default 0).","saidas":"stock_entries[], total_count, limit, offset, has_more.","regras":"Conta e pagina ordenando por posting_date desc e created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"submit-stock-entry","objetivo":"Submete uma stock entry rascunho, postando SLE e GL de inventário perpétuo.","entradas":"--stock-entry-id (obrigatório).","saidas":"stock_entry_id, sle_entries_created, gl_entries_created.","regras":"Erra se não existe ou status != 'draft'; erra se sem itens; constrói SLE por tipo (receipt +qty com require_rate; issue -qty; transfer -from/+to; manufacture +to/-from); resolve fiscal_year e cost_center; falha de SLE/GL aborta com erro.","efeitos":"INSERT em stock_ledger_entry (insert_sle_entries) e gl_entry (create_perpetual_inventory_gl + insert_gl_entries); UPDATE stock_entry status='submitted'; audit_log via audit('submit-stock-entry'); commit.","precondicoes":"Stock entry em status 'draft' com itens; fiscal year e contas de inventário configurados."},{"nome":"cancel-stock-entry","objetivo":"Cancela uma stock entry submetida, revertendo SLE e GL.","entradas":"--stock-entry-id (obrigatório).","saidas":"stock_entry_id, reversed, sle_reversals, gl_reversals.","regras":"Erra se não existe ou status != 'submitted'; reverte SLE (obrigatório) e GL (tolera ausência de GL); usa posting_date original.","efeitos":"INSERT de SLE de reversão (reverse_sle_entries) e GL de reversão (reverse_gl_entries); UPDATE stock_entry status='cancelled'; audit_log via audit('cancel-stock-entry'); commit.","precondicoes":"Stock entry em status 'submitted'."}]},{"group":"Razão de Estoque (SLE)","objetivo":"Gateway cross-skill para selling/buying criarem e reverterem lançamentos no razão de estoque.","acoes":[{"nome":"create-stock-ledger-entries","objetivo":"Cross-skill: cria lançamentos de SLE para um voucher externo.","entradas":"--voucher-type (obrigatório, canonicalizado para snake_case); --voucher-id (obrigatório); --posting-date (obrigatório); --entries (obrigatório, JSON array); --company-id (obrigatório).","saidas":"sle_ids[], count.","regras":"Canonicaliza voucher_type via canonical_voucher_type (FINDING-006); --entries deve ser array não vazio; injeta fiscal_year em cada entry; falha de SLE aborta com erro.","efeitos":"INSERT em stock_ledger_entry (insert_sle_entries); audit_log via audit('create-stock-ledger-entries'); commit.","precondicoes":"Empresa e itens/warehouses dos entries existentes; chamado por selling/buying."},{"nome":"reverse-stock-ledger-entries","objetivo":"Cross-skill: reverte os lançamentos de SLE de um voucher externo.","entradas":"--voucher-type (obrigatório, canonicalizado); --voucher-id (obrigatório); --posting-date (obrigatório).","saidas":"reversal_ids[], count.","regras":"Canonicaliza voucher_type para casar com SLE armazenados; falha de reversão aborta com erro.","efeitos":"INSERT de SLE de reversão (reverse_sle_entries); audit_log via audit('reverse-stock-ledger-entries'); commit.","precondicoes":"Existirem SLE não cancelados sob o voucher informado."}]},{"group":"Saldos e Relatórios","objetivo":"Consultas de saldo por item/depósito, relatórios de estoque/razão, status e checagem de ponto de reposição.","acoes":[{"nome":"get-stock-balance","objetivo":"Retorna saldo, taxa de valoração e valor de um item em um depósito.","entradas":"--item-id (obrigatório); --warehouse-id (obrigatório).","saidas":"item_id, warehouse_id, qty, valuation_rate, stock_value.","regras":"Delega a get_stock_balance (soma de SLE não cancelado).","efeitos":"nenhum (leitura).","precondicoes":"Item e depósito informados."},{"nome":"stock-balance-report","objetivo":"Resumo de saldo de todos os itens de uma empresa (com alias 'stock-balance').","entradas":"--company-id ou --company (nome) (via resolve_company_id); filtro opcional --warehouse-id.","saidas":"report[] (item, warehouse, qty, valuation_rate, stock_value), total_stock_value, row_count.","regras":"SQL raw com decimal_sum e subquery correlacionada de valuation_rate mais recente; só linhas com saldo != 0; ignora SLE cancelado.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."},{"nome":"stock-ledger-report","objetivo":"Relatório detalhado de lançamentos no razão de estoque.","entradas":"Filtros opcionais: --item-id, --warehouse-id, --from-date, --to-date; --limit (default 100); --offset (default 0).","saidas":"entries[] (campos da SLE + item_code/item_name/warehouse_name), count.","regras":"Apenas SLE não cancelado, ordenado por posting_date desc e created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"status","objetivo":"Resumo de inventário (itens, depósitos, stock entries por status e valor total) de uma empresa.","entradas":"--company-id ou --company (nome) (via resolve_company_id).","saidas":"items, warehouses, stock_entries{draft,submitted,cancelled,total}, total_stock_value.","regras":"Conta itens (global), depósitos da empresa, stock entries agrupadas por status; soma stock_value_difference de SLE não cancelado via decimal_sum.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."},{"nome":"check-reorder","objetivo":"Lista itens cujo estoque atual está no nível de reposição ou abaixo.","entradas":"--company-id ou --company (nome) (via resolve_company_id).","saidas":"items_below_reorder, items[] (item, current_stock, reorder_level, reorder_qty, shortfall).","regras":"Considera só itens ativos com reorder_level definido (não vazio/!=0); soma estoque por todos depósitos da empresa via decimal_sum em SLE não cancelado; inclui item se current_stock <= reorder_level com shortfall calculado.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível; itens com reorder_level configurado."}]},{"group":"Lotes","objetivo":"Cadastro e listagem de lotes (batches) por item, com saldos por depósito.","acoes":[{"nome":"add-batch","objetivo":"Cria um lote vinculado a um item.","entradas":"--item-id (obrigatório); --batch-name (obrigatório); --manufacturing-date (opcional); --expiry-date (opcional).","saidas":"batch_id, batch_name.","regras":"Erra se item não existe; IntegrityError vira erro de duplicidade/inválido.","efeitos":"INSERT em batch; audit_log via audit('add-batch'); commit.","precondicoes":"Item existe."},{"nome":"list-batches","objetivo":"Lista lotes, opcionalmente filtrando por item e por estoque em um depósito.","entradas":"Filtros opcionais: --item-id, --warehouse-id; --limit (default 20); --offset (default 0).","saidas":"batches[], total_count, limit, offset, has_more.","regras":"Com --warehouse-id usa SQL raw com decimal_sum (HAVING saldo>0) sobre SLE não cancelado; sem warehouse lista direto da tabela batch ordenado por batch_name.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Números de Série","objetivo":"Registro e listagem de números de série de itens, com status de ciclo de vida.","acoes":[{"nome":"add-serial-number","objetivo":"Registra um número de série para um item.","entradas":"--item-id (obrigatório); --serial-no (obrigatório); --warehouse-id (opcional); --batch-id (opcional).","saidas":"serial_number_id, serial_no.","regras":"Erra se item não existe; status inicial 'active'; IntegrityError vira erro de duplicidade.","efeitos":"INSERT em serial_number (status='active'); audit_log via audit('add-serial-number'); commit.","precondicoes":"Item existe."},{"nome":"list-serial-numbers","objetivo":"Lista números de série com filtros e paginação.","entradas":"Filtros opcionais: --item-id, --warehouse-id, --serial-status (dest sn_status, valores active|delivered|returned|scrapped); --limit (default 20); --offset (default 0).","saidas":"serial_numbers[] (com item_code/item_name), total_count, limit, offset, has_more.","regras":"Valida sn_status contra VALID_SERIAL_STATUSES quando informado; ordena por serial_no.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Preços e Regras","objetivo":"Listas de preço, preços por item (com faixas/validade) e regras de precificação/desconto.","acoes":[{"nome":"add-price-list","objetivo":"Cria uma lista de preços (compra e/ou venda).","entradas":"--name (obrigatório); --currency (default 'USD'); --is-buying (default 0); --is-selling (default 0).","saidas":"price_list_id, name.","regras":"IntegrityError vira erro de duplicidade.","efeitos":"INSERT em price_list; audit_log via audit('add-price-list'); commit.","precondicoes":"Nenhuma."},{"nome":"add-item-price","objetivo":"Define um preço para um item em uma lista de preços.","entradas":"--item-id (obrigatório); --price-list-id (obrigatório); --rate (obrigatório); --min-qty (default 0); --valid-from (opcional); --valid-to (opcional).","saidas":"item_price_id, rate.","regras":"Erra se item ou price_list não existem; arredonda rate.","efeitos":"INSERT em item_price; audit_log via audit('add-item-price'); commit.","precondicoes":"Item e price_list existem."},{"nome":"get-item-price","objetivo":"Obtém o preço aplicável de um item em uma lista de preços para uma quantidade.","entradas":"--item-id (obrigatório); --price-list-id (obrigatório); --qty (default 1).","saidas":"Campos do item_price selecionado.","regras":"Busca melhor faixa válida por data e min_qty<=qty (ordem min_qty desc); fallback para preço mais recente ignorando data/qty; erra se nenhum preço encontrado.","efeitos":"nenhum (leitura).","precondicoes":"Existir item_price para item/lista."},{"nome":"add-pricing-rule","objetivo":"Cria uma regra de precificação/desconto por entidade.","entradas":"--name (obrigatório); --applies-to (obrigatório, item|item_group|customer|customer_group); --company-id (obrigatório); opcionais: --entity-id, --discount-percentage, --pricing-rule-rate (dest pr_rate), --min-qty, --max-qty, --valid-from, --valid-to, --priority (default 0).","saidas":"pricing_rule_id, name.","regras":"Valida applies_to contra valores permitidos; priority default 0.","efeitos":"INSERT em pricing_rule; audit_log via audit('add-pricing-rule'); commit.","precondicoes":"Empresa informada."}]},{"group":"Reconciliação","objetivo":"Reconciliação de estoque (contagem física) com ciclo rascunho/submit que ajusta SLE e GL pelas diferenças.","acoes":[{"nome":"add-stock-reconciliation","objetivo":"Cria uma reconciliação de estoque (contagem física) em rascunho.","entradas":"--posting-date (obrigatório); --items (obrigatório, JSON array com item_id, warehouse_id, qty, valuation_rate); --company-id (obrigatório).","saidas":"stock_reconciliation_id, naming_series, difference_amount, item_count.","regras":"Valida company; cada item exige item_id e warehouse_id; busca saldo atual via get_stock_balance; calcula quantity_difference e amount_difference (contado vs atual) e soma total.","efeitos":"INSERT em stock_reconciliation (status='draft', naming via get_next_name) e stock_reconciliation_item; audit_log via audit('add-stock-reconciliation'); commit. NÃO posta SLE/GL.","precondicoes":"Empresa existe; itens e depósitos referenciados existem."},{"nome":"submit-stock-reconciliation","objetivo":"Submete a reconciliação, postando SLE e GL para as diferenças de quantidade/valor.","entradas":"--stock-reconciliation-id (obrigatório).","saidas":"stock_reconciliation_id, sle_entries_created, gl_entries_created.","regras":"Erra se não existe ou status != 'draft'; erra se sem itens; cria SLE só para itens com quantity_difference != 0 (incoming_rate=valuation_rate se diff>0, senão 0); resolve fiscal_year, cost_center e conta stock_adjustment como contra; falha de SLE/GL aborta.","efeitos":"INSERT em stock_ledger_entry e gl_entry (create_perpetual_inventory_gl); UPDATE stock_reconciliation status='submitted'; audit_log via audit('submit-stock-reconciliation'); commit.","precondicoes":"Reconciliação em status 'draft' com itens; contas de inventário/ajuste configuradas."}]},{"group":"Revaloração","objetivo":"Revaloração de estoque (mudança de taxa sem alterar quantidade) com postagem imediata e ciclo submit/cancel.","acoes":[{"nome":"revalue-stock","objetivo":"Revaloriza o estoque de um item em um depósito alterando a taxa, sem mudar a quantidade.","entradas":"--item-id (obrigatório); --warehouse-id (obrigatório); --new-rate (obrigatório, >=0); --posting-date (obrigatório); --reason (opcional).","saidas":"revaluation_id, naming_series, item_id, item_name, warehouse, current_qty, old_rate, new_rate, adjustment_amount, gl_entries_created.","regras":"Valida new_rate numérico e não negativo; item deve existir e ser is_stock_item; warehouse deve existir; erra se qty<=0 ou se new_rate igual ao atual; calcula ajuste = novo_valor - valor_atual; GL: ajuste>0 DR Stock-in-Hand/CR Stock-Adjustment, ajuste<0 inverso; ação one-step (sem rascunho), grava status='submitted'.","efeitos":"INSERT em stock_ledger_entry (actual_qty=0, com stock_value_difference), gl_entry (insert_gl_entries) e stock_revaluation (status='submitted'); audit_log via audit('revalue-stock'); commit.","precondicoes":"Item de estoque com saldo>0 no depósito; contas stock e stock_adjustment configuradas para gerar GL."},{"nome":"list-stock-revaluations","objetivo":"Lista revalorações de estoque de uma empresa.","entradas":"--company-id ou --company (nome) (via resolve_company_id); --limit (default 20); --offset (default 0).","saidas":"revaluations[] (com item_code/item_name/warehouse_name), total_count, limit, offset, has_more.","regras":"Ordena por created_at desc; conta total da empresa.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível por id ou nome."},{"nome":"get-stock-revaluation","objetivo":"Retorna detalhes de uma revaloração incluindo seus SLE e GL.","entradas":"--revaluation-id (obrigatório).","saidas":"Campos da stock_revaluation + item/warehouse + sle_entries[] + gl_entries[].","regras":"Erra se não existe; busca SLE e GL pelo voucher_type='stock_revaluation' e voucher_id.","efeitos":"nenhum (leitura).","precondicoes":"Revaloração existe."},{"nome":"cancel-stock-revaluation","objetivo":"Cancela uma revaloração submetida, revertendo SLE e GL.","entradas":"--revaluation-id (obrigatório).","saidas":"revaluation_id, cancelled, item_id, warehouse_id.","regras":"Erra se não existe ou status != 'submitted'; reverte SLE e GL (ambos obrigatórios, falha aborta).","efeitos":"INSERT de SLE de reversão (reverse_sle_entries) e GL de reversão (reverse_gl_entries); UPDATE stock_revaluation status='cancelled'; audit_log via audit('cancel-stock-revaluation'); commit.","precondicoes":"Revaloração em status 'submitted'."}]},{"group":"Reposição/Projeção","objetivo":"Cálculo de quantidade projetada considerando estoque atual, pedidos de compra pendentes e vendas reservadas.","acoes":[{"nome":"get-projected-qty","objetivo":"Calcula a quantidade projetada de um item em um depósito (atual + a receber - reservado).","entradas":"--item-id (obrigatório); --warehouse-id (obrigatório).","saidas":"item_id, item_code, item_name, warehouse_id, actual_qty, ordered_qty, reserved_qty, projected_qty.","regras":"Erra se item ou warehouse não existem; actual_qty via get_stock_balance; ordered_qty soma (quantity-received_qty) de itens de PO confirmados/parcialmente recebidos; reserved_qty soma (quantity-delivered_qty) de itens de SO confirmados/parcialmente entregues; projected = actual + ordered - reserved.","efeitos":"nenhum (leitura).","precondicoes":"Item e depósito existem; tabelas purchase_order(_item) e sales_order(_item) presentes."}]},{"group":"Variantes","objetivo":"Definição de atributos de template e geração de variantes de item (single ou produto cartesiano).","acoes":[{"nome":"add-item-attribute","objetivo":"Adiciona uma definição de atributo a um item template, marcando-o como template.","entradas":"--item-id (obrigatório); --attribute-name (obrigatório); --attribute-values (obrigatório, JSON array).","saidas":"attribute_id, item_id, attribute_name, values.","regras":"Erra se item não existe ou é variante (variant_of setado); values deve ser array não vazio; erra se atributo já existe no item.","efeitos":"INSERT em item_attribute; UPDATE item has_variants=1 e updated_at; audit_log via audit('add-item-attribute'); commit.","precondicoes":"Item existe e não é variante."},{"nome":"create-item-variant","objetivo":"Cria uma única variante de item a partir de um template com valores de atributo específicos.","entradas":"--template-item-id (obrigatório); --attributes (obrigatório, JSON object).","saidas":"variant_id, item_code, item_name, template_item_id, attributes.","regras":"Erra se template não existe ou não tem has_variants; valida cada attr_name e valor contra definições do template; gera item_code/name por sufixo de valores; erra se variante duplicada.","efeitos":"INSERT em item (variant_of=template, status='active') e em item_attribute por atributo; audit_log via audit('create-item-variant'); commit.","precondicoes":"Item template com atributos definidos (has_variants=1)."},{"nome":"generate-item-variants","objetivo":"Gera todas as variantes possíveis de um template (produto cartesiano dos atributos).","entradas":"--template-item-id (obrigatório).","saidas":"template_item_id, created, skipped, skipped_codes[], variants[].","regras":"Erra se template não existe ou não é template ou sem atributos; erra se algum atributo sem valores; itertools.product das combinações; pula variantes cujo item_code já existe.","efeitos":"INSERT em item (variant_of, status='active') e item_attribute para cada combinação nova; commit. NÃO grava audit_log.","precondicoes":"Template com has_variants=1 e atributos com valores."},{"nome":"list-item-variants","objetivo":"Lista todas as variantes de um item template com seus atributos.","entradas":"--template-item-id (obrigatório).","saidas":"template_item_id, count, variants[] (variant_id, item_code, item_name, status, standard_rate, attributes).","regras":"Erra se template não existe; busca itens com variant_of=template e seus item_attribute.","efeitos":"nenhum (leitura).","precondicoes":"Item template existe."}]},{"group":"Fornecedores de Item","objetivo":"Vínculo entre itens e fornecedores com quantidade mínima de pedido, lead time e prioridade.","acoes":[{"nome":"add-item-supplier","objetivo":"Vincula um item a um fornecedor com qty mínima de pedido e lead time.","entradas":"--item-id (obrigatório); --supplier-id (obrigatório); --min-order-qty (default 0); --lead-time-days (opcional); --priority (default 0).","saidas":"item_supplier_id, item_id, supplier_id, min_order_qty, lead_time_days, priority.","regras":"Erra se item ou supplier não existem; arredonda min_order_qty; IntegrityError vira erro 'link já existe'.","efeitos":"INSERT em item_supplier; audit_log via audit('add-item-supplier'); commit.","precondicoes":"Item e fornecedor existem; tabela supplier presente."},{"nome":"list-item-suppliers","objetivo":"Lista fornecedores de um item ou itens de um fornecedor.","entradas":"Pelo menos um de --item-id ou --supplier-id (obrigatório).","saidas":"count, item_suppliers[] (com item_code/item_name/supplier_name).","regras":"Erra se nenhum dos dois filtros informado; ordena por priority.","efeitos":"nenhum (leitura).","precondicoes":"Tabelas item_supplier, item e supplier presentes."}]}]},"billing":{"module":"billing","display":"Faturamento por uso","functionalities":[{"group":"Medidores","objetivo":"Cadastrar, atualizar, consultar e listar medidores (meters) vinculados a clientes e planos de tarifa.","acoes":[{"nome":"add-meter","objetivo":"Registra um novo medidor para um cliente.","entradas":"--customer-id (obrigatório); --meter-type (obrigatório, deve estar em electricity/water/gas/telecom/saas/parking/rental/waste/custom); --rate-plan-id (opcional, validado se informado); --unit (opcional, vira metadata.uom); --name (opcional, gravado em service_point_id); --address (opcional, service_point_address); --install-date (opcional).","saidas":"meter: linha completa do medidor inserido (id, meter_number, customer_id, service_type, status, etc.).","regras":"Valida meter_type contra VALID_SERVICE_TYPES; exige cliente existente; valida rate_plan_id se informado; gera meter_number via get_next_name; status inicial fixado em 'active'.","efeitos":"INSERT em meter; conn.commit; audit_log via audit('add-meter'). Sem postagens contábeis.","precondicoes":"Cliente existente; tabela meter e (se usado) rate_plan."},{"nome":"update-meter","objetivo":"Atualiza configuração de um medidor existente.","entradas":"--meter-id (obrigatório); --name (opcional, atualiza service_point_id); --status (opcional, deve estar em active/disconnected/removed/suspended); --rate-plan-id (opcional, validado se informado).","saidas":"meter: linha completa atualizada.","regras":"Exige medidor existente; valida status contra VALID_METER_STATUSES; valida rate_plan_id se informado; erro 'No fields to update' se nenhum campo fornecido; sempre seta updated_at.","efeitos":"UPDATE em meter; conn.commit; audit_log via audit('update-meter') com old_values. Sem postagens contábeis.","precondicoes":"Medidor existente; rate plan existente se informado."},{"nome":"get-meter","objetivo":"Retorna um medidor com sua última leitura e contagem de leituras.","entradas":"--meter-id (obrigatório).","saidas":"meter: linha do medidor acrescida de latest_reading (última leitura por reading_date desc, ou null) e reading_count.","regras":"Exige medidor existente; leitura mais recente ordenada por reading_date desc limit 1.","efeitos":"nenhum (leitura).","precondicoes":"Medidor existente."},{"nome":"list-meters","objetivo":"Lista medidores com filtros opcionais e nome do cliente.","entradas":"--customer-id, --meter-type, --status (todos filtros opcionais); --limit (default 20), --offset (default 0).","saidas":"meters (com customer_name via left join), total_count, limit, offset, has_more.","regras":"Filtros aplicados em count e data query; ordena por created_at desc; paginação via limit/offset.","efeitos":"nenhum (leitura).","precondicoes":"Tabelas meter e customer."}]},{"group":"Leituras","objetivo":"Registrar leituras de medidor com cálculo automático de consumo e listar o histórico de leituras.","acoes":[{"nome":"add-meter-reading","objetivo":"Registra uma leitura de medidor calculando o consumo automaticamente.","entradas":"--meter-id (obrigatório); --reading-date (obrigatório); --reading-value (obrigatório); --reading-type (opcional, default 'actual', em actual/estimated/adjusted/rollover); --source (opcional, default 'manual', em manual/smart_meter/api/import/estimated); --uom (opcional, herda de metadata.uom do medidor).","saidas":"reading: linha completa da leitura inserida (consumption, previous_reading_value, reading_type, etc.).","regras":"Exige medidor existente; valida reading_type e source; consumption = reading_value - last_reading_value; se diff<0 trata rollover (consumption=reading_value e reading_type vira 'rollover' se era 'actual'); validated gravado como 0.","efeitos":"INSERT em meter_reading; UPDATE meter (last_reading_date, last_reading_value, updated_at); conn.commit; audit_log via audit('add-meter-reading'). Sem postagens contábeis.","precondicoes":"Medidor existente."},{"nome":"list-meter-readings","objetivo":"Lista leituras de um medidor com filtros de data opcionais.","entradas":"--meter-id (obrigatório); --from-date, --to-date (filtros opcionais sobre reading_date); --limit (default 20), --offset (default 0).","saidas":"readings, total_count, limit, offset, has_more.","regras":"Exige meter-id; aplica filtros de data; ordena por reading_date desc; paginação.","efeitos":"nenhum (leitura).","precondicoes":"Tabela meter_reading."}]},{"group":"Eventos de Uso","objetivo":"Ingerir eventos de consumo individuais ou em lote, com deduplicação por chave de idempotência.","acoes":[{"nome":"add-usage-event","objetivo":"Registra um único evento de uso para um medidor.","entradas":"--meter-id (obrigatório); --event-date (obrigatório, vira timestamp); --quantity (obrigatório); --event-type (opcional, default 'usage'); --properties (opcional, metadata); --idempotency-key (opcional, dedup).","saidas":"usage_event: linha completa do evento; se duplicado, retorna o evento existente com deduplicated=true.","regras":"Exige medidor existente; customer_id derivado do medidor; se idempotency_key já existir, retorna evento existente sem inserir (deduplicated); processed gravado como 0.","efeitos":"INSERT em usage_event (exceto quando deduplicado); conn.commit; audit_log via audit('add-usage-event'). Sem postagens contábeis.","precondicoes":"Medidor existente."},{"nome":"add-usage-events-batch","objetivo":"Ingere eventos de uso em massa a partir de um array JSON.","entradas":"--events (obrigatório, array JSON; cada item: meter_id, event_date, quantity obrigatórios, event_type default 'usage', idempotency_key e properties opcionais).","saidas":"inserted, duplicates, errors (lista com index/erro), total_processed.","regras":"Valida que --events é array não vazio; por item valida campos obrigatórios e existência do medidor (erros acumulados, não abortam o lote); pula duplicados por idempotency_key; processed=0.","efeitos":"INSERT em usage_event para cada item válido; um único conn.commit ao final. NÃO grava audit_log. Sem postagens contábeis.","precondicoes":"Medidores referenciados existentes; tabela usage_event."}]},{"group":"Planos de Tarifa","objetivo":"Criar, atualizar, consultar e listar planos de tarifa (rate plans) com suas faixas (tiers).","acoes":[{"nome":"add-rate-plan","objetivo":"Cria um plano de tarifa/preço com faixas opcionais.","entradas":"--name (obrigatório); --billing-model (obrigatório, em flat/tiered/time_of_use/demand/volume_discount/prepaid_credit/hybrid); --service-type, --base-charge, --base-charge-period (em monthly/quarterly/annually), --effective-from (default hoje), --effective-to, --minimum-charge, --minimum-commitment, --overage-rate (opcionais); --tiers (array JSON opcional).","saidas":"rate_plan: linha do plano com array tiers.","regras":"Valida billing_model contra VALID_PLAN_TYPES e base_charge_period; currency fixado em 'USD'; tiers inseridos com sort_order pela ordem do array; effective_from default = data atual.","efeitos":"INSERT em rate_plan e (se houver) rate_tier; conn.commit; audit_log via audit('add-rate-plan'). Sem postagens contábeis.","precondicoes":"Tabelas rate_plan e rate_tier."},{"nome":"update-rate-plan","objetivo":"Atualiza configuração e/ou faixas de um plano de tarifa.","entradas":"--rate-plan-id (obrigatório); --name, --base-charge, --effective-to, --minimum-charge, --overage-rate (opcionais); --tiers (array JSON opcional — substitui todas as faixas).","saidas":"rate_plan: linha atualizada com array tiers.","regras":"Exige plano existente; erro 'No fields to update' se nenhum campo nem tiers; se --tiers fornecido, DELETE todas as faixas e reinsere; seta updated_at quando há campos escalares.","efeitos":"UPDATE em rate_plan; DELETE+INSERT em rate_tier se --tiers; conn.commit; audit_log via audit('update-rate-plan') com old_values. Sem postagens contábeis.","precondicoes":"Plano de tarifa existente."},{"nome":"get-rate-plan","objetivo":"Retorna um plano de tarifa com suas faixas.","entradas":"--rate-plan-id (obrigatório).","saidas":"rate_plan: linha do plano com array tiers (ordenado por sort_order).","regras":"Exige plano existente.","efeitos":"nenhum (leitura).","precondicoes":"Plano de tarifa existente."},{"nome":"list-rate-plans","objetivo":"Lista planos de tarifa com filtro opcional por tipo de serviço.","entradas":"--service-type (filtro opcional); --limit (default 20), --offset (default 0).","saidas":"rate_plans, total_count, limit, offset, has_more.","regras":"Filtro por service_type; ordena por created_at desc; paginação.","efeitos":"nenhum (leitura).","precondicoes":"Tabela rate_plan."}]},{"group":"Cálculo de Tarifação","objetivo":"Calcular o valor cobrado para um consumo contra um plano de tarifa, sem persistir nada.","acoes":[{"nome":"rate-consumption","objetivo":"Calcula os encargos de um consumo contra um plano de tarifa (função pura).","entradas":"--rate-plan-id (obrigatório); --consumption (obrigatório).","saidas":"calculation: usage_charge, base_charge, total_charge, breakdown (por faixa), rate_plan_name, plan_type, consumption.","regras":"Exige plano existente; só suporta plan_type em flat/tiered/volume_discount (erro caso contrário); flat usa tiers[0]; tiered acumula por banda; volume_discount aplica a taxa da faixa correspondente; aplica minimum_charge se total < mínimo.","efeitos":"nenhum (leitura/cálculo, não persiste).","precondicoes":"Plano de tarifa existente com faixas compatíveis."}]},{"group":"Ciclos de Faturamento","objetivo":"Criar períodos de faturamento (billing periods), consultar e listar com totais e ajustes.","acoes":[{"nome":"create-billing-period","objetivo":"Cria um período de faturamento para um cliente/medidor.","entradas":"--customer-id (obrigatório); --meter-id (obrigatório); --from-date (obrigatório); --to-date (obrigatório); --rate-plan-id (opcional, senão usa o do medidor).","saidas":"billing_period: linha criada com totais zerados e status 'open'.","regras":"Exige cliente e medidor existentes; rate_plan_id = informado ou do medidor (erro se nenhum); valida plano; rejeita período sobreposto (mesmo meter, status != void, datas que se cruzam); status inicial 'open' e todos os valores em '0'.","efeitos":"INSERT em billing_period; conn.commit; audit_log via audit('create-billing-period'). Sem postagens contábeis.","precondicoes":"Cliente, medidor e plano de tarifa existentes; nenhum período sobreposto."},{"nome":"list-billing-periods","objetivo":"Lista períodos de faturamento com filtros opcionais.","entradas":"--customer-id, --meter-id, --status, --from-date (sobre period_start), --to-date (sobre period_end) (filtros opcionais); --limit (default 20), --offset (default 0).","saidas":"billing_periods (com customer_name e meter_number), total_count, limit, offset, has_more.","regras":"Aplica filtros em count e data; ordena por created_at desc; paginação.","efeitos":"nenhum (leitura).","precondicoes":"Tabelas billing_period, customer, meter."},{"nome":"get-billing-period","objetivo":"Retorna um período de faturamento com seus ajustes.","entradas":"--billing-period-id (obrigatório).","saidas":"billing_period: linha (com customer_name, meter_number, rate_plan_name) e array adjustments.","regras":"Exige período existente; ajustes ordenados por created_at.","efeitos":"nenhum (leitura).","precondicoes":"Período de faturamento existente."}]},{"group":"Bill Run","objetivo":"Executar o processo de faturamento em lote (agregar consumo, tarifar, criar/atualizar períodos) e gerar faturas a partir de períodos tarifados.","acoes":[{"nome":"run-billing","objetivo":"Executa o bill run: agrega consumo, tarifa e cria/atualiza períodos para todos os medidores ativos da empresa.","entradas":"--company-id (obrigatório); --billing-date (obrigatório); --from-date (opcional, default billing-date menos 30 dias); --to-date (opcional, default billing-date).","saidas":"periods_created, period_ids, total_billed (arredondado).","regras":"Exige empresa existente; processa medidores 'active' com rate_plan_id; pula medidores já com período 'rated'/'invoiced'/'paid'; só tarifa plan_type suportado (flat/tiered/volume_discount); soma consumo de meter_reading e de usage_event não processados na janela; cria período novo ou atualiza período 'open' existente para status 'rated'.","efeitos":"INSERT ou UPDATE em billing_period (status -> 'rated', seta rated_at); UPDATE em usage_event (processed=1, billing_period_id); conn.commit; audit_log via audit('run-billing'). Sem postagens contábeis.","precondicoes":"Empresa existente com clientes, medidores ativos com plano e leituras/eventos na janela."},{"nome":"generate-invoices","objetivo":"Cria faturas de venda a partir de períodos de faturamento tarifados.","entradas":"--billing-period-ids (obrigatório, array JSON de IDs).","saidas":"invoiced (contagem), results (por período: billing_period_id, invoice_id, status ou error).","regras":"Valida array JSON; processa só períodos com status 'rated' (senão registra erro); cria sales_invoice chamando o script de selling via subprocess se a tabela sales_invoice existir (best-effort, invoice_id pode ficar null); sempre marca o período como 'invoiced'.","efeitos":"Subprocess opcional para selling (add-sales-invoice) que pode inserir sales_invoice/gl_entry no outro skill; UPDATE em billing_period (status -> 'invoiced', invoiced_at, invoice_id); conn.commit. NÃO grava audit_log próprio.","precondicoes":"Períodos de faturamento com status 'rated'; opcionalmente skill selling instalado para a fatura real."}]},{"group":"Ajustes","objetivo":"Adicionar ajustes (crédito, multa, desconto, etc.) a um período de faturamento e recalcular seus totais.","acoes":[{"nome":"add-billing-adjustment","objetivo":"Adiciona um ajuste a um período de faturamento e recalcula os totais.","entradas":"--billing-period-id (obrigatório); --amount (obrigatório); --adjustment-type (obrigatório, em credit/late_fee/deposit/refund/proration/discount/penalty/write_off); --reason, --approved-by (opcionais).","saidas":"adjustment: linha do ajuste inserido acrescida de updated_grand_total.","regras":"Valida adjustment_type contra VALID_ADJUSTMENT_TYPES; exige período existente; recalcula adjustments_total (soma via DecimalSum), subtotal = base+usage+adj_total, grand_total = subtotal+tax.","efeitos":"INSERT em billing_adjustment; UPDATE em billing_period (adjustments_total, subtotal, grand_total, updated_at); conn.commit; audit_log via audit('add-billing-adjustment'). Sem postagens contábeis.","precondicoes":"Período de faturamento existente."}]},{"group":"Créditos Pré-pagos","objetivo":"Registrar compromissos pré-pagos (prepaid credits) e consultar o saldo remanescente do cliente.","acoes":[{"nome":"add-prepaid-credit","objetivo":"Registra um compromisso/saldo pré-pago para um cliente.","entradas":"--customer-id (obrigatório); --amount (obrigatório); --valid-until (obrigatório, vira period_end); --rate-plan-id (opcional; senão usa um plano prepaid_credit ou o primeiro disponível).","saidas":"prepaid_credit: linha inserida (original_amount, remaining_amount, status 'active', etc.).","regras":"Exige cliente existente; resolve rate_plan_id (informado, ou primeiro plano prepaid_credit, ou primeiro plano; erro se nenhum existir); period_start = data atual; remaining_amount = original_amount; overage_amount '0'; status 'active'.","efeitos":"INSERT em prepaid_credit_balance; conn.commit; audit_log via audit('add-prepaid-credit'). Sem postagens contábeis.","precondicoes":"Cliente existente; pelo menos um rate plan existente."},{"nome":"get-prepaid-balance","objetivo":"Consulta os créditos pré-pagos remanescentes de um cliente.","entradas":"--customer-id (obrigatório).","saidas":"customer_id, active_credits, total_remaining (soma dos status 'active', arredondado), balances (todos os registros).","regras":"Exige customer-id; soma remaining_amount apenas dos saldos com status 'active'; lista ordenada por created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Tabela prepaid_credit_balance."}]},{"group":"Status","objetivo":"Fornecer um resumo geral do estado do faturamento (medidores, períodos, eventos, planos, pré-pagos).","acoes":[{"nome":"status","objetivo":"Retorna um resumo do faturamento, opcionalmente filtrado por empresa.","entradas":"--company-id (opcional; se informado, valida empresa e restringe contagens aos clientes dela).","saidas":"meters (contagem por status), meters_total, billing_periods (por status), billing_periods_total, rate_plans_total, unprocessed_events, prepaid_balances.","regras":"Se company-id, exige empresa existente e filtra por seus customer_ids (IN dinâmico); conta medidores por status, períodos por status, eventos não processados (processed=0), planos e saldos pré-pagos.","efeitos":"nenhum (leitura).","precondicoes":"Tabelas meter, billing_period, usage_event, rate_plan, prepaid_credit_balance; empresa existente se filtrada."}]}]},"tax":{"module":"tax","display":"Impostos","functionalities":[{"group":"Modelos","objetivo":"Gerenciar modelos de imposto (tax_template) e suas linhas de alíquota (CRUD completo).","acoes":[{"nome":"add-tax-template","objetivo":"Cria um modelo de imposto com suas linhas de alíquota para uma empresa.","entradas":"--name (obrigatório); --tax-type (obrigatório: sales|purchase|both); --company-id (obrigatório); --lines JSON array (obrigatório, cada linha exige tax_account_id e rate; opcionais charge_type [def on_net_total], add_deduct [def add], row_order [def índice], included_in_print_rate, description); --is-default (flag, default None).","saidas":"status='created', tax_template_id, name, line_count.","regras":"Valida tax_type contra VALID_TAX_TYPES; verifica que a empresa existe; valida cada linha (rate decimal, charge_type em VALID_CHARGE_TYPES, add_deduct em add/deduct) e que cada tax_account_id existe; se --is-default, zera is_default de outros templates do mesmo company com tax_type igual ou 'both'. Sem ciclo submit/cancel.","efeitos":"INSERT em tax_template e tax_template_line; possível UPDATE is_default=0 em tax_template; grava audit_log via audit(); commit.","precondicoes":"Empresa existente e contas (account) das linhas existentes."},{"nome":"update-tax-template","objetivo":"Atualiza nome, flag de padrão e/ou substitui as linhas de um modelo existente.","entradas":"--tax-template-id (obrigatório); --name (opcional); --is-default (flag, default None); --lines JSON array (opcional; substitui todas as linhas).","saidas":"status='updated', tax_template_id, updated_fields (lista).","regras":"Erro se template não existe; se is_default=true zera is_default dos demais templates do mesmo company/tax_type(ou both) exceto o próprio; se --lines informado, revalida linhas e contas, apaga linhas antigas e reinsere; erro 'No fields to update' se nada mudou; seta updated_at via dynamic_update.","efeitos":"UPDATE em tax_template (campos + updated_at); possível UPDATE is_default=0 nos demais; DELETE+INSERT em tax_template_line se --lines; grava audit_log; commit.","precondicoes":"Modelo existente; contas das novas linhas existentes."},{"nome":"get-tax-template","objetivo":"Retorna um modelo de imposto com suas linhas e nomes das contas.","entradas":"--tax-template-id (obrigatório).","saidas":"Campos do tax_template (star) mais lines[] (linhas com account_name, ordenadas por row_order).","regras":"Erro se template não encontrado. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Modelo existente."},{"nome":"list-tax-templates","objetivo":"Lista modelos de imposto de uma empresa com paginação.","entradas":"--company-id ou --company (nome) resolvidos por resolve_company_id; --tax-type (opcional, filtra por tax_type igual ou 'both'); --limit (def 20); --offset (def 0).","saidas":"templates[], total_count, limit, offset, has_more.","regras":"Resolve company; aplica filtro opcional de tax_type; ordena por name. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível."},{"nome":"delete-tax-template","objetivo":"Exclui um modelo de imposto e suas linhas se não estiver referenciado.","entradas":"--tax-template-id (obrigatório).","saidas":"deleted=True.","regras":"Erro se não existe; erro se referenciado por tax_rule (cnt>0) ou por item_tax_template (cnt>0). Exclusão definitiva (sem cancelamento lógico).","efeitos":"DELETE em tax_template_line e em tax_template; grava audit_log; commit.","precondicoes":"Modelo existente e sem referências em tax_rule nem item_tax_template."}]},{"group":"Categorias","objetivo":"Gerenciar categorias de imposto (tax_category) usadas como filtro em regras.","acoes":[{"nome":"add-tax-category","objetivo":"Cria uma categoria de imposto com nome e descrição opcional.","entradas":"--name (obrigatório); --description (opcional, default '').","saidas":"status='created', tax_category_id, name.","regras":"Erro se --name ausente. Sem validações adicionais nem ciclo de status.","efeitos":"INSERT em tax_category; grava audit_log; commit.","precondicoes":"Nenhuma específica."},{"nome":"list-tax-categories","objetivo":"Lista todas as categorias de imposto com paginação.","entradas":"--limit (def 20); --offset (def 0).","saidas":"categories[], total_count, limit, offset, has_more.","regras":"Sem filtro por empresa (tax_category é global); ordena por name. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Regras","objetivo":"Gerenciar regras (tax_rule) que mapeiam filtros de parte/estado/categoria para um modelo de imposto.","acoes":[{"nome":"add-tax-rule","objetivo":"Cria uma regra que associa filtros a um modelo de imposto com prioridade.","entradas":"--tax-template-id (obrigatório); --tax-type (obrigatório: sales|purchase); --priority int (obrigatório); ao menos um filtro: --customer-id, --customer-group, --supplier-id, --shipping-state ou --tax-category-id.","saidas":"status='created', tax_rule_id.","regras":"Erro se tax_type não for sales/purchase; erro se priority ausente; erro se template não existe; erro se nenhum filtro informado. supplier_group é gravado como None; company_id herdado do template.","efeitos":"INSERT em tax_rule; grava audit_log; commit.","precondicoes":"Modelo de imposto existente."},{"nome":"list-tax-rules","objetivo":"Lista as regras de imposto de uma empresa com o nome do modelo associado.","entradas":"--company-id ou --company (nome); --limit (def 20); --offset (def 0).","saidas":"rules[] (campos da regra + template_name), total_count, limit, offset, has_more.","regras":"Resolve company; ordena por priority e depois created_at. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível."}]},{"group":"Resolução","objetivo":"Selecionar automaticamente o modelo de imposto aplicável a uma parte/transação avaliando as regras por prioridade.","acoes":[{"nome":"resolve-tax-template","objetivo":"Determina o modelo de imposto para uma parte casando regras na ordem de prioridade, com fallback no padrão da empresa.","entradas":"--party-type (obrigatório, deve estar em party_type_registry); --party-id (obrigatório); --company-id ou --company; --transaction-type (opcional; default sales p/ customer, purchase p/ supplier, senão sales); --tax-category-id (opcional); --shipping-address JSON (opcional, usa campo state).","saidas":"tax_template_id, template_name, is_exempt, item_overrides[].","regras":"Valida party_type contra registro; para customer marca is_exempt se exempt_from_sales_tax; itera regras (tax_type igual ou template 'both') por priority asc casando customer_id, customer_group, supplier_id, shipping_state e tax_category_id; primeira regra casada vence; sem match cai no template is_default da empresa; coleta item_tax_template cujo template difere do escolhido. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"party_type registrado em party_type_registry; empresa resolvível; regras/template padrão cadastrados para haver resultado."}]},{"group":"Cálculo","objetivo":"Calcular impostos sobre itens a partir das linhas de um modelo, sem persistência.","acoes":[{"nome":"calculate-tax","objetivo":"Calcula impostos em cascata por linha do modelo e distribui proporcionalmente por item.","entradas":"--tax-template-id (obrigatório); --items JSON array (obrigatório; cada item com item_id, net_amount, opcional qty); --item-overrides JSON (opcional; item_id->override_template_id, itens sobrepostos não recebem rateio).","saidas":"tax_lines[] (tax_account_id, account_name, description, rate, amount), total_tax, net_total, grand_total, per_item_tax[].","regras":"Erro se sem template ou sem linhas; soma net_total; por linha aplica base conforme charge_type (on_net_total, on_previous_row_total, on_previous_row_amount, actual [rate vira valor], on_item_quantity [soma qty]); 'actual' usa valor direto, demais base*rate/100; add_deduct=deduct nega o valor; rateio proporcional ao net_amount do item; arredonda via round_currency. Cálculo puro.","efeitos":"nenhum (leitura).","precondicoes":"Modelo com linhas (tax_template_line) cadastradas."}]},{"group":"Impostos por Item","objetivo":"Definir sobreposições de modelo de imposto por item (item_tax_template).","acoes":[{"nome":"add-item-tax-template","objetivo":"Associa um item a um modelo de imposto (override por item) com alíquota opcional.","entradas":"--item-id (obrigatório); --tax-template-id (obrigatório); --tax-rate (opcional).","saidas":"status='created', item_tax_template_id.","regras":"Erro se item-id ou tax-template-id ausentes; erro se template não existe. Sem verificação de existência do item nem ciclo de status.","efeitos":"INSERT em item_tax_template; grava audit_log; commit.","precondicoes":"Modelo de imposto existente."}]},{"group":"Retenção na Fonte","objetivo":"Configurar categorias de retenção e registrar entradas de imposto retido (tax_withholding_category/group/entry).","acoes":[{"nome":"add-tax-withholding-category","objetivo":"Cria uma categoria de retenção (e um grupo padrão com a alíquota) vinculada ao tipo de formulário.","entradas":"--name (obrigatório); --rate (obrigatório, decimal); --threshold-amount (obrigatório, decimal); --form-type (obrigatório: 1099-NEC|1099-MISC); --company-id (obrigatório).","saidas":"status='created', category_id, name.","regras":"Valida form-type em VALID_FORM_TYPES; valida rate e threshold como decimais; grava form_type em category_code e threshold em cumulative_threshold; busca primeira conta tax/payable da empresa para o grupo (group 'Default', effective_from 2020-01-01); grupo só é criado se houver conta de retenção.","efeitos":"INSERT em tax_withholding_category e (condicional) tax_withholding_group; grava audit_log; commit.","precondicoes":"Empresa existente; idealmente uma conta com account_type tax/payable para criar o grupo."},{"nome":"get-withholding-details","objetivo":"Agrega informação de retenção de um fornecedor em um ano fiscal (YTD, limite, backup withholding).","entradas":"--supplier-id (obrigatório); --tax-year (obrigatório); --company-id ou --company.","saidas":"is_1099_vendor, withholding_category, ytd_payments, threshold_exceeded, withholding_rate, backup_withholding_rate, w9_on_file, withholding_amount.","regras":"Erro se fornecedor não existe; lê categoria do fornecedor e a alíquota do grupo mais recente (effective_from desc); soma taxable_amount em tax_withholding_entry no ano; threshold_exceeded se ytd>=cumulative_threshold; backup rate=24% se 1099 e sem W9, aplicado sobre o YTD. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Fornecedor existente; empresa resolvível."},{"nome":"record-withholding-entry","objetivo":"Registra uma entrada de imposto retido (withheld_amount) de um fornecedor para um voucher.","entradas":"--supplier-id (obrigatório); --voucher-type (obrigatório); --voucher-id (obrigatório); --withholding-amount (obrigatório); --tax-year (obrigatório).","saidas":"status='created', withholding_entry_id.","regras":"Normaliza voucher_type via canonical_voucher_type (FINDING-006); erro se fornecedor não existe; erro se fornecedor sem tax_withholding_category_id; grava taxable_amount=0 e withheld_amount=withholding-amount em withholding_voucher_type/id.","efeitos":"INSERT em tax_withholding_entry; grava audit_log; commit. Não posta em gl_entry/PLE.","precondicoes":"Fornecedor existente com categoria de retenção atribuída."}]},{"group":"Relatórios 1099","objetivo":"Registrar pagamentos elegíveis a 1099 e gerar os dados consolidados de 1099 por fornecedor.","acoes":[{"nome":"record-1099-payment","objetivo":"Registra um pagamento tributável (taxable_amount) elegível a 1099 para um fornecedor e retorna o total YTD.","entradas":"--supplier-id (obrigatório); --amount (obrigatório, mapeado para ple_amount); --tax-year (obrigatório); --voucher-type (obrigatório); --voucher-id (obrigatório).","saidas":"status='created', ytd_1099_total.","regras":"Normaliza voucher_type via canonical_voucher_type; erro se fornecedor não existe; erro se sem tax_withholding_category_id; grava taxable_amount=amount e withheld_amount=0 em taxable_voucher_type/id; recalcula soma YTD de taxable_amount.","efeitos":"INSERT em tax_withholding_entry; grava audit_log; commit. Não posta em gl_entry/PLE.","precondicoes":"Fornecedor existente com categoria de retenção atribuída."},{"nome":"generate-1099-data","objetivo":"Gera a lista de fornecedores e valores para emissão de 1099 no ano fiscal, aplicando o limite por categoria.","entradas":"--tax-year (obrigatório); --company-id ou --company.","saidas":"vendors[] (supplier_id, name, tin, total_paid, form_type, box_1).","regras":"Soma taxable_amount por party_id/category das entries do ano cujas categorias pertencem à empresa; ignora fornecedores abaixo do cumulative_threshold da categoria; form_type vem de category_code (default 1099-NEC); box_1 = total se 1099-NEC senão 0.00. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível; entradas em tax_withholding_entry para o ano."}]},{"group":"Status","objetivo":"Resumir contagens de configuração de imposto e fornecedores 1099 do ano corrente para a empresa.","acoes":[{"nome":"status","objetivo":"Retorna contagens de modelos, regras, categorias de retenção e fornecedores 1099 do ano atual.","entradas":"--company-id ou --company (resolvidos por resolve_company_id).","saidas":"templates, rules, withholding_categories, ytd_1099_vendors.","regras":"Conta tax_template, tax_rule e tax_withholding_category da empresa; conta party_id distintos em tax_withholding_entry do ano UTC atual cujas categorias são da empresa. Somente leitura.","efeitos":"nenhum (leitura).","precondicoes":"Empresa resolvível."}]}]},"payments":{"module":"payments","display":"Pagamentos","functionalities":[{"group":"Cadastro","objetivo":"Criar e editar lançamentos de pagamento (payment_entry) em rascunho, incluindo suas alocações iniciais.","acoes":[{"nome":"add-payment","objetivo":"Cria um novo lançamento de pagamento em status draft (receive, pay ou internal_transfer).","entradas":"--company-id (obrigatório), --payment-type (obrigatório: receive|pay|internal_transfer), --posting-date (obrigatório), --party-type (obrigatório salvo internal_transfer; deve estar registrado em party_type_registry), --party-id (obrigatório salvo internal_transfer), --paid-from-account (obrigatório), --paid-to-account (obrigatório), --paid-amount (obrigatório, >0), --payment-currency (default USD), --exchange-rate (default 1), --reference-number, --reference-date, --allocations (JSON opcional).","saidas":"status='created', payment_entry_id, naming_series.","regras":"Valida company existente; valida que ambas as contas existem e não são group (auto-resolve para filha-folha única, senão erro); paid_amount convertido com round_currency e deve ser >0; received_amount = paid_amount*exchange_rate; --allocations malformado gera erro JSON. Cria sempre em status 'draft' com unallocated_amount = paid_amount (recalculado se houver alocações).","efeitos":"Escreve em payment_entry (1 linha, status draft); insere linhas em payment_allocation se --allocations; recalcula unallocated_amount; grava audit_log (add-payment). Nenhuma postagem em gl_entry/PLE. conn.commit().","precondicoes":"Company, contas paid-from/paid-to e (se aplicável) party_type registrado e party devem existir."},{"nome":"update-payment","objetivo":"Atualiza campos editáveis (valor, número de referência, alocações) de um pagamento ainda em draft.","entradas":"--payment-entry-id (obrigatório); opcionais --paid-amount (>0), --reference-number, --allocations (JSON).","saidas":"status='updated', payment_entry_id, updated_fields (lista dos campos alterados).","regras":"Erro se pagamento não está em 'draft' (sugere cancelar primeiro). Se --paid-amount: recalcula received_amount = amount*exchange_rate existente. --allocations substitui (DELETE + reinsert) e recalcula unallocated. Erro 'No fields to update' se nada informado; JSON de alocações inválido gera erro.","efeitos":"UPDATE em payment_entry (paid_amount/received_amount/reference_number); DELETE+INSERT em payment_allocation; recalcula unallocated_amount; grava audit_log (update-payment) com old/new values. conn.commit(). Nenhuma postagem em gl_entry/PLE.","precondicoes":"Payment entry existente em status 'draft'."}]},{"group":"Listagem","objetivo":"Consultas de leitura de pagamentos: detalhe individual e listagem filtrada/paginada.","acoes":[{"nome":"get-payment","objetivo":"Retorna um lançamento de pagamento completo com suas alocações.","entradas":"--payment-entry-id (obrigatório).","saidas":"id, naming_series, payment_type, posting_date, party_type, party_id, paid_from_account, paid_to_account, paid_amount, received_amount, payment_currency, exchange_rate, reference_number, reference_date, status, unallocated_amount, company_id, allocations[] (id, voucher_type, voucher_id, allocated_amount, exchange_gain_loss).","regras":"Erro se payment_entry não encontrado (sugere 'list payments'). Alocações ordenadas por created_at depois id.","efeitos":"nenhum (leitura).","precondicoes":"Payment entry existente."},{"nome":"list-payments","objetivo":"Lista lançamentos de pagamento de uma empresa com filtros e paginação.","entradas":"--company-id ou --company (nome) para resolver empresa; filtros opcionais --payment-type, --party-type, --party-id, --status (pe_status), --from-date, --to-date; --limit (default 20), --offset (default 0).","saidas":"payments[] (id, naming_series, payment_type, posting_date, party_type, party_id, paid_amount, status, unallocated_amount, party_name resolvido), total_count, limit, offset, has_more.","regras":"company_id resolvido via resolve_company_id (id ou nome). party_name obtido por subconsulta CASE em customer/supplier/employee. Ordena por posting_date desc, created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Empresa identificável por id ou nome."}]},{"group":"Ciclo de Vida","objetivo":"Transições draft→submit→cancel e exclusão de rascunhos, com postagens e reversões contábeis.","acoes":[{"nome":"submit-payment","objetivo":"Submete um pagamento draft: posta GL, cria PLE, aplica desconto por pagamento antecipado e liquida faturas alocadas.","entradas":"--payment-entry-id (obrigatório).","saidas":"status='submitted', payment_entry_id, gl_entries_created, documents_cleared, outstanding_updated (bool); opcional early_payment_discount{discount_amount,bank_amount,details}; opcional exchange_gain_loss.","regras":"Erro se status != 'draft'. Re-valida contas não-group (auto-resolve+update). Exige currency da fatura == payment_currency (senão erro de mismatch). Calcula desconto antecipado via payment_terms (discount_percentage/discount_days) dentro da janela. Monta GL: receive DR paid_to/CR paid_from; pay DR paid_to/CR paid_from; internal_transfer banco-a-banco; com desconto adiciona leg na conta de desconto. Roteia porção de adiantamento (unallocated) para sub-conta de advance se configurada. Branch FX dormente (rate==1 garantido). Falha de GL ou de clearing faz rollback e erro; se nomeou alocações de fatura mas nenhuma liquidou, rollback e erro.","efeitos":"INSERT em gl_entry (via insert_gl_entries, voucher_type=payment_entry); INSERT em payment_ledger_entry (PLE party-level -paid_amount) e PLE por-alocação (-allocated, INV-22); UPDATE payment_entry.status='submitted' e advance_account_id se roteado; UPDATE em sales_invoice/purchase_invoice (outstanding/status via apply_payment_to_document); possível UPDATE payment_allocation.exchange_gain_loss; audit_log (submit-payment). conn.commit().","precondicoes":"Payment entry em 'draft'; contas válidas; moeda da fatura igual à do pagamento."},{"nome":"cancel-payment","objetivo":"Cancela um pagamento submetido: reverte GL, desfaz liquidação das faturas e reverte PLE.","entradas":"--payment-entry-id (obrigatório).","saidas":"status='cancelled', payment_entry_id, reversed=true.","regras":"Erro se status != 'submitted'. Reverte GL via reverse_gl_entries (erro de reversão aborta). Para cada alocação de fatura, restaura outstanding/status via reverse_payment_on_document (lê grand_total). Seleciona todas as PLE não-delinked do pagamento (party-level + por-alocação) e cria linhas estornantes.","efeitos":"INSERT de gl_entry de reversão; UPDATE payment_ledger_entry.delinked=1 nas linhas originais + INSERT de PLE estornantes (valor negado, preservando against_voucher); UPDATE em sales_invoice/purchase_invoice (outstanding/status); UPDATE payment_entry.status='cancelled'; audit_log (cancel-payment). conn.commit().","precondicoes":"Payment entry em 'submitted'."},{"nome":"delete-payment","objetivo":"Exclui fisicamente um pagamento que ainda está em draft.","entradas":"--payment-entry-id (obrigatório).","saidas":"status='deleted', deleted=true.","regras":"Erro se status != 'draft' (somente drafts; sugere cancelar primeiro). Remove dependências antes do registro principal.","efeitos":"DELETE em payment_allocation, payment_deduction e payment_entry do registro; audit_log (delete-payment) com old_values. conn.commit(). Nenhuma postagem em gl_entry/PLE.","precondicoes":"Payment entry existente em status 'draft'."}]},{"group":"Alocação a Faturas","objetivo":"Alocar um pagamento submetido a uma fatura específica, liquidando o documento e gerando PLE de offset.","acoes":[{"nome":"allocate-payment","objetivo":"Aloca parte do valor não-alocado de um pagamento submetido a um voucher (fatura), liquidando-o.","entradas":"--payment-entry-id (obrigatório), --voucher-type (obrigatório; canonicalizado), --voucher-id (obrigatório), --allocated-amount (obrigatório, >0).","saidas":"status='created', allocation_id, document_cleared (bool), remaining_unallocated.","regras":"Erro se pagamento != 'submitted'. amount deve ser >0 e <= unallocated_amount (senão erro de excesso). Insere alocação e recalcula unallocated. Se advance_account_id setado, posta GL de reclassificação (receive: DR advance/CR AR; pay: DR AP/CR advance). Liquida a fatura via _clear_invoice_allocation; voucher de tipo fatura que não liquida nada gera rollback+erro; tipos advance/on-account liquidam nada legitimamente.","efeitos":"INSERT em payment_allocation; UPDATE payment_entry.unallocated_amount; possível INSERT em gl_entry (reclassificação de adiantamento, entry_set=advance_alloc_*); INSERT PLE por-alocação (INV-22) e UPDATE em sales_invoice/purchase_invoice via apply_payment_to_document; audit_log (allocate-payment). conn.commit().","precondicoes":"Payment entry em 'submitted' com unallocated suficiente; voucher/fatura existente."},{"nome":"apply-advance-to-invoice","objetivo":"Alias de vocabulário (SAP B1) para allocate-payment: aplica um adiantamento a uma fatura.","entradas":"Idêntico a allocate-payment: --payment-entry-id, --voucher-type, --voucher-id, --allocated-amount (todos obrigatórios).","saidas":"Idêntico a allocate-payment: status='created', allocation_id, document_cleared, remaining_unallocated.","regras":"Mapeia exatamente para a função allocate_payment (mesmas validações e ciclo); apenas o nome no dispatch difere.","efeitos":"Idêntico a allocate-payment: payment_allocation, payment_entry, gl_entry (reclass de adiantamento), PLE por-alocação, sales_invoice/purchase_invoice, audit_log (allocate-payment). conn.commit().","precondicoes":"Mesmas de allocate-payment: pagamento 'submitted' com unallocated e fatura existente."}]},{"group":"Adiantamentos","objetivo":"Consultar pagamentos com saldo não-alocado (adiantamentos em aberto) por parceiro.","acoes":[{"nome":"get-unallocated-payments","objetivo":"Lista pagamentos submetidos de um parceiro que ainda têm valor não-alocado (>0).","entradas":"--party-type (obrigatório), --party-id (obrigatório); --company-id ou --company para resolver empresa.","saidas":"payments[] (id, naming_series, paid_amount, unallocated_amount, posting_date).","regras":"Filtra status='submitted' e unallocated_amount numérico >0; ordena por posting_date. company_id resolvido por id/nome.","efeitos":"nenhum (leitura).","precondicoes":"Parceiro e empresa identificáveis."},{"nome":"list-open-advances","objetivo":"Alias de vocabulário (SAP B1) para get-unallocated-payments: lista adiantamentos em aberto.","entradas":"Idêntico a get-unallocated-payments: --party-type, --party-id (obrigatórios), --company-id/--company.","saidas":"Idêntico a get-unallocated-payments: payments[] (id, naming_series, paid_amount, unallocated_amount, posting_date).","regras":"Mapeia exatamente para get_unallocated_payments; apenas o nome no dispatch difere.","efeitos":"nenhum (leitura).","precondicoes":"Mesmas de get-unallocated-payments."}]},{"group":"Razão de Pagamentos (PLE)","objetivo":"Manter e consultar o subledger payment_ledger_entry e os saldos em aberto por parceiro/voucher.","acoes":[{"nome":"create-payment-ledger-entry","objetivo":"Cria uma linha de payment_ledger_entry, usada cross-skill por selling/buying na submissão de faturas.","entradas":"--voucher-type (obrigatório; canonicalizado), --voucher-id (obrigatório), --party-type (obrigatório; registrado), --party-id (obrigatório), --amount (obrigatório), --posting-date (obrigatório), --account-id (obrigatório); opcionais --against-voucher-type (canonicalizado), --against-voucher-id.","saidas":"status='created', ple_id.","regras":"voucher_type e against_voucher_type canonicalizados para snake_case; party_type deve estar registrado; amount arredondado via round_currency; currency gravada como 'USD'.","efeitos":"INSERT em payment_ledger_entry (1 linha); audit_log (create-payment-ledger-entry). conn.commit(). Nenhuma postagem em gl_entry.","precondicoes":"Conta, party_type registrado e party válidos."},{"nome":"get-outstanding","objetivo":"Retorna saldos em aberto de um parceiro agregados por voucher a partir do PLE.","entradas":"--party-type (obrigatório), --party-id (obrigatório); filtros opcionais --voucher-type (canonicalizado), --voucher-id.","saidas":"outstanding (total), vouchers[] (voucher_type, voucher_id, outstanding_amount, posting_date).","regras":"Considera apenas PLE delinked=0; soma amount agrupado por voucher; descarta saldos líquidos zero (HAVING != 0); ordena por posting_date. voucher_type filtrado é canonicalizado.","efeitos":"nenhum (leitura).","precondicoes":"Parceiro existente; PLE registradas."}]},{"group":"Conciliação","objetivo":"Conciliar automaticamente (FIFO) pagamentos não-alocados contra faturas em aberto de um parceiro.","acoes":[{"nome":"reconcile-payments","objetivo":"Concilia em FIFO os pagamentos submetidos não-alocados de um parceiro contra suas faturas em aberto.","entradas":"--party-type (obrigatório), --party-id (obrigatório), --company-id (obrigatório).","saidas":"matched[] (payment_id, voucher_id, allocated_amount), unmatched_payments (contagem), unmatched_invoices (contagem).","regras":"Pagamentos: status='submitted' e unallocated>0, ordenados FIFO (posting_date, created_at). Faturas: PLE delinked=0 de sales_invoice/purchase_invoice com saldo>0, FIFO por MIN(posting_date). Casa o menor entre saldo do pagamento e da fatura; cada match deve liquidar documento (False gera rollback+erro). Liquidação inválida aborta com rollback.","efeitos":"INSERT em payment_allocation por match; INSERT PLE por-alocação (INV-22) e UPDATE sales_invoice/purchase_invoice via _clear_invoice_allocation; UPDATE payment_entry.unallocated_amount de todos pagamentos afetados. conn.commit(). Não grava audit_log próprio.","precondicoes":"Parceiro com pagamentos submetidos não-alocados e faturas em aberto na empresa."}]},{"group":"Conciliação Bancária","objetivo":"Comparar, em modo leitura, o saldo contábil de uma conta bancária com os pagamentos do período.","acoes":[{"nome":"bank-reconciliation","objetivo":"Compara o saldo do razão (GL) de uma conta bancária com os pagamentos submetidos do período (somente leitura).","entradas":"--bank-account-id (obrigatório), --from-date (obrigatório), --to-date (obrigatório).","saidas":"bank_account (nome), from_date, to_date, gl_entries (contagem), gl_balance (debit-credit), payment_entries (contagem).","regras":"Erro se conta bancária não encontrada. gl_balance = soma(debit)-soma(credit) de gl_entry não cancelado no período; conta pagamentos submetidos que tocam a conta como paid_from ou paid_to no período.","efeitos":"nenhum (leitura).","precondicoes":"Conta bancária existente; gl_entry e payment_entry no período."}]},{"group":"Status","objetivo":"Resumir contagens por status e totais recebidos/pagos dos pagamentos de uma empresa.","acoes":[{"nome":"status","objetivo":"Retorna contagens de pagamentos por status e totais recebidos/pagos (submetidos) da empresa.","entradas":"--company-id ou --company (nome) para resolver empresa.","saidas":"total, draft, submitted, cancelled (contagens), total_received, total_paid.","regras":"Agrupa contagens e soma paid_amount por status; total_received/total_paid somam paid_amount apenas de pagamentos 'submitted' por payment_type (receive/pay). company_id resolvido por id/nome.","efeitos":"nenhum (leitura).","precondicoes":"Empresa identificável por id ou nome."}]}]},"reports":{"module":"reports","display":"Relatórios","functionalities":[{"group":"DRE","objetivo":"Demonstração de resultado (receitas, despesas, lucro líquido) flat, agrupada por dimensão, ou comparativa entre períodos.","acoes":[{"nome":"profit-and-loss","objetivo":"Calcula a demonstração de resultado (receitas menos despesas = lucro líquido) de um período, opcionalmente quebrada por uma dimensão contábil.","entradas":"--company-id ou --company (resolvido); --from-date (obrigatório); --to-date (obrigatório); --project-id (filtro opcional); --dimension-key/--dimension-value (pares de filtro M6); --group-by (uma única dimensão, opcional).","saidas":"Flat: period, income[] (account, account_id, amount), income_total, expenses[], expense_total, net_income. Com --group-by: period, group_by, groups[] (chave, revenue, expenses, net), income_total, expense_total, net_income.","regras":"Exige from-date e to-date. Receita = credit-debit em contas root_type='income'; despesa = debit-credit em 'expense', ambas is_group=0 e is_cancelled=0; HAVING descarta contas com amount=0. Com --group-by aceita exatamente UMA dimensão (erro se vazia ou múltipla), que precisa estar registrada e ativa; entradas sem a chave caem no bucket '(untagged)'.","efeitos":"nenhum (leitura)","precondicoes":"company existente; contas income/expense e gl_entry postados no período; para --group-by, a dimensão registrada e ativa em dimension_registry."},{"nome":"comparative-pl","objetivo":"Compara receitas, despesas e resultado líquido de várias contas income/expense lado a lado entre múltiplos períodos informados.","entradas":"--company-id ou --company (resolvido); --periods (obrigatório, JSON array de {from_date, to_date, label}).","saidas":"accounts[] (account, account_id, root_type, periods[] com label e amount por período); totals[] (label, income, expenses, net por período).","regras":"Erro se --periods ausente ou não for lista. Para cada período soma income (credit-debit) e expense (debit-credit) por conta (is_group=0, is_cancelled=0); label default é 'from to to'. Acumula cada conta uma vez e anexa um amount por período.","efeitos":"nenhum (leitura)","precondicoes":"company existente; contas income/expense; gl_entry postados nos períodos informados."}]},{"group":"Balanço","objetivo":"Balanço patrimonial (ativos, passivos, patrimônio) em uma data, incluindo o lucro do exercício no patrimônio.","acoes":[{"nome":"balance-sheet","objetivo":"Produz o balanço patrimonial em uma data, somando ativos, passivos e patrimônio mais o lucro líquido acumulado do exercício (YTD).","entradas":"--company-id ou --company (resolvido); --as-of-date (obrigatório); --project-id (filtro opcional); --dimension-key/--dimension-value (pares de filtro M6).","saidas":"as_of_date, assets[] (account, account_id, amount), total_assets, liabilities[], total_liabilities, equity[], total_equity, net_income_ytd.","regras":"Exige as-of-date. Ativos = debit-credit; passivos e patrimônio = credit-debit; só contas is_group=0, is_cancelled=0 até a data; HAVING descarta saldo zero. net_income_ytd = (income credit-debit) - (expense debit-credit) desde o início do fiscal_year vigente na data; total_equity = patrimônio base + net_income_ytd. O filtro dimensional/projeto é aplicado tanto nas seções quanto no cálculo de lucro para manter o balanço fechando.","efeitos":"nenhum (leitura)","precondicoes":"company existente; contas asset/liability/equity/income/expense; fiscal_year cobrindo a data (senão net_income_ytd=0); gl_entry postados."}]},{"group":"Balancete","objetivo":"Balancete de verificação por conta com saldos de abertura, movimento do período e fechamento.","acoes":[{"nome":"trial-balance","objetivo":"Lista o balancete por conta com débito/crédito de abertura, do período e de fechamento, totalizando débitos e créditos.","entradas":"--company-id ou --company (resolvido); --to-date (obrigatório); --from-date (opcional, define abertura/movimento); --project-id (filtro opcional); --dimension-key/--dimension-value (pares de filtro M6).","saidas":"as_of_date, total_debit, total_credit, accounts[] (account_id, account_name, account_number, root_type, opening_debit, opening_credit, debit, credit, closing_debit, closing_credit).","regras":"Exige to-date. Com --from-date: abertura = soma antes de from-date e movimento = entre from-date e to-date; sem from-date: abertura zero e movimento = tudo até to-date. Fechamento = abertura+período; contas is_group são puladas e as com fechamento débito e crédito zero são omitidas. Sempre is_cancelled=0.","efeitos":"nenhum (leitura)","precondicoes":"company existente; contas e gl_entry postados; dimensão registrada se usada como filtro."}]},{"group":"Fluxo de Caixa","objetivo":"Demonstração de fluxo de caixa pelo método indireto, classificando movimentos em operacional, investimento e financiamento.","acoes":[{"nome":"cash-flow","objetivo":"Monta o fluxo de caixa indireto do período com saldos de abertura/fechamento de caixa e bancos e movimentos categorizados.","entradas":"--company-id ou --company (resolvido); --from-date (obrigatório); --to-date (obrigatório); --dimension-key/--dimension-value (pares de filtro M6).","saidas":"operating, investing, financing, net_change, opening_balance, closing_balance, details[] (category, account, amount).","regras":"Exige from-date e to-date. Abertura/fechamento = debit-credit em contas account_type bank/cash antes/até as datas. Movimentos das demais contas (is_cancelled=0) classificados: income/expense e ativo circulante/passivo→operating; fixed_asset/accumulated_depreciation→investing; 'Long Term Loan' e equity→financing. net_change = fechamento-abertura.","efeitos":"nenhum (leitura)","precondicoes":"company existente; contas bank/cash e demais com gl_entry postados no período."}]},{"group":"Razão","objetivo":"Livro razão (general ledger) com lançamentos detalhados, saldo de abertura e saldo corrido, paginado e filtrável.","acoes":[{"nome":"general-ledger","objetivo":"Lista lançamentos do razão no período com saldo de abertura, saldo corrido por linha e totais de débito/crédito.","entradas":"--company-id ou --company (resolvido); --from-date (obrigatório); --to-date (obrigatório); --account-id, --party-type, --party-id, --voucher-type (filtros opcionais); --dimension-key/--dimension-value (M6); --limit (default 100); --offset (default 0).","saidas":"entries[] (posting_date, account_name, debit, credit, balance, voucher_type, voucher_id, party_type, party_id, remarks), opening_balance, total_debit, total_credit, closing_balance.","regras":"Exige from-date e to-date. Abertura = soma(debit-credit) antes de from-date. --voucher-type é canonicalizado (ex.: 'Sales Invoice'→'sales_invoice') antes de filtrar. Lançamentos ordenados por posting_date e created_at, is_cancelled=0; saldo corrido acumula debit-credit a partir da abertura.","efeitos":"nenhum (leitura)","precondicoes":"company existente; gl_entry e account; partes/dimensões existentes se usadas como filtro."}]},{"group":"Razão por Parceiro","objetivo":"Razão de um parceiro (cliente ou fornecedor) específico com saldo de abertura, lançamentos e fechamento.","acoes":[{"nome":"party-ledger","objetivo":"Mostra o razão de um cliente ou fornecedor com saldo de abertura, lançamentos do período e saldo de fechamento.","entradas":"--party-type (obrigatório, 'customer' ou 'supplier'); --party-id (obrigatório); --from-date (opcional, define abertura); --to-date (opcional).","saidas":"party_name, opening_balance, entries[] (posting_date, voucher_type, voucher_id, debit, credit, balance), closing_balance.","regras":"Erro se party-type ausente/inválido ou party-id ausente. Com --from-date a abertura = soma(debit-credit) antes dela; sem from-date a abertura é forçada a zero (cláusula 1=0). Filtra gl_entry por party_type+party_id, is_cancelled=0, ordenado por posting_date/created_at; saldo corrido = abertura + (debit-credit).","efeitos":"nenhum (leitura)","precondicoes":"customer ou supplier existente com o party-id; gl_entry com lançamentos para o parceiro."}]},{"group":"Aging AR/AP","objetivo":"Relatórios de aging de contas a receber (clientes) e a pagar (fornecedores) por faixas de dias a partir do payment_ledger_entry.","acoes":[{"nome":"ar-aging","objetivo":"Gera o aging de contas a receber por cliente, distribuindo saldos em aberto em faixas de dias até a data de corte.","entradas":"--company-id ou --company (resolvido); --as-of-date (obrigatório); --aging-buckets (default '30,60,90,120').","saidas":"as_of_date, total_outstanding, customers[] (customer_id, customer_name, current, days_<b>..., days_<último>_plus, total).","regras":"Exige as-of-date; buckets devem ser inteiros separados por vírgula. Lê payment_ledger_entry com party_type='customer', delinked=0, posting_date<=as_of_date; HAVING mantém saldos com |total|>0.005. Idade = as_of_date - posting_date em dias; cada lançamento cai na faixa correspondente ou no bucket além da última.","efeitos":"nenhum (leitura)","precondicoes":"customer existente; payment_ledger_entry não-delinkados com party_type='customer'."},{"nome":"ap-aging","objetivo":"Gera o aging de contas a pagar por fornecedor, distribuindo saldos em aberto em faixas de dias até a data de corte.","entradas":"--company-id ou --company (resolvido); --as-of-date (obrigatório); --aging-buckets (default '30,60,90,120').","saidas":"as_of_date, total_outstanding, suppliers[] (supplier_id, supplier_name, current, days_<b>..., days_<último>_plus, total).","regras":"Idêntica a ar-aging mas com party_type='supplier' lendo nomes da tabela supplier. Exige as-of-date e buckets inteiros; HAVING |total|>0.005; idade por dias entre posting_date e as_of_date distribuída nas faixas.","efeitos":"nenhum (leitura)","precondicoes":"supplier existente; payment_ledger_entry não-delinkados com party_type='supplier'."}]},{"group":"Faturas Vencidas","objetivo":"Identifica faturas de venda vencidas e as agrupa em faixas de atraso a partir da data atual.","acoes":[{"nome":"check-overdue","objetivo":"Encontra faturas de venda vencidas com saldo em aberto e as agrupa em faixas de atraso (0-30, 31-60, 61-90, 90+).","entradas":"--company-id ou --company (resolvido). Sem flags de data: usa a data atual (datetime.now) como referência.","saidas":"overdue_count, total_overdue, buckets (0_30/31_60/61_90/90_plus com count e total), invoices[] (id, name, customer_name, grand_total, outstanding, due_date, days_overdue).","regras":"Considera sales_invoice da empresa com status em submitted/partially_paid/overdue, outstanding_amount>0 e due_date<hoje. days_overdue = hoje - due_date; aloca o saldo na faixa por atraso; lista de faturas ordenada por days_overdue desc.","efeitos":"nenhum (leitura)","precondicoes":"company existente; sales_invoice com saldo em aberto e due_date vencida; tabela customer para o nome."}]},{"group":"Orçado vs Realizado","objetivo":"Compara valores orçados (budget) com o realizado do gl_entry por conta/centro de custo dentro de um exercício fiscal.","acoes":[{"nome":"budget-vs-actual","objetivo":"Compara o valor orçado de cada budget com o realizado no período do exercício fiscal, calculando variação absoluta e percentual.","entradas":"--fiscal-year-id (obrigatório); --company-id ou --company (resolvido); --account-id (filtro opcional); --cost-center-id (filtro opcional).","saidas":"items[] (account_or_cc, budget, actual, variance, variance_pct, action_if_exceeded).","regras":"Erro se fiscal-year-id ausente ou fiscal_year não encontrado. Realizado = soma(debit-credit) em gl_entry (is_cancelled=0) dentro de start_date/end_date do FY, filtrado pelo account_id/cost_center_id do budget. variance = budget-actual; variance_pct = variance/budget*100 (0 se budget=0).","efeitos":"nenhum (leitura)","precondicoes":"fiscal_year existente; registros budget para a empresa/FY; gl_entry postados; cost_center/account referenciados."},{"nome":"budget-variance","objetivo":"Alias de budget-vs-actual: compara orçado e realizado por conta/centro de custo no exercício fiscal.","entradas":"Mesmas de budget-vs-actual: --fiscal-year-id (obrigatório); --company-id/--company; --account-id; --cost-center-id. Mapeado para a mesma função no dispatch.","saidas":"Mesmas de budget-vs-actual: items[] (account_or_cc, budget, actual, variance, variance_pct, action_if_exceeded).","regras":"Comportamento idêntico a budget-vs-actual (mesma função handler); apenas um nome alternativo no ACTIONS.","efeitos":"nenhum (leitura)","precondicoes":"Iguais a budget-vs-actual: fiscal_year e budgets existentes; gl_entry postados."}]},{"group":"Dimensionais","objetivo":"Relatórios agrupados por dimensões contábeis registradas (dimensions_json), com balancete multi-dimensional e saldo por valor de dimensão.","acoes":[{"nome":"multi-dim-trial-balance","objetivo":"Produz um balancete agrupado por uma ou mais dimensões contábeis lidas de gl_entry.dimensions_json, somando débito/crédito por grupo.","entradas":"--company-id ou --company (resolvido); --to-date (obrigatório); --group-by (obrigatório, ex.: 'project,department'); --from-date (opcional); --dimension-key/--dimension-value (pares de filtro M6).","saidas":"group_by[], as_of_date, groups[] (uma chave por dimensão + debit, credit, balance), total_debit, total_credit.","regras":"Erro se to-date ou group-by ausentes. Cada chave é extraída via json_get de dimensions_json; agrupa por todas as chaves até to-date (e desde from-date se dado), is_cancelled=0. balance = debit-credit por grupo.","efeitos":"nenhum (leitura)","precondicoes":"company existente; gl_entry com dimensions_json populado nas chaves pedidas."},{"nome":"dimension-balance-report","objetivo":"Retorna o saldo líquido (débito-crédito) por valor distinto de uma única dimensão contábil, com filtro opcional de valores.","entradas":"--company-id ou --company (resolvido); --dimension (obrigatório, chave K); --to-date (obrigatório); --from-date (opcional); --values (opcional, lista CSV restringindo os valores).","saidas":"dimension, as_of_date, values[] (value, debit, credit, balance), total_debit, total_credit.","regras":"Erro se --dimension ou --to-date ausentes. Extrai o valor da dimensão via json_get; soma debit/credit por valor (is_cancelled=0, até to-date, desde from-date se dado), descartando valores NULL; --values limita a um IN dos valores informados. balance = debit-credit.","efeitos":"nenhum (leitura)","precondicoes":"company existente; gl_entry com dimensions_json contendo a chave K."}]},{"group":"Resumo de Impostos","objetivo":"Resumo de impostos coletados e pagos por conta de imposto no período, com passivo líquido.","acoes":[{"nome":"tax-summary","objetivo":"Resume impostos coletados (créditos) e pagos (débitos) por conta de imposto no período e calcula o passivo líquido.","entradas":"--company-id ou --company (resolvido); --from-date (obrigatório); --to-date (obrigatório).","saidas":"collected, paid, net_liability, by_account[] (account_id, account_name, amount).","regras":"Exige from-date e to-date. Considera apenas contas account_type='tax', is_group=0; collected=soma(credit), paid=soma(debit) no período (is_cancelled=0); pula contas sem movimento; net_liability = total coletado - total pago; amount por conta = collected-paid.","efeitos":"nenhum (leitura)","precondicoes":"company existente; contas account_type='tax' com gl_entry postados no período."}]},{"group":"Resumos Operacionais","objetivo":"Resumos agregados de pagamentos (payment_entry) e do razão (gl_entry) por tipo, não cobertos pelos demonstrativos principais.","acoes":[{"nome":"payment-summary","objetivo":"Resume pagamentos recebidos e pagos no período e os agrega por tipo de parte a partir de payment_entry submetidos.","entradas":"--company-id ou --company (resolvido); --from-date (obrigatório); --to-date (obrigatório).","saidas":"total_received, total_paid, by_party_type[] (party_type, count, amount).","regras":"Exige from-date e to-date. Lê payment_entry com status='submitted' no período: total_received soma paid_amount de payment_type='receive', total_paid de 'pay'; agrega contagem e soma de paid_amount por party_type.","efeitos":"nenhum (leitura)","precondicoes":"company existente; payment_entry submetidos no período."},{"nome":"gl-summary","objetivo":"Resume o razão por tipo de voucher no período, com contagem e totais de débito/crédito por voucher_type.","entradas":"--company-id ou --company (resolvido); --from-date (obrigatório); --to-date (obrigatório).","saidas":"by_voucher_type[] (voucher_type, count, total_debit, total_credit).","regras":"Exige from-date e to-date. Agrupa gl_entry (join account da empresa, is_cancelled=0) por voucher_type no período, contando linhas e somando debit/credit; ordenado por voucher_type.","efeitos":"nenhum (leitura)","precondicoes":"company existente; gl_entry postados no período."}]},{"group":"Eliminações Intercompany","objetivo":"Gestão e execução de regras de eliminação intercompany, criando lançamentos de eliminação e mantendo trilha de auditoria.","acoes":[{"nome":"add-elimination-rule","objetivo":"Cria uma regra de eliminação intercompany ligando uma conta de origem (empresa fonte) a uma conta de destino (empresa alvo).","entradas":"--name (obrigatório, ou --rule-name); --company-id (obrigatório, empresa fonte); --target-company-id (obrigatório); --source-account-id (obrigatório); --target-account-id (obrigatório).","saidas":"rule_id, name.","regras":"Erro se faltar qualquer campo, se fonte=alvo, se empresas não existirem, se contas não existirem ou não pertencerem às respectivas empresas. Gera rule_id UUID; insere a regra (status default da tabela).","efeitos":"Escreve: INSERT em elimination_rule (id, name, source/target company e account); conn.commit(). Sem postagem em gl_entry.","precondicoes":"Duas company distintas existentes; source_account na empresa fonte e target_account na empresa alvo."},{"nome":"list-elimination-rules","objetivo":"Lista as regras de eliminação intercompany com nomes de empresas e contas de origem/destino.","entradas":"--company-id (filtro opcional: regras onde a empresa é fonte ou alvo).","saidas":"rules[] (id, name, status, source_company, target_company, source_account, target_account), total.","regras":"Junta elimination_rule a company e account (origem/destino). Com --company-id filtra por source_company_id OU target_company_id; sem ele retorna todas.","efeitos":"nenhum (leitura)","precondicoes":"Tabelas elimination_rule, company e account; regras previamente criadas."},{"nome":"run-elimination","objetivo":"Executa as regras de eliminação ativas para um exercício fiscal, criando pares balanceados de lançamentos de eliminação no gl_entry.","entradas":"--fiscal-year-id (obrigatório); --posting-date ou --as-of-date (obrigatório, um deles).","saidas":"fiscal_year, posting_date, eliminations[] (rule_name, amount, source_gl_id, target_gl_id, entry_id), total_eliminated.","regras":"Erro se fiscal-year-id ou data ausentes, ou FY não encontrado, ou sem regras ativas. Para cada regra status='active': idempotente (pula se já existe elimination_entry posted para a regra+FY); valor = credit-debit da conta de origem no período do FY (excluindo voucher_type='elimination_entry'); pula se <=0. Cria DR na conta origem e CR na conta destino (par balanceado em USD).","efeitos":"Escreve: 2 INSERTs em gl_entry por regra (voucher_type='elimination_entry', is_cancelled=0) e 1 INSERT em elimination_entry; conn.commit(). Postagem direta no gl_entry contornando insert_gl_entries.","precondicoes":"fiscal_year existente; ao menos uma elimination_rule ativa; gl_entry de receita na conta de origem dentro do período."},{"nome":"list-elimination-entries","objetivo":"Lista os lançamentos de eliminação já criados, formando a trilha de auditoria das eliminações intercompany.","entradas":"--fiscal-year-id (filtro opcional).","saidas":"entries[] (id, posting_date, amount, status, rule_name, source_company, target_company, source_account, target_account, fiscal_year), total.","regras":"Junta elimination_entry a elimination_rule, company (origem/destino), account (origem/destino) e fiscal_year. Com --fiscal-year-id filtra por FY; ordenado por posting_date desc.","efeitos":"nenhum (leitura)","precondicoes":"Tabela elimination_entry com lançamentos previamente criados por run-elimination."}]},{"group":"Status","objetivo":"Diagnóstico do estado dos dados contábeis da empresa para os relatórios.","acoes":[{"nome":"status","objetivo":"Reporta o estado de saúde dos dados de relatório: contagem de lançamentos, datas de postagem mais antiga/recente e número de exercícios fiscais.","entradas":"--company-id ou --company (resolvido).","saidas":"gl_entry_count, latest_posting_date, earliest_posting_date, fiscal_years.","regras":"Conta gl_entry não cancelados (join account da empresa), pega min/max posting_date e conta fiscal_year da empresa. Apenas resolve a empresa, sem outras validações.","efeitos":"nenhum (leitura)","precondicoes":"company existente; tabelas gl_entry, account e fiscal_year presentes."}]}]},"hr":{"module":"hr","display":"Recursos Humanos","functionalities":[{"group":"Funcionários","objetivo":"Cadastro, atualização e consulta de funcionários e seus dados de RH/folha.","acoes":[{"nome":"add-employee","objetivo":"Cria um novo registro de funcionário com status inicial 'active'.","entradas":"--first-name (obrigatório), --date-of-joining (obrigatório), --company-id (obrigatório); opcionais: --last-name, --date-of-birth, --gender, --employment-type (default full_time), --department-id, --designation-id, --employee-grade-id, --branch, --reporting-to, --company-email, --personal-email, --cell-phone, --emergency-contact (JSON), --bank-details (JSON), --federal-filing-status, --w4-allowances (default 0), --holiday-list-id, --payroll-cost-center-id.","saidas":"employee_id, naming_series, full_name, message.","regras":"Valida existência de company e dos FKs informados (department/designation/grade/reporting-to/holiday-list/cost-center); valida gender, employment_type e federal_filing_status contra listas válidas; valida formatos de datas (YYYY-MM-DD) e de e-mails (regex); calcula full_name = first+last; gera naming_series via get_next_name; status fixo 'active'.","efeitos":"INSERT em employee; INSERT em employee_lifecycle_event (event_type='hiring'); audit_log via audit(); commit.","precondicoes":"Company existente; FKs referenciados (se informados) devem existir."},{"nome":"update-employee","objetivo":"Atualiza dinamicamente campos de um funcionário existente.","entradas":"--employee-id (obrigatório); opcionais (qualquer subconjunto): --first-name, --last-name, --date-of-birth, --gender, --date-of-joining, --date-of-exit, --employment-type, --status, --department-id, --designation-id, --employee-grade-id, --branch, --reporting-to, --company-email, --personal-email, --cell-phone, --emergency-contact, --bank-details, --federal-filing-status, --w4-allowances, --w4-additional-withholding, --state-filing-status, --state-withholding-allowances, --employee-401k-rate, --hsa-contribution, --is-exempt-from-fica, --salary-structure-id, --leave-policy-id, --shift-id, --holiday-list-id, --attendance-device-id, --payroll-cost-center-id.","saidas":"employee_id, updated_fields (lista de campos alterados), message.","regras":"Funcionário deve existir; recomputa full_name se nome muda; valida formatos de data/e-mail e enums (gender/employment_type/status/federal_filing_status); impede reporting_to == próprio employee; FKs validados quando não-vazios; erro se nenhum campo a atualizar.","efeitos":"UPDATE em employee (dynamic_update, inclui updated_at); audit_log com old/new values; commit.","precondicoes":"Funcionário existente; FKs informados devem existir."},{"nome":"get-employee","objetivo":"Retorna detalhes de um funcionário com saldos de férias, resumo de ponto e cadeia de reporte.","entradas":"--employee-id (obrigatório).","saidas":"employee (linha completa com department_name, designation_name, employee_grade_name, holiday_list_name, emergency_contact/bank_details parseados, leave_balances do ano fiscal corrente, attendance_summary do mês corrente, reporting_to_name, direct_reports_count).","regras":"Erro se funcionário não existir; parseia JSON de emergency_contact/bank_details; saldos de férias só preenchidos se houver ano fiscal aberto para hoje; resumo de ponto agrega o mês corrente.","efeitos":"nenhum (leitura).","precondicoes":"Funcionário existente."},{"nome":"list-employees","objetivo":"Lista funcionários com filtros e paginação.","entradas":"Opcionais: --company-id, --department-id, --designation-id, --status, --employment-type, --search (full_name/naming_series/company_email/cell_phone), --limit (default 20), --offset (default 0).","saidas":"employees (com department_name/designation_name), total_count, limit, offset, has_more.","regras":"Valida status e employment_type contra enums quando informados; ordena por full_name; busca via LIKE em 4 campos.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma (tabela company exigida na dependência do módulo)."}]},{"group":"Estrutura Org.","objetivo":"Gestão de departamentos e cargos (designações) da organização.","acoes":[{"nome":"add-department","objetivo":"Cria um novo departamento dentro de uma empresa.","entradas":"--name (obrigatório), --company-id (obrigatório); opcionais: --parent-id, --cost-center-id.","saidas":"department_id, name, message.","regras":"Valida company; valida parent (deve existir e pertencer à mesma company); valida cost_center se informado; impede nome duplicado dentro da mesma company.","efeitos":"INSERT em department; audit_log; commit.","precondicoes":"Company existente; parent/cost-center (se informados) existentes."},{"nome":"list-departments","objetivo":"Lista departamentos com nome do pai, da empresa e contagem de funcionários ativos.","entradas":"Opcionais: --company-id, --parent-id, --limit (default 20), --offset (default 0).","saidas":"departments (com parent_name, company_name, employee_count), total_count, limit, offset, has_more.","regras":"Conta apenas funcionários com status 'active' por departamento; ordena por name.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"add-designation","objetivo":"Cria uma nova designação (cargo/título).","entradas":"--name (obrigatório); opcional: --description.","saidas":"designation_id, name, message.","regras":"designation.name é UNIQUE: erro se já existir.","efeitos":"INSERT em designation; audit_log; commit.","precondicoes":"Nenhuma."},{"nome":"list-designations","objetivo":"Lista todas as designações com contagem de funcionários ativos.","entradas":"Opcionais: --limit (default 20), --offset (default 0).","saidas":"designations (com employee_count), total_count, limit, offset, has_more.","regras":"Conta apenas funcionários 'active' por designação; ordena por name.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Tipos/Alocação de Férias","objetivo":"Definição de tipos de férias/licença e alocação anual de dias por funcionário, incluindo saldos.","acoes":[{"nome":"add-leave-type","objetivo":"Cria um novo tipo de licença/férias com regras de dias e carry-forward.","entradas":"--name (obrigatório), --max-days-allowed (obrigatório); opcionais: --is-paid-leave (default 1), --is-carry-forward (default 0), --max-carry-forward-days, --is-compensatory (default 0), --applicable-after-days (default 0).","saidas":"leave_type_id, name, max_days_allowed, message.","regras":"max_days_allowed deve ser > 0; leave_type.name é UNIQUE; flags booleanas restritas a 0/1; max_carry_forward_days >= 0; applicable_after_days inteiro >= 0.","efeitos":"INSERT em leave_type; audit_log; commit.","precondicoes":"Nenhuma."},{"nome":"list-leave-types","objetivo":"Lista todos os tipos de licença/férias.","entradas":"Opcionais: --limit (default 20), --offset (default 0).","saidas":"leave_types (campos completos), total_count, limit, offset, has_more.","regras":"Ordena por name.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"add-leave-allocation","objetivo":"Aloca dias de férias a um funcionário para um ano fiscal, aplicando carry-forward quando configurado.","entradas":"--employee-id (obrigatório), --leave-type-id (obrigatório), --total-leaves (obrigatório), --fiscal-year (obrigatório).","saidas":"allocation_id, employee_id, leave_type, fiscal_year, total_leaves, used_leaves, remaining_leaves, message; (carry_forwarded, carry_forwarded_from se aplicável).","regras":"Valida employee, leave_type e existência do fiscal_year; total_leaves >= 0; impede alocação duplicada (employee+leave_type+fiscal_year); se leave_type.is_carry_forward, soma remaining da alocação do ano anterior (limitado por max_carry_forward_days); used_leaves=0 e remaining=total na criação.","efeitos":"INSERT em leave_allocation; audit_log; commit.","precondicoes":"Funcionário, tipo de licença e ano fiscal (por nome) existentes; sem alocação prévia para a mesma combinação."},{"nome":"get-leave-balance","objetivo":"Retorna o saldo de férias de um funcionário por tipo no ano fiscal.","entradas":"--employee-id (obrigatório); opcionais: --leave-type-id, --fiscal-year (default ano fiscal corrente).","saidas":"employee_id, fiscal_year, balances (allocation_id, leave_type_id/name, is_paid_leave, total/used/remaining_leaves, pending_days), total_count.","regras":"Funcionário deve existir; se fiscal_year omitido usa o ano fiscal aberto de hoje (erro se inexistente); valida leave_type se filtrado; calcula pending_days somando total_days de leave_application em status 'draft'.","efeitos":"nenhum (leitura).","precondicoes":"Funcionário existente; ano fiscal aberto se não informado."}]},{"group":"Solicitações de Férias","objetivo":"Ciclo de vida das solicitações de férias: criação (rascunho), aprovação, rejeição e listagem.","acoes":[{"nome":"add-leave-application","objetivo":"Cria uma solicitação de férias em status 'draft' calculando dias úteis.","entradas":"--employee-id (obrigatório), --leave-type-id (obrigatório), --from-date (obrigatório), --to-date (obrigatório); opcionais: --half-day (0/1), --half-day-date (default from-date), --reason.","saidas":"leave_application_id, naming_series, employee_id, leave_type, from_date, to_date, total_days, half_day, status='draft', holidays_excluded, message.","regras":"Funcionário deve estar 'active'; valida datas e from<=to; total_days = dias úteis (exclui fins de semana e feriados do funcionário, -0.5 se half_day); erro se total_days<=0; respeita applicable_after_days do tipo; checa saldo na leave_allocation do ano fiscal (erro se insuficiente ou sem alocação); impede sobreposição com applications draft/approved; gera naming_series.","efeitos":"INSERT em leave_application (status draft); audit_log; commit.","precondicoes":"Funcionário ativo; leave_type existente; alocação de férias no ano fiscal do from-date."},{"nome":"approve-leave","objetivo":"Aprova uma solicitação de férias em rascunho e deduz o saldo alocado.","entradas":"--leave-application-id (obrigatório), --approved-by (obrigatório).","saidas":"leave_application_id, status='approved', approved_by, approver_name, total_days, leave_type, message.","regras":"Application deve existir e estar 'draft'; approved_by deve ser funcionário válido e diferente do solicitante; deduz used_leaves += e remaining_leaves -= na leave_allocation do ano fiscal; rollback+erro se saldo ficaria negativo, sem alocação ou sem ano fiscal aberto.","efeitos":"UPDATE leave_application (status/approved_by); UPDATE leave_allocation (used/remaining); audit_log; commit.","precondicoes":"Application em 'draft'; aprovador válido; alocação existente no ano fiscal."},{"nome":"reject-leave","objetivo":"Rejeita uma solicitação de férias em rascunho.","entradas":"--leave-application-id (obrigatório); opcional: --reason (default 'No reason provided').","saidas":"leave_application_id, status='rejected', leave_type, employee_id, rejection_reason, message.","regras":"Application deve existir e estar 'draft'; não altera saldo de alocação.","efeitos":"UPDATE leave_application (status='rejected'); audit_log; commit.","precondicoes":"Application em 'draft'."},{"nome":"list-leave-applications","objetivo":"Lista solicitações de férias com filtros e paginação.","entradas":"Opcionais: --employee-id, --status, --leave-type-id, --from-date, --to-date, --limit (default 20), --offset (default 0).","saidas":"leave_applications (com employee_name/series, leave_type_name, approved_by_name), total_count, limit, offset, has_more.","regras":"Valida status contra VALID_LEAVE_STATUSES quando informado; ordena por created_at desc; from-date filtra >=, to-date filtra <=.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Ponto","objetivo":"Registro de presença (individual e em lote) e consulta de ponto dos funcionários.","acoes":[{"nome":"mark-attendance","objetivo":"Registra a presença de um funcionário em uma data.","entradas":"--employee-id (obrigatório), --date (obrigatório), --status (obrigatório); opcionais: --shift, --check-in-time, --check-out-time, --working-hours, --late-entry (0/1, default 0), --early-exit (0/1, default 0), --source (manual|biometric|app, default manual).","saidas":"attendance_id, employee_id, employee_name, date, status, source, message.","regras":"Funcionário deve existir; data válida e não futura; valida status/source/late_entry/early_exit; impede duplicidade por (employee_id, attendance_date).","efeitos":"INSERT em attendance; audit_log; commit.","precondicoes":"Funcionário existente; sem registro de ponto prévio para a mesma data."},{"nome":"bulk-mark-attendance","objetivo":"Registra presença para vários funcionários numa data, pulando duplicados.","entradas":"--date (obrigatório), --entries (JSON array de {employee_id, status}, obrigatório); opcional: --source (default manual).","saidas":"date, total, created, skipped_duplicates, errors (lista), message.","regras":"Valida data e source; cada entry exige employee_id e status válido e funcionário existente (caso contrário adiciona à lista errors e continua); registros já existentes na data contam como skipped_duplicates; late_entry/early_exit fixos em 0.","efeitos":"INSERT em attendance por entry válida e não duplicada; commit (sem audit_log).","precondicoes":"Funcionários referenciados existentes (entradas inválidas são apenas reportadas)."},{"nome":"list-attendance","objetivo":"Lista registros de ponto com filtros, paginação e resumo agregado.","entradas":"Opcionais: --employee-id, --from-date, --to-date, --status, --limit (default 20), --offset (default 0).","saidas":"attendance (com employee_name/series), total_count, limit, offset, has_more, summary (contagens por status).","regras":"Valida status contra enum quando informado; ordena por attendance_date desc e full_name; summary usa os mesmos filtros.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Regularização","objetivo":"Regras de regularização de atrasos e sua aplicação em massa sobre registros de ponto.","acoes":[{"nome":"add-regularization-rule","objetivo":"Adiciona uma regra de regularização de atraso para uma empresa.","entradas":"--company-id (obrigatório), --late-threshold-minutes (obrigatório), --regularization-action (obrigatório: half_day|deduct_leave|warn).","saidas":"rule_id, company_id, late_threshold_minutes, action, message.","regras":"Company deve existir; late_threshold_minutes inteiro > 0; action restrita a VALID_REGULARIZATION_ACTIONS.","efeitos":"INSERT em attendance_regularization_rule; audit_log; commit.","precondicoes":"Company existente."},{"nome":"apply-attendance-regularization","objetivo":"Aplica as regras de regularização aos registros de ponto com atraso de uma empresa.","entradas":"--company-id (obrigatório); opcionais: --from-date, --to-date.","saidas":"records_processed, records_updated, warnings (lista), warning_count.","regras":"Erro se não houver regras para a company; processa attendance com late_entry=1; calcula minutos de atraso a partir de check_in_time (referência 9h); para a primeira regra cujo threshold é atingido aplica: half_day (atualiza status), warn ou deduct_leave (apenas registra warning).","efeitos":"UPDATE attendance SET status='half_day' para registros que casam regra half_day; commit; warn/deduct_leave não escrevem (apenas reportam).","precondicoes":"Pelo menos uma regra de regularização cadastrada para a company."}]},{"group":"Feriados","objetivo":"Criação de listas de feriados e suas datas para cálculo de dias úteis.","acoes":[{"nome":"add-holiday-list","objetivo":"Cria uma lista de feriados com datas-filho opcionais para uma empresa.","entradas":"--name (obrigatório), --company-id (obrigatório), --from-date (obrigatório), --to-date (obrigatório); opcional: --holidays (JSON array de {date, description}).","saidas":"holiday_list_id, name, from_date, to_date, holiday_count, message.","regras":"Company deve existir; datas válidas e from<=to; holiday_list.name é UNIQUE; feriados com data inválida ou fora do intervalo são ignorados (não contam).","efeitos":"INSERT em holiday_list e em holiday (um por feriado válido); audit_log; commit.","precondicoes":"Company existente."}]},{"group":"Reembolsos de Despesas","objetivo":"Ciclo de vida das despesas de funcionários: rascunho, submissão, aprovação com lançamento contábil, rejeição, atualização de status e listagem.","acoes":[{"nome":"add-expense-claim","objetivo":"Cria uma despesa de funcionário em status 'draft' com itens.","entradas":"--employee-id (obrigatório), --expense-date (obrigatório), --company-id (obrigatório), --items (JSON array de {expense_type, description, amount, account_id}, obrigatório).","saidas":"expense_claim_id, naming_series, employee_id, employee_name, expense_date, total_amount, item_count, status='draft', message.","regras":"Valida employee, company e data; cada item exige expense_type válido e amount>0; account_id (se informado) deve existir, não ser grupo e pertencer à mesma company; total_amount = soma dos itens (arredondada); gera naming_series.","efeitos":"INSERT em expense_claim (status draft) e em expense_claim_item (um por item); audit_log; commit.","precondicoes":"Funcionário e company existentes; contas dos itens válidas se informadas."},{"nome":"submit-expense-claim","objetivo":"Submete uma despesa em rascunho para aprovação.","entradas":"--expense-claim-id (obrigatório).","saidas":"expense_claim_id, naming_series, status='submitted', message.","regras":"Despesa deve existir e estar 'draft'.","efeitos":"UPDATE expense_claim (status='submitted'); audit_log; commit.","precondicoes":"Despesa em 'draft'."},{"nome":"approve-expense-claim","objetivo":"Aprova uma despesa submetida e gera lançamentos contábeis (GL).","entradas":"--expense-claim-id (obrigatório), --approved-by (obrigatório).","saidas":"expense_claim_id, naming_series, status='approved', approved_by, approver_name, total_amount, gl_entry_count, gl_entry_ids, message.","regras":"Despesa deve existir e estar 'submitted'; approved_by funcionário válido e diferente do solicitante; exige itens; resolve conta a pagar (default_payable_account_id da company, ou conta payable, ou liability) e conta de despesa (account_id do item ou default_expense_account_id/conta expense); exige cost center e ano fiscal aberto; DR conta de despesa por item, CR conta a pagar pelo total (party employee); rollback+erro em qualquer falha de GL/contas.","efeitos":"INSERT em gl_entry (via insert_gl_entries) — DR despesas / CR a pagar; UPDATE expense_claim (status='approved', approved_by, approval_date); audit_log; commit.","precondicoes":"Despesa em 'submitted' com itens; contas a pagar/despesa, cost center e ano fiscal aberto disponíveis para a company."},{"nome":"reject-expense-claim","objetivo":"Rejeita uma despesa submetida.","entradas":"--expense-claim-id (obrigatório); opcional: --reason (default 'No reason provided').","saidas":"expense_claim_id, naming_series, status='rejected', employee_id, rejection_reason, message.","regras":"Despesa deve existir e estar 'submitted'; não gera lançamento contábil.","efeitos":"UPDATE expense_claim (status='rejected'); audit_log; commit.","precondicoes":"Despesa em 'submitted'."},{"nome":"update-expense-claim-status","objetivo":"Atualiza o status (e vínculo de pagamento) de uma despesa; usado entre skills (ex.: pagamentos para marcar 'paid').","entradas":"--expense-claim-id (obrigatório), --status (obrigatório, deve ser VALID_EXPENSE_STATUSES); opcional: --payment-entry-id.","saidas":"expense_claim_id, naming_series, old_status, new_status, payment_entry_id, message.","regras":"Despesa deve existir; status validado contra enum; grava payment_entry_id se informado; não valida transição de estado específica.","efeitos":"UPDATE expense_claim (status e opcionalmente payment_entry_id, via dynamic_update); audit_log; commit.","precondicoes":"Despesa existente."},{"nome":"list-expense-claims","objetivo":"Lista despesas de funcionários com filtros, paginação e contagem de itens.","entradas":"Opcionais: --employee-id, --status, --company-id, --from-date, --to-date, --limit (default 20), --offset (default 0).","saidas":"expense_claims (com employee_name/series e item_count via subquery), total_count, limit, offset, has_more.","regras":"Valida status contra enum quando informado; usa SQL bruto com subquery correlacionada para item_count; ordena por created_at desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Turnos","objetivo":"Definição de tipos de turno e atribuição/listagem de turnos por funcionário.","acoes":[{"nome":"add-shift-type","objetivo":"Cria um tipo de turno com horários de início e fim.","entradas":"--name (obrigatório), --start-time (obrigatório), --end-time (obrigatório), --company-id (obrigatório); opcional: --status (default 'active').","saidas":"shift_type_id, name, start_time, end_time, company_id, shift_status.","regras":"status restrito a active/inactive; start/end-time no formato HH:MM ou HH:MM:SS; company deve existir; shift_type.name único.","efeitos":"INSERT em shift_type; commit (sem audit_log).","precondicoes":"Company existente; nome de turno não usado."},{"nome":"list-shift-types","objetivo":"Lista tipos de turno com filtros opcionais.","entradas":"Opcionais: --company-id, --status, --limit (default 20), --offset (default 0).","saidas":"shift_types (linhas completas), count.","regras":"Ordena por name; status comparado em minúsculas.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."},{"nome":"update-shift-type","objetivo":"Atualiza campos de um tipo de turno existente.","entradas":"--shift-type-id (obrigatório); opcionais: --name, --start-time, --end-time, --status.","saidas":"linha do shift_type atualizado (com status renomeado para shift_status).","regras":"Turno deve existir; novo name deve ser único; start/end-time validados (HH:MM[:SS]); status restrito a active/inactive; erro se nenhum campo informado.","efeitos":"UPDATE shift_type (SQL bruto, inclui updated_at); commit (sem audit_log).","precondicoes":"Tipo de turno existente."},{"nome":"assign-shift","objetivo":"Atribui um tipo de turno a um funcionário num período.","entradas":"--employee-id (obrigatório), --shift-type-id (obrigatório), --start-date (obrigatório); opcionais: --end-date, --status (default 'active').","saidas":"shift_assignment_id, employee_id, shift_type_id, start_date, end_date, assignment_status.","regras":"status restrito a active/inactive; funcionário e tipo de turno devem existir; datas no formato YYYY-MM-DD; end_date não pode ser anterior a start_date.","efeitos":"INSERT em shift_assignment; commit (sem audit_log).","precondicoes":"Funcionário e tipo de turno existentes."},{"nome":"list-shift-assignments","objetivo":"Lista atribuições de turno com filtros opcionais.","entradas":"Opcionais: --employee-id, --shift-type-id, --status, --company-id, --limit (default 20), --offset (default 0).","saidas":"shift_assignments (com shift_name e employee_name), count.","regras":"JOIN com shift_type e employee; --company-id filtra pela company do funcionário; ordena por start_date desc.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Documentos","objetivo":"Cadastro, consulta e monitoramento de vencimento de documentos dos funcionários.","acoes":[{"nome":"add-employee-document","objetivo":"Adiciona um documento ao funcionário com status inicial 'active'.","entradas":"--employee-id (obrigatório), --document-type (obrigatório, VALID_DOCUMENT_TYPES), --document-name (obrigatório); opcionais: --expiry-date, --notes.","saidas":"employee_document_id, employee_id, employee_name, document_type, document_name, expiry_date, message.","regras":"Funcionário deve existir; document_type validado contra lista (passport/visa/drivers_license/i9/w4/offer_letter/contract/certificate/other); expiry_date validada (YYYY-MM-DD) se informada; status fixo 'active'.","efeitos":"INSERT em employee_document; audit_log; commit.","precondicoes":"Funcionário existente."},{"nome":"list-employee-documents","objetivo":"Lista os documentos de um funcionário.","entradas":"--employee-id (obrigatório); opcionais: --document-type, --status.","saidas":"documents (linhas completas), count.","regras":"Filtra por document_type/status (minúsculas) quando informados; ordena por created_at.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma (não revalida existência do funcionário)."},{"nome":"get-employee-document","objetivo":"Retorna um documento específico de funcionário.","entradas":"--document-id (obrigatório).","saidas":"linha completa do employee_document.","regras":"Erro se o documento não existir.","efeitos":"nenhum (leitura).","precondicoes":"Documento existente."},{"nome":"check-expiring-documents","objetivo":"Lista documentos ativos que vencem dentro de N dias.","entradas":"Opcionais: --company-id, --days (default 30).","saidas":"expiring_documents (com employee_name, company_id, days_until_expiry, is_expired), count, days_window.","regras":"Considera apenas documentos com expiry_date não nula, status 'active' e expiry_date <= hoje+days; filtra por company quando informado; calcula days_until_expiry e is_expired (expiry < hoje); ordena por expiry_date.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]},{"group":"Eventos de Carreira","objetivo":"Registro de eventos do ciclo de vida do funcionário, com efeito de desligamento.","acoes":[{"nome":"record-lifecycle-event","objetivo":"Registra um evento de ciclo de vida do funcionário (contratação, promoção, desligamento, etc.).","entradas":"--employee-id (obrigatório), --event-type (obrigatório, VALID_LIFECYCLE_EVENTS), --event-date (obrigatório); opcionais: --details (JSON), --old-values (JSON), --new-values (JSON).","saidas":"event_id, employee_id, employee_name, event_type, event_date, message; (employee_status_updated, new_employee_status='left', date_of_exit se desligamento).","regras":"Funcionário deve existir; event_type validado (hiring/confirmation/promotion/transfer/separation/resignation/retirement); data válida; para separation/resignation/retirement atualiza employee para status 'left' e define date_of_exit.","efeitos":"INSERT em employee_lifecycle_event; UPDATE employee (status='left' + date_of_exit) em eventos de desligamento; audit_log; commit.","precondicoes":"Funcionário existente."}]},{"group":"Status","objetivo":"Resumo geral do módulo de RH com contagens e indicadores agregados.","acoes":[{"nome":"status","objetivo":"Retorna um resumo do módulo de RH (funcionários, departamentos, férias, ponto, despesas e eventos recentes).","entradas":"Opcional: --company-id (filtra por empresa).","saidas":"total_employees, employees_by_status, total_departments, leave_summary, attendance_summary_current_month, expense_claims_by_status, recent_lifecycle_events (últimos 10), fiscal_year.","regras":"Contagens por status só incluídas quando > 0; leave_summary baseado no ano fiscal corrente; resumo de ponto do mês corrente; tudo filtrável por company.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma."}]}]},"payroll":{"module":"payroll","display":"Folha de Pagamento","functionalities":[{"group":"Componentes","objetivo":"Cria e lista componentes salariais (proventos, descontos e contribuições do empregador) que servem de blocos para as estruturas salariais.","acoes":[{"nome":"add-salary-component","objetivo":"Cria um componente salarial (earning, deduction ou employer_contribution) com suas flags fiscais.","entradas":"--name (obrigatório); --component-type (obrigatório: earning|deduction|employer_contribution); --is-tax-applicable (default 1); --is-statutory (default 0); --is-pre-tax (default 0); --variable-based-on-taxable-salary (default 0); --depends-on-payment-days (default 1); --is-supplemental (default 0); --gl-account-id; --description.","saidas":"salary_component_id, name, component_type.","regras":"component_type deve estar em (earning, deduction, employer_contribution); nome único (erro se já existe); se --gl-account-id informado o account deve existir; flags booleanas aceitam 1/0, true/false, yes/no. Sem ciclo draft/submit.","efeitos":"Insere 1 linha em salary_component; grava audit_log (add-salary-component). 2 commits.","precondicoes":"Tabelas company e employee existem (REQUIRED_TABLES); GL account opcional precisa existir se informado."},{"nome":"list-salary-components","objetivo":"Lista componentes salariais com filtro opcional por tipo e busca textual, paginado.","entradas":"--component-type (filtro opcional, validado contra os tipos válidos); --search (LIKE no name); --limit (default 20); --offset (default 0).","saidas":"count, components[] (id, name, component_type, flags, gl_account_id, description, created_at, updated_at), limit, offset, has_more.","regras":"Se --component-type informado e inválido, erro. Ordena por name. has_more = offset+limit < total.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além das tabelas base."}]},{"group":"Estruturas","objetivo":"Define estruturas salariais (conjunto de componentes com valor fixo, percentual ou fórmula) e permite consultá-las.","acoes":[{"nome":"add-salary-structure","objetivo":"Cria uma estrutura salarial com seus detalhes de componentes (amount/percentage/formula).","entradas":"--name (obrigatório); --company-id (obrigatório); --components (obrigatório, JSON array); --payroll-frequency (default monthly: monthly|biweekly|weekly).","saidas":"salary_structure_id, name, payroll_frequency, component_count.","regras":"Frequência deve ser válida; company deve existir; nome único; cada item do JSON precisa de salary_component_id existente, sem duplicatas; no máximo um de amount/percentage/formula por componente; percentage em [0,100]; base_component_id (se informado) deve existir; currency fixado em USD; is_active=1.","efeitos":"Insere 1 linha em salary_structure e N linhas em salary_structure_detail; grava audit_log (add-salary-structure). 2 commits.","precondicoes":"Company existente; salary_components referenciados já criados."},{"nome":"get-salary-structure","objetivo":"Retorna uma estrutura salarial com a lista detalhada de seus componentes.","entradas":"--salary-structure-id (obrigatório).","saidas":"salary_structure { campos da estrutura, components[] (id, salary_component_id, component_name, component_type, amount, percentage, formula, base_component_id, base_component_name, sort_order), component_count }.","regras":"Estrutura deve existir (erro caso contrário); enriquece base_component_name a partir de salary_component; ordena por sort_order.","efeitos":"nenhum (leitura).","precondicoes":"Estrutura salarial existente."},{"nome":"list-salary-structures","objetivo":"Lista estruturas salariais com filtro por empresa e busca, incluindo a contagem de componentes.","entradas":"--company-id (filtro); --search (LIKE no name); --limit (default 20); --offset (default 0).","saidas":"count, structures[] (id, name, payroll_frequency, currency, company_id, is_active, component_count, timestamps), limit, offset, has_more.","regras":"component_count via subconsulta correlacionada em salary_structure_detail; ordena por name.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além das tabelas base."}]},{"group":"Atribuições","objetivo":"Vincula uma estrutura salarial a um funcionário com valor-base e vigência, e lista essas atribuições.","acoes":[{"nome":"add-salary-assignment","objetivo":"Atribui uma estrutura salarial a um funcionário com base_amount e período de vigência, fechando automaticamente a atribuição anterior.","entradas":"--employee-id (obrigatório); --salary-structure-id (obrigatório); --base-amount (obrigatório, decimal texto); --effective-from (obrigatório, YYYY-MM-DD); --effective-to (opcional).","saidas":"salary_assignment_id, employee_id, salary_structure_id, base_amount, effective_from, effective_to e previous_assignment_closed (se houve).","regras":"Funcionário e estrutura devem existir; estrutura e funcionário devem ser da mesma company; base_amount não negativo; effective_to >= effective_from; se houver atribuição ativa anterior, ela é fechada com effective_to = dia anterior ao novo effective_from; currency USD; base arredondada.","efeitos":"Insere 1 linha em salary_assignment; pode atualizar a linha da atribuição anterior (effective_to/updated_at); grava audit_log (add-salary-assignment). 2 commits.","precondicoes":"Funcionário e estrutura salarial existentes na mesma empresa."},{"nome":"list-salary-assignments","objetivo":"Lista atribuições salariais com filtros por funcionário, empresa e janela de datas (sobreposição), paginado.","entradas":"--employee-id; --company-id; --from-date (atribuição ativa em/depois); --to-date (effective_from <= to-date); --limit (default 20); --offset (default 0).","saidas":"count, assignments[] (campos da atribuição + employee_name + salary_structure_name), limit, offset, has_more.","regras":"JOIN com employee e salary_structure; filtros de data tratam effective_to NULL como aberto; ordena por effective_from DESC.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além das tabelas base."}]},{"group":"Tabelas de IR","objetivo":"Configura faixas progressivas de imposto de renda federal e estadual e o vínculo de estados do funcionário.","acoes":[{"nome":"add-income-tax-slab","objetivo":"Cria uma faixa (slab) de imposto de renda federal ou estadual com seus brackets de alíquota.","entradas":"--name (obrigatório); --tax-jurisdiction (obrigatório: federal|state); --effective-from (obrigatório); --filing-status; --state-code (obrigatório se state); --standard-deduction (default 0); --rates (JSON array de brackets).","saidas":"income_tax_slab_id, name, tax_jurisdiction, state_code, filing_status, effective_from, standard_deduction, rate_count.","regras":"jurisdiction válida; state exige state-code (federal ignora state-code); filing_status válido se informado; standard_deduction >= 0; brackets contíguos (from_amount == to_amount anterior), último pode ter to_amount null; rate em [0,100]; to_amount > from_amount. is_active=1.","efeitos":"Insere 1 linha em income_tax_slab e N linhas em income_tax_slab_rate; grava audit_log (add-income-tax-slab). 2 commits.","precondicoes":"Nenhuma específica além das tabelas base."},{"nome":"add-state-tax-slab","objetivo":"Adiciona um único bracket de imposto estadual para um estado/filing_status.","entradas":"--state-code (obrigatório); --bracket-start (obrigatório); --rate (obrigatório); --bracket-end (opcional); --filing-status (default single).","saidas":"state_tax_slab_id, state_code, bracket_start, bracket_end, rate, filing_status.","regras":"filing_status válido; bracket-start >= 0; bracket-end > bracket-start se informado; rate em [0,100]; state_code uppercase; valores arredondados.","efeitos":"Insere 1 linha em state_tax_slab. 1 commit. Não grava audit_log.","precondicoes":"Nenhuma específica além das tabelas base."},{"nome":"update-employee-state-config","objetivo":"Define ou atualiza o estado de trabalho e o estado de residência de um funcionário (UPSERT).","entradas":"--employee-id (obrigatório); --work-state (obrigatório); --residence-state (obrigatório).","saidas":"employee_id, work_state, residence_state.","regras":"Funcionário deve existir; estados em uppercase; UPSERT por employee_id (ON CONFLICT atualiza work_state/residence_state/updated_at).","efeitos":"Insere ou atualiza 1 linha em employee_state_config. 1 commit. Não grava audit_log.","precondicoes":"Funcionário existente."}]},{"group":"Config. de Impostos (FICA/FUTA)","objetivo":"Configura por ano-fiscal as alíquotas FICA (Social Security/Medicare) e as bases/alíquotas FUTA/SUTA.","acoes":[{"nome":"update-fica-config","objetivo":"Insere ou atualiza (UPSERT) as taxas de Social Security e Medicare para um ano-fiscal.","entradas":"Todos obrigatórios: --tax-year; --ss-wage-base; --ss-employee-rate; --ss-employer-rate; --medicare-employee-rate; --medicare-employer-rate; --additional-medicare-threshold; --additional-medicare-rate.","saidas":"tax_year, ss_wage_base, ss_employee_rate, ss_employer_rate, medicare_employee_rate, medicare_employer_rate, additional_medicare_threshold, additional_medicare_rate, action (created|updated).","regras":"tax_year inteiro em [2000,2100]; todos os campos decimais válidos e não negativos; UPSERT por tax_year (ON CONFLICT atualiza todas as taxas).","efeitos":"Insere ou atualiza 1 linha em fica_config; grava audit_log (update-fica-config) com old_values/new_values. 2 commits.","precondicoes":"Nenhuma específica além das tabelas base."},{"nome":"update-futa-suta-config","objetivo":"Insere ou atualiza (UPSERT) a configuração FUTA (federal) ou SUTA (estadual) de desemprego por ano-fiscal.","entradas":"--tax-year (obrigatório); --wage-base (obrigatório); --rate (obrigatório); --state-code (opcional, NULL=FUTA federal, valor=SUTA estadual); --employer-rate-override (opcional).","saidas":"tax_year, state_code, config_type, wage_base, rate, employer_rate_override, action (created|updated).","regras":"tax_year em [2000,2100]; wage_base >= 0; rate em [0,100]; employer_rate_override em [0,100] se informado; UPSERT por (tax_year, state_code).","efeitos":"Insere ou atualiza 1 linha em futa_suta_config; grava audit_log (update-futa-suta-config) com old/new. 2 commits.","precondicoes":"Nenhuma específica além das tabelas base."}]},{"group":"Ciclos de Folha","objetivo":"Gerencia o ciclo de vida do payroll_run: criação em rascunho, geração de holerites, submissão com postagem contábil e cancelamento com estorno.","acoes":[{"nome":"create-payroll-run","objetivo":"Cria um payroll_run em rascunho para um período de pagamento.","entradas":"--company-id (obrigatório); --period-start (obrigatório); --period-end (obrigatório); --department-id (opcional, filtro); --payroll-frequency (default monthly).","saidas":"payroll_run_id, naming_series, period_start, period_end, payroll_frequency.","regras":"period_start < period_end; frequência válida; company existe; department existe se informado (resolve por id ou name); erro se houver payroll_run sobreposto não cancelado na mesma empresa; gera naming_series; status='draft', totais zerados.","efeitos":"Insere 1 linha em payroll_run (status draft); grava audit_log (create-payroll-run). 1 commit.","precondicoes":"Company existente; department existente se informado."},{"nome":"generate-salary-slips","objetivo":"Calcula e gera os holerites (salary_slip) de todos os funcionários elegíveis do payroll_run, com proventos, impostos e descontos.","entradas":"--payroll-run-id (obrigatório).","saidas":"payroll_run_id, slips_generated, total_gross, total_deductions, total_net.","regras":"Run deve existir e estar em 'draft'; apaga slips draft anteriores (regeração); seleciona funcionários ativos com salary_assignment vigente (e department se houver); calcula dias trabalhados/pagos com leave não-pago; proventos fixos/percentuais com proração; hora extra via overtime_policy + attendance; pré-tax 401k/HSA; IR federal progressivo (anualizado) + flat 22%/37% para wages suplementares; IR estadual; FICA (SS com teto, Medicare e Additional Medicare); penhoras pós-tax priorizadas com tetos federais. Erro se não houver funcionários elegíveis.","efeitos":"Deleta e insere linhas em salary_slip e salary_slip_detail; pode criar salary_components estatutários (auto); atualiza cumulative_paid e status de wage_garnishment; atualiza totais/employee_count do payroll_run; grava audit_log (generate-salary-slips). 1 commit. Não posta GL.","precondicoes":"Payroll_run em draft; funcionários ativos com salary_assignment vigente; FICA/tax slabs configurados para cálculo completo."},{"nome":"submit-payroll-run","objetivo":"Submete o payroll_run: marca holerites como submitted e posta as lançamentos contábeis balanceados no razão.","entradas":"--payroll-run-id (obrigatório); --cost-center-id (usa centro de custo default se omitido).","saidas":"payroll_run_id, naming_series, gl_entries (qtd), total_gross, total_net, total_employer_tax.","regras":"Run deve existir e estar 'draft'; deve ter slips draft; resolve contas de GL (salary_expense e payroll_payable obrigatórias); calcula impostos patronais (SS/Medicare empregador, FUTA, SUTA) por funcionário; monta DR despesa salarial/patronal e CR payroll_payable (por funcionário, com partido), IR federal/estadual, SS, Medicare, FUTA, SUTA; auto-corrige diferenças de arredondamento <=1.00; remove entradas zero; aborta com rollback se o GL falhar.","efeitos":"Insere lançamentos em gl_entry via insert_gl_entries (voucher_type payroll_entry); atualiza salary_slip para 'submitted' e payroll_run para 'submitted'; grava audit_log (submit-payroll-run). 1 commit final.","precondicoes":"Payroll_run em draft com slips gerados; contas de despesa salarial e payroll payable existentes; centro de custo disponível."},{"nome":"cancel-payroll-run","objetivo":"Cancela um payroll_run submetido, estornando os lançamentos contábeis e marcando holerites como cancelled.","entradas":"--payroll-run-id (obrigatório).","saidas":"payroll_run_id, naming_series, reversed_entries (qtd).","regras":"Run deve existir e estar 'submitted' (erro caso contrário); estorna via reverse_gl_entries; aborta com rollback se o estorno falhar.","efeitos":"Cria lançamentos de estorno em gl_entry (reverse_gl_entries); atualiza salary_slip para 'cancelled' e payroll_run para 'cancelled'; grava audit_log (cancel-payroll-run) com old/new. 1 commit final.","precondicoes":"Payroll_run em status submitted com GL postado."}]},{"group":"Holerites","objetivo":"Consulta individual e listagem dos holerites (salary_slip) gerados, com seus proventos e descontos.","acoes":[{"nome":"get-salary-slip","objetivo":"Retorna um holerite com seus detalhes aninhados de proventos e descontos.","entradas":"--salary-slip-id (obrigatório).","saidas":"Campos do slip no topo + employee_name/first_name/last_name + earnings[], deductions[], details[] (id, salary_component_id, component_name, component_type, amount, year_to_date).","regras":"Slip deve existir (erro caso contrário); separa detalhes em earnings vs deductions; details = earnings + deductions.","efeitos":"nenhum (leitura).","precondicoes":"Salary slip existente."},{"nome":"list-salary-slips","objetivo":"Lista holerites com filtros por payroll run, funcionário e status, paginado.","entradas":"--payroll-run-id; --employee-id; --status (draft|submitted|paid|cancelled); --limit (default 20); --offset (default 0).","saidas":"count, slips[] (campos do slip + employee_name), limit, offset, has_more.","regras":"JOIN com employee; ordena por created_at DESC; has_more = offset+limit < total.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além das tabelas base."}]},{"group":"W-2","objetivo":"Gera os dados de W-2 de fim de ano para os funcionários a partir dos holerites submetidos.","acoes":[{"nome":"generate-w2-data","objetivo":"Agrega holerites submetidos do ano e produz os boxes de W-2 por funcionário.","entradas":"--tax-year (obrigatório); --company-id (obrigatório).","saidas":"tax_year, company_id, company_name, employee_count, w2_data[] (employee_id, employee_name, ssn_last_four, filing_status, boxes{1..6, 12{D,W}}).","regras":"tax_year inteiro; company deve existir; soma todos os slips submitted do ano; Box1=gross-pretax, Box2=federal, Box3=min(gross, ss_wage_base), Box4=SS, Box5=gross, Box6=Medicare, Box12 D=401k, W=HSA (só se >0); ss_wage_base de fica_config (default 168600); SSN descriptografado e exposto só nos últimos 4 dígitos.","efeitos":"nenhum (leitura). Lê salary_slip/salary_slip_detail/salary_component/employee/company/fica_config; descriptografa SSN.","precondicoes":"Holerites submetidos no ano-fiscal; company existente; idealmente fica_config do ano."}]},{"group":"Penhoras","objetivo":"Gerencia ordens de penhora salarial (wage garnishment) por funcionário, com prioridade federal e tetos.","acoes":[{"nome":"add-garnishment","objetivo":"Adiciona uma ordem de penhora salarial para um funcionário.","entradas":"--employee-id (obrigatório); --order-number (obrigatório); --creditor-name (obrigatório); --garnishment-type (obrigatório: child_support|tax_levy|student_loan|creditor); --start-date (obrigatório); --amount-or-percentage (default 0); --is-percentage (flag); --total-owed; --end-date.","saidas":"garnishment_id, priority.","regras":"Funcionário deve existir; type válido; priority derivada do tipo (child_support=1..creditor=4); max_percentage 50 para child_support, senão 25; status inicial 'active', cumulative_paid '0'.","efeitos":"Insere 1 linha em wage_garnishment; grava audit_log (add-garnishment). 1 commit.","precondicoes":"Funcionário existente."},{"nome":"update-garnishment","objetivo":"Atualiza campos de uma penhora (status, valor, total devido, data final).","entradas":"--garnishment-id (obrigatório); --status (active|paused|completed|cancelled); --amount-or-percentage; --total-owed; --end-date.","saidas":"updated (true).","regras":"Penhora deve existir; status (se informado) deve ser válido; erro se nenhum campo a atualizar; atualiza updated_at.","efeitos":"Atualiza 1 linha em wage_garnishment via dynamic_update; grava audit_log (update-garnishment). 1 commit.","precondicoes":"Penhora existente."},{"nome":"list-garnishments","objetivo":"Lista penhoras filtrando por funcionário, empresa e status, ordenadas por prioridade.","entradas":"--employee-id; --company-id; --status.","saidas":"garnishments[] (linhas de wage_garnishment), count.","regras":"Filtros opcionais combinam por AND; ordena por priority e created_at.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além das tabelas base."},{"nome":"get-garnishment","objetivo":"Retorna uma penhora individual pelo ID.","entradas":"--garnishment-id (obrigatório).","saidas":"Linha completa de wage_garnishment.","regras":"Erro se a penhora não existir.","efeitos":"nenhum (leitura).","precondicoes":"Penhora existente."}]},{"group":"Horas Extras","objetivo":"Configura a política de horas extras da empresa e calcula as horas/valores de overtime de um funcionário no período.","acoes":[{"nome":"add-overtime-policy","objetivo":"Cria ou atualiza (UPSERT) a política de horas extras de uma empresa.","entradas":"--company-id (obrigatório); --weekly-threshold (default 40); --daily-threshold; --ot-multiplier (default 1.5); --double-ot-multiplier (default 2.0).","saidas":"company_id, weekly_threshold, daily_threshold, ot_multiplier, double_ot_multiplier.","regras":"Company deve existir; thresholds/multiplicadores numéricos e não negativos; UPSERT por company_id (ON CONFLICT atualiza thresholds/multiplicadores/updated_at).","efeitos":"Insere ou atualiza 1 linha em overtime_policy. 1 commit. Não grava audit_log.","precondicoes":"Company existente."},{"nome":"calculate-overtime","objetivo":"Calcula horas regulares/extras e valores de overtime de um funcionário em um período a partir da attendance.","entradas":"--employee-id (obrigatório); --period-start (obrigatório); --period-end (obrigatório); --hourly-rate (opcional; senão derivado da salary_assignment).","saidas":"employee_id, period_start, period_end, total_hours, regular_hours, ot_hours, hourly_rate, ot_multiplier, regular_amount, ot_amount, total_amount.","regras":"Funcionário deve existir; deve haver overtime_policy da empresa (senão erro); hourly_rate derivado de base_amount*12/2080 se não informado (erro se sem assignment); soma horas de attendance (present/wfh/half_day); OT = max(OT diário, OT semanal=horas acima do weekly_threshold*num_semanas); valores arredondados.","efeitos":"nenhum (leitura). Lê employee, overtime_policy, salary_assignment, attendance.","precondicoes":"Funcionário existente; overtime_policy da empresa; attendance no período; salary_assignment se hourly-rate omitido."}]},{"group":"Retro","objetivo":"Calcula pagamento retroativo comparando a taxa salarial atual com a anterior e registra os ajustes pendentes.","acoes":[{"nome":"calculate-retro-pay","objetivo":"Calcula pagamento retroativo de um funcionário com base na diferença entre as duas últimas atribuições salariais e registra ajustes.","entradas":"--employee-id (obrigatório); --from-date (opcional); --to-date (opcional).","saidas":"employee_id, periods_affected, total_retro_amount, details[] (period_from, period_to, old_rate, new_rate, adjustment_amount) e message quando não há retro.","regras":"Funcionário deve existir; precisa de >=2 salary_assignments (erro caso contrário); compara última (current) vs penúltima (previous); se current_rate <= old_rate retorna 0 sem ajustes; período retro entre os effective_from, limitado por from/to-date; aplica diferença por slip não-cancelado no período, ou por períodos mensais aproximados (30 dias) se não houver slips.","efeitos":"Insere N linhas em retro_pay_adjustment (status 'pending'). 1 commit. Não grava audit_log.","precondicoes":"Funcionário com pelo menos 2 atribuições salariais."}]},{"group":"ACH/NACHA","objetivo":"Cadastra contas bancárias de funcionários (criptografadas) e gera o arquivo NACHA/ACH de depósito direto a partir de um payroll run.","acoes":[{"nome":"add-employee-bank-account","objetivo":"Cadastra uma conta bancária de funcionário para ACH/depósito direto, com routing/account criptografados.","entradas":"--employee-id (obrigatório); --bank-name (obrigatório); --routing-number (obrigatório, 9 dígitos); --account-number (obrigatório, 4-17 dígitos); --account-type (checking|savings, default checking).","saidas":"employee_bank_account_id, employee_id, bank_name, account_type, message.","regras":"Funcionário deve existir; routing exatamente 9 dígitos numéricos; account 4-17 dígitos numéricos; account_type válido; routing e account são criptografados antes de gravar; is_primary=1.","efeitos":"Insere 1 linha em employee_bank_account (campos sensíveis cifrados); grava audit_log (add-employee-bank-account). 1 commit.","precondicoes":"Funcionário existente."},{"nome":"list-employee-bank-accounts","objetivo":"Lista as contas bancárias de um funcionário com número de conta mascarado.","entradas":"--employee-id (obrigatório).","saidas":"accounts[] (campos da conta com account_number mascarado ****+4, account_number_masked, routing_number descriptografado), count.","regras":"Descriptografa colunas cifradas; mascara account_number (apenas últimos 4); ordena por created_at.","efeitos":"nenhum (leitura).","precondicoes":"Funcionário existente; contas cadastradas."},{"nome":"generate-nacha-file","objetivo":"Gera o conteúdo de um arquivo NACHA/ACH de pagamento a partir dos holerites de um payroll run submetido/pago.","entradas":"--payroll-run-id (obrigatório).","saidas":"file_content (texto fixed-width NACHA), entry_count, total_amount, payroll_run_id.","regras":"Run deve existir e estar 'submitted' ou 'paid'; usa slips não cancelados com net_pay>0; cada funcionário precisa de conta primária (senão é pulado); descriptografa routing/account; monta registros tipo 1/5/6/8/9; txn_code 22 (checking) ou 32 (savings); erro se nenhum funcionário com conta bancária.","efeitos":"nenhum (leitura). Lê payroll_run, company, salary_slip, employee_bank_account; não persiste o arquivo no banco.","precondicoes":"Payroll_run submitted/paid com slips; funcionários com employee_bank_account primária."}]},{"group":"Status","objetivo":"Retorna métricas e contagens resumidas do domínio de folha de pagamento.","acoes":[{"nome":"status","objetivo":"Retorna métricas-resumo de folha: contagens de componentes, estruturas, atribuições ativas, runs por status, holerites, FICA/tax slabs e o run mais recente.","entradas":"--company-id (opcional, filtra estruturas/atribuições/runs/slips por empresa).","saidas":"total_salary_components, components_by_type, total/active_salary_structures, total/active_salary_assignments, total_payroll_runs, payroll_runs_by_status, total_salary_slips, fica_configs, fica_years, total_income_tax_slabs, tax_slabs_by_jurisdiction, futa_suta_configs, latest_payroll_run.","regras":"Componentes e FICA/tax slabs são globais (sem filtro de empresa); atribuições ativas = effective_from<=hoje e effective_to NULL/futuro; latest_payroll_run por period_end DESC.","efeitos":"nenhum (leitura).","precondicoes":"Nenhuma além das tabelas base."}]}]},"accounting-adv":{"module":"accounting-adv","display":"Contabilidade Avançada","functionalities":[{"group":"Contratos de Receita (ASC606)","objetivo":"Gerenciar o ciclo de vida (CRUD e modificações) de contratos de receita sob ASC 606.","acoes":[{"nome":"add-revenue-contract","objetivo":"Cria um novo contrato de receita em status draft.","entradas":"--company-id (obrigatório); --customer-name (obrigatório); --total-value (default \"0\"); --contract-number; --start-date; --end-date.","saidas":"id, naming_series, customer_name, contract_status (\"draft\"), total_value.","regras":"Valida existência da company; customer-name obrigatório; total-value deve ser decimal válido. Gera naming_series via get_next_name(prefixo RCON-). Inicializa allocated_value=\"0\", modification_count=0, contract_status=\"draft\".","efeitos":"INSERT em advacct_revenue_contract; audit_log via audit(); commit.","precondicoes":"Company existente; tabelas advacct_* criadas (init_db)."},{"nome":"update-revenue-contract","objetivo":"Atualiza campos editáveis de um contrato de receita existente.","entradas":"--id (obrigatório); campos opcionais: --customer-name, --contract-number, --start-date, --end-date, --total-value, --contract-status.","saidas":"id, updated_fields (lista de colunas alteradas).","regras":"Valida existência do contrato; se contract-status fornecido deve estar em (draft, active, modified, completed, terminated); erro \"No fields to update\" se nada mudou. Não há checagem de status para permitir edição.","efeitos":"UPDATE dinâmico em advacct_revenue_contract (set updated_at); audit_log; commit.","precondicoes":"Contrato existente."},{"nome":"get-revenue-contract","objetivo":"Retorna um contrato de receita com suas obrigações e considerações variáveis.","entradas":"--id (obrigatório).","saidas":"Todos os campos do contrato + obligations[], obligation_count, variable_considerations[].","regras":"Valida existência do contrato; carrega obligations ordenadas por created_at e variable_considerations.","efeitos":"nenhum (leitura).","precondicoes":"Contrato existente."},{"nome":"list-revenue-contracts","objetivo":"Lista contratos de receita com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --contract-status, --search (customer_name/contract_number); --limit (default 20), --offset (default 0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"Monta WHERE dinâmico; ordena por created_at DESC; has_more = (offset+limit) < total.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_revenue_contract existente."},{"nome":"modify-contract","objetivo":"Marca um contrato como modificado e incrementa o contador de modificações.","entradas":"--id (obrigatório).","saidas":"id, contract_status (\"modified\"), modification_count.","regras":"Contrato deve estar em status draft ou active, caso contrário erro; incrementa modification_count em 1 e seta contract_status=\"modified\".","efeitos":"UPDATE em advacct_revenue_contract (contract_status, modification_count, updated_at); audit_log; commit.","precondicoes":"Contrato existente em status draft ou active."}]},{"group":"Obrigações de Desempenho","objetivo":"Gerenciar obrigações de desempenho (performance obligations) e seu cumprimento sob ASC 606.","acoes":[{"nome":"add-performance-obligation","objetivo":"Adiciona uma obrigação de desempenho a um contrato e atualiza o valor alocado do contrato.","entradas":"--contract-id (obrigatório); --company-id (obrigatório); --name (obrigatório); --standalone-price (default \"0\"); --recognition-method (default \"over_time\"); --recognition-basis (default \"time\").","saidas":"id, contract_id, name, standalone_price, allocated_price, recognition_method, obligation_status (\"unsatisfied\").","regras":"Valida contrato e company; recognition-method em (point_in_time, over_time); recognition-basis em (output, input, time); allocated_price = standalone_price; pct_complete=\"0\", obligation_status=\"unsatisfied\".","efeitos":"INSERT em advacct_performance_obligation; UPDATE de advacct_revenue_contract.allocated_value (SUM dos allocated_price, arredondado 2 casas); audit_log; commit.","precondicoes":"Contrato e company existentes."},{"nome":"list-performance-obligations","objetivo":"Lista obrigações de desempenho com filtros e paginação.","entradas":"Filtros opcionais: --contract-id, --company-id, --obligation-status; --limit (20), --offset (0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"WHERE dinâmico; ordena por created_at ASC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_performance_obligation existente."},{"nome":"satisfy-performance-obligation","objetivo":"Registra o percentual de cumprimento de uma obrigação e ajusta seu status.","entradas":"--id (obrigatório); --pct-complete (default \"100\").","saidas":"id, pct_complete, obligation_status.","regras":"Obrigação não pode já estar satisfied; pct deve ser decimal entre 0 e 100; pct=100 => satisfied (satisfied_date=now); 0<pct<100 => partially_satisfied; pct=0 => unsatisfied.","efeitos":"UPDATE em advacct_performance_obligation (pct_complete, obligation_status, satisfied_date, updated_at); audit_log; commit.","precondicoes":"Obrigação existente e não satisfied."},{"nome":"update-performance-obligation","objetivo":"Atualiza campos de preço/método de uma obrigação de desempenho.","entradas":"--id (obrigatório); campos opcionais: --standalone-price, --allocated-price, --name, --recognition-method, --recognition-basis.","saidas":"id, updated_fields.","regras":"Valida existência; erro \"No fields to update\" se nada fornecido. Não revalida enums de recognition-method/basis nesta ação.","efeitos":"UPDATE dinâmico em advacct_performance_obligation (set updated_at); audit_log; commit.","precondicoes":"Obrigação existente."}]},{"group":"Consideração Variável","objetivo":"Registrar e listar considerações variáveis (variable consideration) dos contratos sob ASC 606.","acoes":[{"nome":"add-variable-consideration","objetivo":"Adiciona uma consideração variável a um contrato de receita.","entradas":"--contract-id (obrigatório); --company-id (obrigatório); --description (obrigatório); --estimated-amount (default \"0\"); --constraint-amount (default \"0\"); --method (default \"expected_value\"); --probability (default \"0\").","saidas":"id, contract_id, description, estimated_amount, method.","regras":"Valida contrato e company; description obrigatório; method em (expected_value, most_likely).","efeitos":"INSERT em advacct_variable_consideration; audit_log; commit.","precondicoes":"Contrato e company existentes."},{"nome":"list-variable-considerations","objetivo":"Lista considerações variáveis com filtros e paginação.","entradas":"Filtros opcionais: --contract-id, --company-id; --limit (20), --offset (0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"WHERE dinâmico; ordena por created_at ASC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_variable_consideration existente."}]},{"group":"Cronograma/Apropriação de Receita","objetivo":"Calcular cronogramas de apropriação de receita e marcar entradas como reconhecidas.","acoes":[{"nome":"calculate-revenue-schedule","objetivo":"Gera um cronograma mensal de receita para uma obrigação a partir das datas do contrato.","entradas":"--obligation-id (obrigatório).","saidas":"obligation_id, entries_created, monthly_amount, total_amount.","regras":"Obrigação e contrato devem existir; contrato precisa de start_date e end_date; allocated_price>0; meses = diferença de meses inclusiva, deve ser >0; valor mensal arredondado e último mês recebe o remainder.","efeitos":"DELETE das entradas existentes + INSERT de N linhas em advacct_revenue_schedule (recognized=0); audit_log; commit.","precondicoes":"Obrigação com allocated_price>0 e contrato com datas válidas."},{"nome":"update-schedule-amounts","objetivo":"Atualiza o valor de todas as entradas não reconhecidas de uma obrigação (modificações de contrato).","entradas":"--obligation-id (obrigatório); --amount (obrigatório).","saidas":"obligation_id, new_amount, entries_updated.","regras":"Obrigação deve existir; amount deve ser decimal válido; atualiza somente linhas com recognized=0; entries_updated = changes().","efeitos":"UPDATE em advacct_revenue_schedule (amount onde recognized=0); audit_log; commit.","precondicoes":"Obrigação existente com cronograma gerado."},{"nome":"generate-revenue-entries","objetivo":"Marca todas as entradas não reconhecidas de uma obrigação como reconhecidas.","entradas":"--obligation-id (obrigatório).","saidas":"obligation_id, recognized_count, total_recognized.","regras":"Obrigação deve existir; erro se não houver entradas com recognized=0; soma os amounts reconhecidos. Não gera lançamentos em gl_entry (apenas atualiza flag recognized).","efeitos":"UPDATE em advacct_revenue_schedule (recognized=1) para cada entrada; audit_log; commit.","precondicoes":"Cronograma com entradas não reconhecidas."},{"nome":"recognize-schedule-entry","objetivo":"Marca uma única entrada de cronograma de receita como reconhecida pelo seu ID.","entradas":"--id (obrigatório).","saidas":"id, recognized (1), amount.","regras":"Entrada deve existir; erro se já recognized=1. Usado para reconhecimento período a período (ex.: bridge Stripe ASC 606).","efeitos":"UPDATE em advacct_revenue_schedule (recognized=1) da entrada; audit_log; commit.","precondicoes":"Entrada de cronograma existente e não reconhecida."}]},{"group":"Relatórios de Receita","objetivo":"Relatórios somente-leitura de waterfall e resumo de reconhecimento de receita.","acoes":[{"nome":"revenue-waterfall-report","objetivo":"Resume por contrato o valor, alocação e contagem de obrigações satisfeitas.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"revenue_waterfall\"), rows[] (contract_id, customer_name, total_value, allocated_value, obligation_count, satisfied_count, etc.), total_contracts.","regras":"LEFT JOIN contratos x obrigações agrupado por contrato; ordena por created_at DESC.","efeitos":"nenhum (leitura).","precondicoes":"Tabelas de contrato e obrigação existentes."},{"nome":"revenue-recognition-summary","objetivo":"Resume por período os valores reconhecidos e não reconhecidos do cronograma.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"revenue_recognition_summary\"), rows[] (period_date, total_amount, recognized_amount, unrecognized_amount, entry_count), total_periods.","regras":"Agrupa advacct_revenue_schedule por period_date; soma condicional por flag recognized; ordena por period_date.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_revenue_schedule existente."}]},{"group":"Arrendamentos (ASC842)","objetivo":"Gerenciar o ciclo de vida (CRUD e classificação) de arrendamentos sob ASC 842.","acoes":[{"nome":"add-lease","objetivo":"Cria um novo arrendamento em status draft.","entradas":"--company-id (obrigatório); --lessee-name (obrigatório); --lessor-name (obrigatório); --monthly-payment (default \"0\"); --discount-rate (default \"0\"); --term-months (default 0); --lease-type (default \"operating\"); --asset-description; --start-date; --end-date; --annual-escalation (default \"0\"); --purchase-option-price.","saidas":"id, naming_series, lessee_name, lessor_name, lease_status (\"draft\"), term_months.","regras":"Valida company; lessee-name e lessor-name obrigatórios; gera naming_series (prefixo LEAS-); rou_asset_value e lease_liability ficam NULL (calculados depois).","efeitos":"INSERT em advacct_lease; audit_log; commit.","precondicoes":"Company existente."},{"nome":"update-lease","objetivo":"Atualiza campos editáveis de um arrendamento existente.","entradas":"--id (obrigatório); opcionais: --lessee-name, --lessor-name, --asset-description, --start-date, --end-date, --monthly-payment, --discount-rate, --annual-escalation, --purchase-option-price, --lease-type, --term-months.","saidas":"id, updated_fields.","regras":"Valida existência; se lease-type fornecido deve estar em (operating, finance); term-months convertido para int; erro \"No fields to update\" se nada mudou.","efeitos":"UPDATE dinâmico em advacct_lease (set updated_at); audit_log; commit.","precondicoes":"Arrendamento existente."},{"nome":"get-lease","objetivo":"Retorna um arrendamento com seus pagamentos e entradas de amortização.","entradas":"--id (obrigatório).","saidas":"Campos do arrendamento + payments[], payment_count, amortization_entries[].","regras":"Valida existência; carrega payments (ordem payment_date) e amortization_entries (ordem period_date).","efeitos":"nenhum (leitura).","precondicoes":"Arrendamento existente."},{"nome":"list-leases","objetivo":"Lista arrendamentos com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --lease-type, --lease-status, --search (lessee/lessor/asset); --limit (20), --offset (0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"WHERE dinâmico; ordena por created_at DESC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_lease existente."},{"nome":"classify-lease","objetivo":"Classifica o arrendamento como operating ou finance (auto por prazo ou override manual).","entradas":"--id (obrigatório); --lease-type opcional (override).","saidas":"id, lease_type.","regras":"Se lease-type não informado, auto-classifica: term_months>=36 => finance, senão operating; lease-type informado deve estar em (operating, finance).","efeitos":"UPDATE em advacct_lease (lease_type, updated_at); audit_log; commit.","precondicoes":"Arrendamento existente."}]},{"group":"ROU/Passivo de Arrendamento","objetivo":"Calcular o ativo de direito de uso (ROU) e o passivo de arrendamento via valor presente.","acoes":[{"nome":"calculate-rou-asset","objetivo":"Calcula o valor do ativo de direito de uso (ROU) como valor presente dos pagamentos.","entradas":"--id (obrigatório).","saidas":"id, rou_asset_value.","regras":"term_months>0 e monthly_payment>0; taxa mensal = discount_rate/12; ROU = PV de anuidade ordinária (arredondado 2 casas; rate=0 => payment*periods).","efeitos":"UPDATE em advacct_lease (rou_asset_value, updated_at); audit_log; commit.","precondicoes":"Arrendamento existente com term_months e monthly_payment positivos."},{"nome":"calculate-lease-liability","objetivo":"Calcula o passivo de arrendamento como valor presente dos pagamentos remanescentes.","entradas":"--id (obrigatório).","saidas":"id, lease_liability.","regras":"term_months>0 e monthly_payment>0; taxa mensal = discount_rate/12; passivo = PV de anuidade (igual ao ROU na origem).","efeitos":"UPDATE em advacct_lease (lease_liability, updated_at); audit_log; commit.","precondicoes":"Arrendamento existente com term_months e monthly_payment positivos."}]},{"group":"Amortização/Pagamentos de Arrendamento","objetivo":"Gerar o cronograma de amortização e registrar pagamentos de arrendamento.","acoes":[{"nome":"generate-amortization-schedule","objetivo":"Gera o cronograma mensal de amortização (juros/principal/saldos) do arrendamento.","entradas":"--lease-id (obrigatório).","saidas":"lease_id, entries_created, initial_balance, monthly_payment.","regras":"term_months>0, monthly_payment>0 e start_date obrigatórios; saldo inicial = PV; por mês: juros=saldo*taxa_mensal, principal=pagamento-juros; último mês zera saldo e ajusta principal/juros por arredondamento.","efeitos":"DELETE entradas existentes + INSERT de N linhas em advacct_amortization_entry; audit_log; commit.","precondicoes":"Arrendamento existente com term_months, monthly_payment e start_date válidos."},{"nome":"record-lease-payment","objetivo":"Registra um pagamento de arrendamento, decompondo em juros e principal.","entradas":"--lease-id (obrigatório); --payment-date (obrigatório); --payment-amount (obrigatório).","saidas":"id, lease_id, payment_amount, principal, interest, balance_after, payment_status (\"paid\").","regras":"Saldo corrente vem da última entrada de amortização (closing_balance) ou do lease_liability ou 0; juros=saldo*discount_rate/12; principal=pagamento-juros; balance_after=saldo-principal; payment_status fixo \"paid\".","efeitos":"INSERT em advacct_lease_payment; audit_log; commit. Não posta em gl_entry/payment_ledger_entry.","precondicoes":"Arrendamento existente."}]},{"group":"Relatórios de Leasing","objetivo":"Relatórios somente-leitura de maturidade, disclosure e resumo de arrendamentos.","acoes":[{"nome":"lease-maturity-report","objetivo":"Lista arrendamentos ordenados por data de término para análise de maturidade.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"lease_maturity\"), rows[] (id, lessee/lessor, lease_type, datas, term_months, monthly_payment, rou_asset_value, lease_liability, lease_status), total_leases.","regras":"WHERE por company; ordena por end_date ASC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_lease existente."},{"nome":"lease-disclosure-report","objetivo":"Agrega por tipo de arrendamento os totais de pagamentos, ROU e passivos.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"lease_disclosure\"), rows[] (lease_type, lease_count, total_monthly_payments, total_rou_assets, total_lease_liabilities).","regras":"Agrupa por lease_type; usa COALESCE para ROU/passivo nulos.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_lease existente."},{"nome":"lease-summary","objetivo":"Retorna contagens totais de arrendamentos por status e por tipo.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"lease_summary\"), total_leases, by_status{}, by_type{}.","regras":"Três queries: total, GROUP BY lease_status e GROUP BY lease_type.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_lease existente."}]},{"group":"Transações Intercompany","objetivo":"Gerenciar o ciclo de vida (CRUD, aprovação e postagem) de transações entre empresas do grupo.","acoes":[{"nome":"add-ic-transaction","objetivo":"Cria uma transação intercompany em status draft.","entradas":"--from-company-id (obrigatório); --to-company-id (obrigatório); --company-id (obrigatório); --transaction-type (obrigatório); --amount (default \"0\", deve ser >0); --currency (default \"USD\"); --transfer-price-method; --description.","saidas":"id, naming_series, from_company_id, to_company_id, transaction_type, amount, ic_status (\"draft\").","regras":"Valida 3 companies; from!=to; transaction-type em (sale, purchase, service, loan, dividend, allocation); amount>0; transfer-price-method (se dado) em (cost_plus, resale_minus, comparable, other); gera naming (ICT-); posted_date NULL.","efeitos":"INSERT em advacct_ic_transaction; audit_log; commit.","precondicoes":"from, to e company existentes e distintos (from!=to)."},{"nome":"update-ic-transaction","objetivo":"Atualiza campos editáveis de uma transação intercompany não postada.","entradas":"--id (obrigatório); opcionais: --description, --amount, --currency, --transaction-type, --transfer-price-method.","saidas":"id, updated_fields.","regras":"Status deve ser draft ou pending_approval, senão erro; valida enums de transaction-type e transfer-price-method se fornecidos; erro \"No fields to update\" se nada mudou.","efeitos":"UPDATE dinâmico em advacct_ic_transaction (set updated_at); audit_log; commit.","precondicoes":"Transação existente em status draft ou pending_approval."},{"nome":"get-ic-transaction","objetivo":"Retorna uma transação intercompany pelo seu ID.","entradas":"--id (obrigatório).","saidas":"Todos os campos da transação (row_to_dict).","regras":"Valida existência da transação.","efeitos":"nenhum (leitura).","precondicoes":"Transação existente."},{"nome":"list-ic-transactions","objetivo":"Lista transações intercompany com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --from-company-id, --to-company-id, --transaction-type, --ic-status, --search (description); --limit (20), --offset (0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"WHERE dinâmico; ordena por created_at DESC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_ic_transaction existente."},{"nome":"approve-ic-transaction","objetivo":"Aprova uma transação intercompany, movendo-a para status approved.","entradas":"--id (obrigatório).","saidas":"id, ic_status (\"approved\").","regras":"Status atual deve ser draft ou pending_approval, senão erro.","efeitos":"UPDATE em advacct_ic_transaction (ic_status=\"approved\", updated_at); audit_log; commit.","precondicoes":"Transação existente em draft ou pending_approval."},{"nome":"post-ic-transaction","objetivo":"Posta uma transação intercompany aprovada, registrando a data de postagem.","entradas":"--id (obrigatório).","saidas":"id, ic_status (\"posted\"), posted_date.","regras":"Status atual deve ser approved, senão erro; seta ic_status=\"posted\" e posted_date=now. Não gera lançamentos em gl_entry.","efeitos":"UPDATE em advacct_ic_transaction (ic_status, posted_date, updated_at); audit_log; commit.","precondicoes":"Transação existente em status approved."}]},{"group":"Preços de Transferência","objetivo":"Definir e listar regras de preço de transferência (transfer pricing) entre empresas.","acoes":[{"nome":"add-transfer-price-rule","objetivo":"Cria uma regra de preço de transferência para um par de empresas/tipo de transação.","entradas":"--company-id (obrigatório); --method (default \"cost_plus\"); --markup-pct (default \"0\"); --from-company-id; --to-company-id; --transaction-type; --effective-date; --expiry-date.","saidas":"id, method, markup_pct, transaction_type.","regras":"Valida company; method em (cost_plus, resale_minus, comparable, other); transaction-type (se dado) em conjunto válido. from/to companies não são revalidadas aqui.","efeitos":"INSERT em advacct_transfer_price_rule; audit_log; commit.","precondicoes":"Company existente."},{"nome":"list-transfer-price-rules","objetivo":"Lista regras de preço de transferência com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --from-company-id, --to-company-id, --transaction-type; --limit (20), --offset (0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"WHERE dinâmico; ordena por created_at DESC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_transfer_price_rule existente."}]},{"group":"Relatórios Intercompany","objetivo":"Relatórios somente-leitura de reconciliação e eliminação de transações intercompany.","acoes":[{"nome":"ic-reconciliation-report","objetivo":"Agrega transações intercompany por par de empresas, tipo e status.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"ic_reconciliation\"), rows[] (from_company_id, to_company_id, transaction_type, transaction_count, total_amount, ic_status).","regras":"Agrupa por from/to/type/status; ordena por from_company_id, to_company_id.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_ic_transaction existente."},{"nome":"ic-elimination-report","objetivo":"Lista transações intercompany postadas e calcula o total a eliminar.","entradas":"Filtro opcional: --company-id.","saidas":"report (\"ic_elimination\"), rows[] (id, from/to, type, amount, currency, posted_date), total_to_eliminate, transaction_count.","regras":"Filtra ic_status='posted'; soma os amounts (Decimal); ordena por posted_date DESC.","efeitos":"nenhum (leitura).","precondicoes":"Existirem transações com ic_status='posted'."}]},{"group":"Grupos de Consolidação","objetivo":"Criar e listar grupos de consolidação e adicionar entidades-membro do grupo.","acoes":[{"nome":"add-consolidation-group","objetivo":"Cria um grupo de consolidação ativo.","entradas":"--company-id (obrigatório); --name (obrigatório); --parent-company-id; --consolidation-currency (default \"USD\").","saidas":"id, naming_series, name, group_status (\"active\").","regras":"Valida company; name obrigatório; gera naming_series (prefixo CGRP-); group_status inicial \"active\".","efeitos":"INSERT em advacct_consolidation_group; audit_log; commit.","precondicoes":"Company existente."},{"nome":"list-consolidation-groups","objetivo":"Lista grupos de consolidação com filtros e paginação.","entradas":"Filtros opcionais: --company-id, --group-status, --search (name); --limit (20), --offset (0).","saidas":"rows[], total_count, limit, offset, has_more.","regras":"WHERE dinâmico; ordena por created_at DESC.","efeitos":"nenhum (leitura).","precondicoes":"Tabela advacct_consolidation_group existente."},{"nome":"add-group-entity","objetivo":"Adiciona uma entidade-membro (subsidiária) a um grupo de consolidação.","entradas":"--group-id (obrigatório); --company-id (obrigatório); --entity-company-id (obrigatório); --entity-name (obrigatório); --consolidation-method (default \"full\"); --ownership-pct (default \"100\"); --functional-currency (default \"USD\").","saidas":"id, group_id, entity_company_id, entity_name, ownership_pct, consolidation_method.","regras":"Valida grupo e company; entity-company-id e entity-name obrigatórios; consolidation-method em (full, proportional, equity); is_active=1.","efeitos":"INSERT em advacct_group_entity; audit_log; commit.","precondicoes":"Grupo e company existentes."}]},{"group":"Execução de Consolidação","objetivo":"Executar a consolidação e gerar lançamentos de eliminação e tradução de moeda.","acoes":[{"nome":"run-consolidation","objetivo":"Executa a consolidação de um grupo para um período, listando as entidades ativas.","entradas":"--group-id (obrigatório); --period-date (obrigatório).","saidas":"group_id, group_name, period_date, entity_count, entities[], consolidation_run (\"completed\").","regras":"Valida grupo; period-date obrigatório; erro se grupo não tem entidades ativas. Não cria lançamentos — apenas agrega/audita a execução.","efeitos":"Nenhuma escrita em tabelas de dados; apenas audit_log (run-consolidation) e commit.","precondicoes":"Grupo existente com pelo menos uma entidade ativa."},{"nome":"generate-elimination-entries","objetivo":"Gera lançamentos de eliminação para transações IC postadas entre entidades do grupo.","entradas":"--group-id (obrigatório); --period-date (obrigatório); --company-id (obrigatório).","saidas":"group_id, period_date, entries_created.","regras":"Valida grupo e company; precisa de >=2 entidades ativas; busca advacct_ic_transaction com ic_status='posted' cujos from e to estão entre as entidades; cria 1 entrada por IC (débito \"IC Revenue\", crédito \"IC Expense\", entry_type \"ic_elimination\").","efeitos":"INSERT de N linhas em advacct_elimination_entry; audit_log; commit. Não posta em gl_entry.","precondicoes":"Grupo com >=2 entidades ativas e transações IC postadas entre elas."},{"nome":"add-currency-translation","objetivo":"Cria um lançamento de ajuste de tradução de moeda (CTA) no grupo.","entradas":"--group-id (obrigatório); --company-id (obrigatório); --period-date (obrigatório); --amount (obrigatório); --debit-account (default \"CTA - Debit\"); --credit-account (default \"CTA - Credit\"); --description (default \"Currency translation adjustment\").","saidas":"id, group_id, period_date, amount, entry_type (\"currency_translation\").","regras":"Valida grupo e company; period-date e amount obrigatórios; entry_type fixo \"currency_translation\".","efeitos":"INSERT em advacct_elimination_entry; audit_log; commit.","precondicoes":"Grupo e company existentes."}]},{"group":"Relatórios de Consolidação","objetivo":"Relatórios somente-leitura de balancete consolidado e resumo do grupo.","acoes":[{"nome":"consolidation-trial-balance-report","objetivo":"Retorna o balancete consolidado com entidades e lançamentos de eliminação do período.","entradas":"--group-id (obrigatório); --period-date (opcional, filtra eliminações).","saidas":"report, group_id, group_name, period_date, entities[], elimination_entries[], total_eliminations, entity_count.","regras":"Valida grupo; entidades ativas ordenadas por entity_name; eliminações filtradas por group_id e, se dado, period_date; total_eliminations = soma dos amounts.","efeitos":"nenhum (leitura).","precondicoes":"Grupo existente."},{"nome":"consolidation-summary","objetivo":"Resume um grupo: contagem de entidades, eliminações e totais por tipo de lançamento.","entradas":"--group-id (obrigatório).","saidas":"report, group_id, group_name, group_status, consolidation_currency, entity_count, elimination_count, eliminations_by_type{}.","regras":"Valida grupo; conta entidades ativas e eliminações; agrupa eliminações por entry_type com count e total arredondado.","efeitos":"nenhum (leitura).","precondicoes":"Grupo existente."}]},{"group":"Conformidade/Status","objetivo":"Painéis transversais somente-leitura de conformidade com os padrões e de status do skill.","acoes":[{"nome":"standards-compliance-dashboard","objetivo":"Painel transversal com indicadores de conformidade ASC 606, ASC 842, intercompany e consolidação.","entradas":"Filtro opcional: --company-id.","saidas":"report, asc_606{revenue_contracts, unsatisfied_obligations}, asc_842{active_leases, leases_without_rou_calculation}, intercompany{unposted_transactions}, consolidation{active_groups}.","regras":"Executa contagens condicionais: obrigações não satisfeitas, leases ativos, leases sem ROU (não draft), IC não posted/eliminated, grupos ativos.","efeitos":"nenhum (leitura).","precondicoes":"Tabelas advacct_* existentes."},{"nome":"status","objetivo":"Retorna versão do skill e a contagem de registros de todas as tabelas do domínio.","entradas":"Nenhuma.","saidas":"skill, version, total_tables, record_counts{} (por tabela).","regras":"Itera as 12 tabelas ALL_TABLES contando registros; tabela ausente/erro retorna 0.","efeitos":"nenhum (leitura).","precondicoes":"Conexão ao DB (tolerante a tabelas ausentes)."}]}]},"meta":{"module":"meta","display":"Meta / Transversal","functionalities":[{"group":"Verificacao de Instalacao","objetivo":"Inspeciona quais skills Glue estao instaladas, o estado do banco e a saude da biblioteca compartilhada.","acoes":[{"nome":"check-installation","objetivo":"Varre as skills instaladas, o estado do banco e a presenca da biblioteca compartilhada, reportando contagens e versoes.","entradas":"--db-path (default ~/.glue/data.sqlite). Sem flags obrigatorias.","saidas":"JSON com status, total_skills_available, installed_skills [{name, version, tables_ok}], installed_count, missing_skills, missing_count, database_exists, database_tables, company_count, shared_library_installed, db_path, skills_dir.","regras":"Itera sobre ALL_SKILLS (26 nomes); para cada uma le a versao do SKILL.md via regex no frontmatter e calcula tables_ok verificando se as tabelas esperadas (SKILL_TABLES) existem no banco; skills sem tabelas proprias sao tables_ok=True. Erros de sqlite sao silenciados (relata o que conseguir). Sempre retorna status ok.","efeitos":"nenhum (leitura): apenas le sqlite_master e a tabela company, lista ~/glue/skills e le arquivos SKILL.md.","precondicoes":"Nenhuma; funciona standalone sem PyPika. O banco e a pasta de skills podem nao existir (campos refletem isso)."}]},{"group":"Guia de Onboarding","objetivo":"Recomenda a proxima tier/skills a instalar com base no estado atual da instalacao.","acoes":[{"nome":"install-guide","objetivo":"Avalia o progresso por tier e recomenda a proxima skill/tier a instalar com o comando glue correspondente.","entradas":"--db-path (default ~/.glue/data.sqlite). Sem flags obrigatorias.","saidas":"JSON com status, current_tier, next_recommendation, install_command, progress (texto 'X of Y (Z%)'), database_exists, company_count, tiers [{name, skills, installed, missing, status, install_cmd}].","regras":"Classifica cada tier (8 tiers em TIERS) como complete/partial/not_started. Identifica o primeiro tier incompleto; se nada instalado recomenda Tier 1, se tier parcial monta comando so com as skills faltantes, se tudo completo retorna mensagem final. Percentual calculado sobre ALL_SKILLS. Sempre retorna status ok.","efeitos":"nenhum (leitura): le sqlite_master/company e lista skills instaladas em ~/glue/skills.","precondicoes":"Nenhuma; funciona standalone sem PyPika. Banco e pasta de skills opcionais."}]},{"group":"Geracao de Dados de Demo","objetivo":"Cria um conjunto completo e idempotente de dados de demonstracao orquestrando subprocessos das demais skills.","acoes":[{"nome":"seed-demo-data","objetivo":"Popula uma empresa de demonstracao (Stark Manufacturing, ou empresa existente via --company-id) com dados de ponta a ponta em todos os modulos.","entradas":"--db-path (default ~/.glue/data.sqlite); --company-id (opcional: usa empresa existente em vez de criar a Stark).","saidas":"JSON com status (ok/partial), message, company_id, summary (contagens por entidade: customers, suppliers, items, warehouses, stock_entries, journal_entries, sales_orders/invoices, purchase_orders/receipts/invoices, payments, boms, work_orders, employees, leads, opportunities, assets, support_issues, projects, tasks etc.) e errors/error_count quando houver falhas parciais.","regras":"Idempotente: se a empresa-alvo ja tem customers (>0) retorna 'already exists' sem reescrever; com --company-id inexistente retorna erro 'Company not found'. Executa fases sequenciais (setup, COA us_gaap, fiscal years, cost centers, master data, opening stock, JEs, SO/SI, PO/PR/PI, pagamentos, manufatura, HR/payroll, CRM, assets, support, projetos) via subprocesso a cada db_query.py de skill; cada fase captura excecoes em errors e continua. Se setup-company falha, tenta recuperar usando qualquer empresa existente; se nem assim ha company_id, retorna erro fatal.","efeitos":"Escreve massivamente no banco INDIRETAMENTE: cada acao chamada via subprocesso grava em suas tabelas e faz postagens reais. Inclui submit de stock entries (stock_ledger_entry + gl_entry), submit de journal entries / sales+purchase invoices (gl_entry), submit de payments (gl_entry/payment_entry_reference), alem de criar company, contas, items, warehouses, customers/suppliers, BOMs, work orders, employees, salary structures, leads/opportunities, assets, SLAs/issues, projects/tasks. audit_log e demais efeitos sao produzidos pelas skills subjacentes.","precondicoes":"Requer PyPika/glue_lib instalado e as skills referenciadas presentes em ~/glue/skills (ou nos pacotes v2 glue-ops/glue-growth); _find_skill_script localiza cada script e lanca erro 'not found' se ausente. Para --company-id, a empresa deve existir."}]},{"group":"Setup Web Dashboard","objetivo":"Acao de setup do dashboard web, agora migrada para o addon externo glue-os-engine (stub de migracao nesta versao air-gapped).","acoes":[{"nome":"setup-web-dashboard","objetivo":"Stub que informa que o setup do dashboard web foi movido para o addon glue-os-engine (renomeado para os-setup-web-dashboard).","entradas":"Flags ainda declaradas no parser mas ignoradas: --domain (default None), --ssl/--no-ssl (default None), --skip-build (default False); --db-path tambem aceito.","saidas":"JSON de erro com status=error, error, missing_addon=glue-os-engine, old_action=setup-web-dashboard, new_action=os-setup-web-dashboard, note, since_version=4.0.0.","regras":"Sempre retorna erro estruturado e encerra com exit 1; nao executa nenhuma logica de clone/build/nginx (removida por seguranca apos flag do VirusTotal Code Insight). O addon nao esta empacotado neste fork air-gapped.","efeitos":"nenhum (apenas imprime JSON de erro e faz sys.exit(1)); nao toca banco, filesystem nem rede.","precondicoes":"Nenhuma; o stub responde independentemente do estado do ambiente."}]}]},"os":{"module":"os","display":"OS / Runtime (Fundação)","functionalities":[{"group":"Validação contra a Constituição","objetivo":"Valida um módulo contra os 21 artigos da Constituição Glue via análise estática (artigos 1-8, 10-12, 19-21) e execução de testes em sandbox (artigo 9).","acoes":[{"nome":"validate-module","objetivo":"Valida o diretório de um módulo contra a Constituição Glue, retornando aprovação/reprovação por artigo.","entradas":"--module-path (obrigatório; caminho do diretório do módulo); --validation-type (default 'full'; choices static|runtime|full); --db-path (default None; banco de teste para o tipo runtime).","saidas":"JSON via ok() com result (pass|fail), module_name, module_path, articles (mapa numero->pass|fail|skip), violations[], skipped[], duration_ms, validation_type; em 'full' inclui sub-objeto runtime e seta articles[9]. Em 'runtime' puro retorna result, tests_run, tests_passed, tests_failed, output.","regras":"Erro (err) se module_path não for diretório existente. static/full roda validate_module_static (14 checagens de artigo). runtime/full roda validate_module_runtime que invoca pytest no tests/. Em 'full', se runtime falhar seta result='fail' e articles[9]='fail', senão articles[9]='pass'. runtime sem tests/ retorna fail; pytest com timeout de 120s vira fail.","efeitos":"Nenhum (leitura) no banco principal: só lê arquivos do módulo (SKILL.md, init_db.py) e roda pytest em subprocesso. Não escreve tabelas, gl_entry/SLE/PLE, status nem audit_log; o runtime pode escrever em banco de teste isolado via GLUE_DB_PATH.","precondicoes":"module_path deve apontar para diretório existente do módulo; para validação runtime/full o módulo precisa de um diretório tests/ com testes pytest."},{"nome":"list-articles","objetivo":"Lista os artigos da Constituição (todos, ou somente os de enforcement estático ou runtime).","entradas":"--article-type (default 'all'; choices all|static|runtime). Sem flags obrigatórias.","saidas":"JSON via ok() com articles (lista de dicts: number, name, description, enforcement, severity, bypass_policy) e count.","regras":"article_type='static' retorna artigos 1-8,10-12,19-21; 'runtime' retorna 9,13-18; 'all' retorna todos os 21. Filtro feito por enforcement==static/runtime sobre a lista ARTICLES.","efeitos":"Nenhum (leitura). Apenas lê a constante ARTICLES em memória.","precondicoes":"Nenhuma além do módulo constitution.py estar importável."}]},{"group":"Registro de Tabelas","objetivo":"Constrói o registro de propriedade (ownership) de tabelas mapeando cada tabela ao módulo dono, usado para impor proteção contra escritas cross-module.","acoes":[{"nome":"build-table-registry","objetivo":"Constrói e exibe o registro de propriedade de tabelas (tabela -> módulo dono) varrendo a árvore de fontes.","entradas":"--src-root (obrigatório; raiz do diretório source/ a varrer).","saidas":"JSON via ok() com total_tables, total_modules, registry (mapa tabela->módulo) e by_module (mapa módulo->lista de tabelas, ordenado).","regras":"Erro (err) se src_root não for diretório existente. Varre glue-setup/init_schema.py atribuindo tabelas ao dono 'glue', depois todos os init_db.py sob src_root atribuindo ao módulo derivado do diretório; pula __pycache__/.git e o init_schema do core. Tabelas extraídas por regex CREATE TABLE IF NOT EXISTS.","efeitos":"Nenhum (leitura). Só lê arquivos init_schema.py/init_db.py do filesystem; não escreve no banco nem em audit_log.","precondicoes":"src-root deve ser diretório existente; tabelas só são detectadas em arquivos init_db.py / init_schema.py com DDL CREATE TABLE IF NOT EXISTS."}]},{"group":"Plano de Migração","objetivo":"Gera um plano de migração comparando o init_db.py declarado do módulo com o schema vivo do banco, validando e gravando um registro 'planned'.","acoes":[{"nome":"schema-plan","objetivo":"Gera um plano de migração (DDL de CREATE TABLE) para sincronizar o banco com o init_db.py do módulo.","entradas":"--module-path (obrigatório; deve conter init_db.py); --db-path (default ~/.glue/data.sqlite); --src-root (opcional; habilita checagem de conflito cross-module).","saidas":"dict com result (planned|no_changes|blocked|error), e em sucesso: migration_id, module_name, new_tables, new_columns, ddl_count, ddl_statements, validation_passed, validation_result, duration_ms. (Obs: o router de db_query.py descarta o dict retornado — nada é impresso no stdout.)","regras":"Erro se faltar init_db.py. Só novas tabelas/colunas contam como mudança acionável; sem mudanças retorna no_changes. Se src_root dado, bloqueia (result='blocked') ADD column / DROP de tabelas de outro dono no registro de ownership. Gera DDL só para new_tables (tipo mais seguro), roda validate_module_static e snapshot do schema atual.","efeitos":"ESCREVE no banco: cria a tabela glue_schema_migration (se ausente) e INSERE 1 registro com status 'planned' (migration_type='create', ddl_statements, previous_schema snapshot, planned_at). Não toca tabelas de negócio, gl_entry/SLE/PLE nem audit_log.","precondicoes":"module-path com init_db.py; banco SQLite acessível; para detecção de conflito, src-root válido com registro de ownership."}]},{"group":"Aplicar/Reverter Migrações","objetivo":"Executa em transação o DDL de uma migração planejada (apply) ou reverte uma migração aplicada derrubando as tabelas criadas e fazendo backup dos dados (rollback).","acoes":[{"nome":"schema-apply","objetivo":"Executa o DDL de uma migração com status 'planned' dentro de uma única transação.","entradas":"--migration-id (lido via getattr, obrigatório para o handler); --db-path (default ~/.glue/data.sqlite). OBS: o parser de db_query.py NÃO define --migration-id, então na prática o handler sempre recebe None e retorna o erro de flag obrigatória.","saidas":"dict com result (applied|error), e em sucesso: migration_id, module_name, tables_created, ddl_executed, duration_ms; erro inclui error e migration_id. (Router descarta o retorno — sem impressão.)","regras":"Sem migration_id retorna {error}. Migração inexistente ou com status != 'planned' retorna error. Executa cada DDL; rastreia tabelas via regex CREATE TABLE. Em falha sqlite3.Error: marca registro como 'failed', faz commit e retorna error; em sucesso marca 'applied' com applied_at e applied_by (default 'system').","efeitos":"ESCREVE no banco: executa os DDL CREATE TABLE/INDEX da migração (cria tabelas reais) e ATUALIZA o status do registro em glue_schema_migration para 'applied' (ou 'failed' em erro). Não posta em gl_entry/SLE/PLE nem audit_log.","precondicoes":"Existir registro em glue_schema_migration com status 'planned' (criado por schema-plan) e o migration_id correspondente."},{"nome":"schema-rollback","objetivo":"Reverte uma migração 'applied' do tipo create, fazendo backup dos dados e derrubando as tabelas criadas.","entradas":"--migration-id (lido via getattr, obrigatório para o handler); --db-path (default ~/.glue/data.sqlite). OBS: o parser de db_query.py NÃO define --migration-id, então na prática o handler sempre recebe None e retorna o erro de flag obrigatória.","saidas":"dict com result (rolled_back|error), e em sucesso: migration_id, module_name, tables_dropped, backups_created (lista de {original, backup, rows}), duration_ms. (Router descarta o retorno — sem impressão.)","regras":"Sem migration_id retorna {error}. Migração inexistente ou com status != 'applied' retorna error. Para migration_type='create': se a tabela tem linhas, copia para {tabela}_backup_{id[:8]} antes; depois DROP TABLE IF EXISTS. Falha sqlite3.Error retorna error sem commit.","efeitos":"ESCREVE no banco: cria tabelas de backup (CREATE TABLE AS SELECT) para tabelas com dados, faz DROP das tabelas criadas pela migração, e ATUALIZA o registro em glue_schema_migration para 'rolled_back' com rolled_back_at. Não posta em gl_entry/SLE/PLE nem audit_log.","precondicoes":"Existir registro em glue_schema_migration com status 'applied' (aplicado por schema-apply) e o migration_id correspondente."}]},{"group":"Detecção de Drift","objetivo":"Detecta divergências (drift) entre o schema vivo do banco e o schema declarado no init_db.py do módulo.","acoes":[{"nome":"schema-drift","objetivo":"Detecta modificações manuais no banco que divergem do schema declarado em init_db.py do módulo.","entradas":"--module-path (obrigatório; deve conter init_db.py); --db-path (default ~/.glue/data.sqlite).","saidas":"dict com result (drift_detected|no_drift), findings (lista de {type, table, column?, details}), finding_count, module_path, duration_ms. (Router descarta o retorno — sem impressão.)","regras":"Sem module_path retorna {error}. Sem init_db.py retorna lista vazia (no_drift). Compara via diff_schema e classifica achados: extra_table (só para tabelas com o prefixo do módulo), missing_column, extra_column, type_mismatch.","efeitos":"Nenhum (leitura). Apenas consulta sqlite_master/PRAGMA table_info e lê init_db.py; não escreve tabelas, gl_entry/SLE/PLE, status nem audit_log.","precondicoes":"module-path com init_db.py e banco SQLite acessível para comparação."}]},{"group":"Ações Movidas para Addon (glue-os-engine)","objetivo":"Stubs para ~29 ações de geração/deploy/evolução DGM que foram movidas para o addon externo glue-os-engine, retornando erro estruturado de addon ausente neste fork air-gapped.","acoes":[{"nome":"handle_moved_to_addon (generate-module, configure-module, list-industries, classify-operation, deploy-module, deploy-audit-log, install-suite, run-audit, compliance-weather-status, log-improvement, list-improvements, review-improvement, semantic-check, semantic-rules-list, dgm-run-variant, dgm-list-variants, dgm-select-best, detect-gaps, detect-schema-divergence, detect-stubs, suggest-modules, heartbeat-analyze, heartbeat-report, heartbeat-suggest, add-feature-to-module, check-feature-completeness, list-feature-matrix, research-business-rule, get-implementation-guide)","objetivo":"Para qualquer uma das ~29 ações listadas em MOVED_ACTIONS_TO_ADDON, retorna erro estruturado indicando que a ação migrou para o addon glue-os-engine.","entradas":"--action com um dos nomes movidos (obrigatório; aceito pelo parser pois consta em all_known). Nenhuma outra flag é processada antes do desvio.","saidas":"JSON de erro (print direto + exit 1) com status='error', error, missing_addon='glue-os-engine', old_action, new_action (nome os-prefixado), note e since_version='4.0.0'.","regras":"Roteado antes de qualquer outra ação: se action está em MOVED_ACTIONS_TO_ADDON, chama handle_moved_to_addon e encerra. Mapeia o nome antigo para o novo (prefixo 'os-'). Sempre falha; nunca executa a lógica real (que vive no addon externo não empacotado).","efeitos":"Nenhum (leitura). Apenas imprime JSON de erro e faz sys.exit(1); não escreve no banco nem em audit_log.","precondicoes":"Nenhuma; o comportamento é independente de estado, sempre retorna o erro de addon ausente."}]}]}};
